import type { PieceTexte } from '../pieceTextes';

const texte: PieceTexte = {
  source: 'William Shakespeare, Hamlet — traduction française de François Guizot, 1864. Source : Wikisource, domaine public.',
  blocs: [
    { k: 'acte', t: 'ACTE PREMIER' },
    { k: 'scene', t: 'SCÈNE I' },
    { k: 'perso', t: 'bernardo' },
    { k: 'ligne', t: 'Qui va là ?' },
    { k: 'perso', t: 'francisco' },
    { k: 'ligne', t: 'Non, répondez vous-même. Arrêtez-vous et faites-vous reconnaître.' },
    { k: 'perso', t: 'bernardo' },
    { k: 'ligne', t: 'Vive le roi !' },
    { k: 'perso', t: 'francisco' },
    { k: 'ligne', t: 'Bernardo ?' },
    { k: 'perso', t: 'bernardo' },
    { k: 'ligne', t: 'En personne.' },
    { k: 'perso', t: 'francisco' },
    { k: 'ligne', t: 'Vous venez très-soigneusement à votre heure.' },
    { k: 'perso', t: 'bernardo' },
    { k: 'ligne', t: 'Minuit vient de sonner : va regagner ton lit, Francisco.' },
    { k: 'perso', t: 'francisco' },
    { k: 'ligne', t: 'Pour cette délivrance, mille grâces. Le froid est aigre, et j’ai le cœur saisi.' },
    { k: 'perso', t: 'bernardo' },
    { k: 'ligne', t: 'Avez-vous eu une garde tranquille ?' },
    { k: 'perso', t: 'francisco' },
    { k: 'ligne', t: 'Pas une souris qui ait bougé !' },
    { k: 'perso', t: 'bernardo' },
    { k: 'ligne', t: 'Allons, bonne nuit. Si vous rencontrez Horatio et Marcellus, mes compagnons de garde, priez-les de faire hâte.' },
    { k: 'perso', t: 'francisco' },
    { k: 'ligne', t: 'Je pense que je les entends. — Holà ! halte ! qui va là ?' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Amis de ce pays.' },
    { k: 'perso', t: 'marcellus' },
    { k: 'ligne', t: 'Et hommes liges du roi de Danemark.' },
    { k: 'perso', t: 'francisco' },
    { k: 'ligne', t: 'Je vous souhaite une bonne nuit.' },
    { k: 'perso', t: 'marcellus' },
    { k: 'ligne', t: 'Adieu donc, honnête soldat ; qui vous a relevé ?' },
    { k: 'perso', t: 'francisco' },
    { k: 'ligne', t: 'Bernardo a pris mon poste ; je vous souhaite une bonne nuit.' },
    { k: 'perso', t: 'marcellus' },
    { k: 'ligne', t: 'Holà ! Bernardo !' },
    { k: 'perso', t: 'bernardo' },
    { k: 'ligne', t: 'Que dites-vous ? Est-ce Horatio qui est là ?' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Un petit morceau de lui, oui.' },
    { k: 'perso', t: 'bernardo' },
    { k: 'ligne', t: 'Soyez le bienvenu, Horatio. Soyez le bienvenu, bon Marcellus.' },
    { k: 'perso', t: 'marcellus' },
    { k: 'ligne', t: 'Eh bien ! cette chose a-t-elle encore apparu cette nuit ?' },
    { k: 'perso', t: 'bernardo' },
    { k: 'ligne', t: 'Je n’ai rien vu.' },
    { k: 'perso', t: 'marcellus' },
    { k: 'ligne', t: 'Horatio dit que c’est pure imagination, et il ne veut pas souffrir que la croyance ait prise sur lui, quant à cette terrible vision que nous avons vue par deux fois. C’est pourquoi j’ai insisté auprès de lui, l’invitant à veiller avec nous chaque minute de cette nuit, afin que, si cette apparition vient encore, il puisse confirmer nos regards et lui parler.' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Bah ! bah ! elle ne paraîtra pas.' },
    { k: 'perso', t: 'bernardo' },
    { k: 'ligne', t: 'Asseyez-vous un moment, et laissez-nous encore une fois livrer assaut à vos oreilles, qui sont si bien fortifiées contre notre histoire, contre ce que nous avons vu pendant deux nuits.' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Bien ! asseyons-nous, et écoutons Bernardo parler de ceci.' },
    { k: 'perso', t: 'bernardo' },
    { k: 'ligne', t: 'La dernière de toutes ces nuits, à l’heure où cette même étoile, qui est à l’occident du pôle, avait fait son voyage jusqu’à éclairer cette partie du ciel où elle flamboie à présent, Marcellus et moi, la cloche sonnant alors une heure.' },
    { k: 'perso', t: 'marcellus' },
    { k: 'ligne', t: 'Paix ! supprime le reste regarde, le voici qui revient.' },
    { k: 'perso', t: 'bernardo' },
    { k: 'ligne', t: 'C’est la même apparence que celle du roi qui est mort.' },
    { k: 'perso', t: 'marcellus' },
    { k: 'ligne', t: 'Toi qui es un savant, parle-lui, Horatio.' },
    { k: 'perso', t: 'bernardo' },
    { k: 'ligne', t: 'Ne ressemble-t-il pas au roi ? Observe-le, Horatio.' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Tout semblable. Il me bouleverse de peur et d’étonnement.' },
    { k: 'perso', t: 'bernardo' },
    { k: 'ligne', t: 'Il voudrait qu’on lui parlât.' },
    { k: 'perso', t: 'marcellus' },
    { k: 'ligne', t: 'Parle-lui, Horatio.' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Qui es-tu, toi qui usurpes ensemble cette heure de la nuit et cette forme noble et guerrière sous laquelle la majesté du Danemark, maintenant ensevelie, a pour un temps marché ? Au nom du ciel, je te somme : parle.' },
    { k: 'perso', t: 'marcellus' },
    { k: 'ligne', t: 'Il est offensé.' },
    { k: 'perso', t: 'bernardo' },
    { k: 'ligne', t: 'Vois, il s’éloigne avec hauteur.' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Arrête ; parle, parle ; je te somme de parler.' },
    { k: 'perso', t: 'marcellus' },
    { k: 'ligne', t: 'Il est parti et ne répondra pas.' },
    { k: 'perso', t: 'bernardo' },
    { k: 'ligne', t: 'Eh bien Horatio, vous tremblez, et vous êtes tout pâle ; ceci n’est-il pas quelque chose de plus que de l’imagination ? Qu’en pensez-vous ?' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Devant mon Dieu, je ne pourrais pas le croire, sans le sensible et sûr témoignage de mes propres yeux.' },
    { k: 'perso', t: 'marcellus' },
    { k: 'ligne', t: 'Ne ressemble-t-il pas au roi ?' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Comme tu te ressembles à toi-même. C’est bien là la même armure qu’il portait lorsqu’il combattit le Norwégien ambitieux ce fut ainsi qu’un jour il fronça le sourcil lorsque, dans une conférence furieuse, il arracha le Polonais de son traîneau et l’étendit sur la glace. Cela est étrange !' },
    { k: 'perso', t: 'marcellus' },
    { k: 'ligne', t: 'Deux fois déjà, justement à cette heure de mort, il a passé près de notre poste avec cette démarche guerrière.' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Sur quel point précis doit, à ce propos, travailler notre pensée, je n’en sais rien ; mais, à dire l’ensemble et la pente de mon opinion, ceci annonce quelque étrange explosion dans notre royaume.' },
    { k: 'perso', t: 'marcellus' },
    { k: 'ligne', t: 'C’est bon ; asseyons-nous, et dites-moi, si vous le savez, pourquoi ces continuelles gardes, si strictes et si rigoureuses, fatiguent ainsi, chaque nuit, les sujets de ce royaume ? Et pourquoi, chaque jour, ces canons de bronze que l’on coule, et tout ce trafic, à l’étranger, pour des munitions de guerre ? Pourquoi la presse sur les charpentiers de vaisseau, dont le rude labeur ne distingue plus le dimanche de la semaine ? Qu’y a-t-il en jeu pour que cette hâte abondante en sueurs fasse les journées et les nuits compagnes du même travail ? Quel est celui qui peut m’instruire ?' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Je le puis, ou, du moins, ainsi vont les rumeurs : notre dernier roi, dont à l’heure même l’image vient de nous apparaître, fut, comme vous savez, provoqué au combat par Fortinbras de Norwége, qu’un jaloux orgueil avait excité à ce défi. Dans ce combat, notre vaillant Hamlet (car cette partie de notre monde connu le tenait pour tel) tua ce Fortinbras, qui, par un acte bien scellé et fait dans toutes les formes des lois et de la science héraldique, abandonnait au vainqueur, avec sa vie, tous les domaines dont il était possesseur. Contre ce gage, notre roi avait assigné une portion équivalente qui serait entrée dans le patrimoine de Fortinbras, s’il fût resté vainqueur, comme son lot, d’après la convention et la teneur des articles ratifiés, est échu à Hamlet. Maintenant, mon cher, le jeune Fortinbras, tout plein et tout bouillant d’une fougue inexpérimentée, a ramassé çà et là sur les frontières de la Norwége une troupe d’aventuriers sans feu ni lieu, moyennant les vivres et l’entretien, pour quelque entreprise où il s’agisse d’avoir du cœur ; ce ne peut être (comme en est bien convaincu notre gouvernement) que le projet de reprendre sur nous à main armée, et par voie de contrainte, les susdites terres, ainsi perdues par son père ; et c’est là, je crois, la cause majeure de nos préparatifs, l’origine de ces gardes que nous montons, et le grand but de ce train de poste et de ce remue-ménage que vous voyez par tout le pays.' },
    { k: 'perso', t: 'bernardo' },
    { k: 'ligne', t: 'Je pense que ce ne peut être autre chose, et cela s’accorde bien avec cette figure d’augure étrange qui passe, armée, au milieu de notre veille, si semblable au roi qui était et est encore l’occasion de ces guerres.' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Ah ! cela, c’est un grain de poussière qui tombe dans l’œil de l’esprit, pour l’inquiéter. Au temps de la plus grande et plus florissante force de Rome, un peu avant que le très-puissant Jules-César ne tombât, les sépulcres se dépeuplèrent, et les morts en linceul s’en allaient, criant et gémissant par les rues de Rome ; on voyait des étoiles avec des queues de flamme, et des rosées de sang, et des ravages dans le soleil ; et l’humide planète, dont l’influence régit l’empire de Neptune, était atteinte d’une éclipse presque comme si c’eût été le jour du jugement. Eh bien ! ce sont de semblables signes précurseurs d’événements terribles, comme des hérauts qui ouvrent la marche des destins, comme un prologue du sort qui s’avance, c’est là ce que le ciel et la terre tout ensemble viennent de montrer dans nos climats et à nos concitoyens. (L’ombre reparaît.) Mais, silence ! voyez : le voilà. Il revient encore. Je veux me mettre devant lui, dût-il m’anéantir ! Arrête, illusion ! si tu as un son, une voix dont tu fasses usage, parle-moi.' },
    { k: 'ligne', t: 'S’il y a quelque chose de bien à faire qui puisse compter pour ton soulagement et pour mon salut, parle-moi.' },
    { k: 'ligne', t: 'Si tu es dans le secret des destins de ta patrie, et que, pour notre bonheur, la prescience puisse les faire éviter, oh ! parle.' },
    { k: 'ligne', t: '(Le coq chante.)' },
    { k: 'ligne', t: 'Ou si, pendant ta vie, tu as enfoui dans le sein de la terre quelque trésor extorqué, ce pourquoi, dit-on, vous autres esprits, vous errez souvent, tout morts que vous êtes, dis-le-moi. Arrête-toi et parle.' },
    { k: 'ligne', t: 'Arrêtez-le, Marcellus.' },
    { k: 'perso', t: 'marcellus' },
    { k: 'ligne', t: 'Le frapperai-je de ma pertuisane ?' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Oui, s’il ne veut pas s’arrêter.' },
    { k: 'perso', t: 'bernardo' },
    { k: 'ligne', t: 'Le voici !' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Le voici !' },
    { k: 'perso', t: 'marcellus' },
    { k: 'ligne', t: 'Le voilà parti. Nous lui faisons tort, à lui qui est si majestueux, en essayant contre lui ces démonstrations de violence ; il est invulnérable comme l’air, et nos coups frappant dans le vide n’auraient été qu’une méchante raillerie.' },
    { k: 'perso', t: 'bernardo' },
    { k: 'ligne', t: 'Il était au moment de parler, quand le coq a chanté.' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Et alors il a tressailli comme un être coupable à un terrible appel. J’ai ouï dire que le coq, qui est le clairon du matin, par sa voix haute et perçante, éveille le dieu du jour ; et qu’à ce signal, les esprits échappés et errants, qu’ils soient dans la mer ou dans le feu, vont se cacher dans leur prison ; et ce que nous venons de voir a prouvé qu’on dit vrai.' },
    { k: 'perso', t: 'marcellus' },
    { k: 'ligne', t: 'Il s’est évanoui au cri du coq. Quelques-uns disent que, toujours, quand la saison s’approche où la naissance de notre Sauveur est célébrée, cet oiseau de l’aurore chante durant toute la nuit ; alors, dit-on, aucun esprit n’ose se risquer dehors ; les nuits sont saines ; alors nulle planète dont l’action nous frappe, nulle fée qui nous surprenne, nulle sorcière qui ait le pouvoir de charmer, tant ce moment de l’année est sanctifié et riche de grâces.' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Je l’ai ouï dire ainsi, et je le crois en partie. Mais voyez : le matin, drapés dans son manteau rougissant, s’avance parmi la rosée sur cette haute colline à l’orient. Descendons notre garde, et si vous m’en croyez, faisons part au jeune Hamlet de ce que nous avons vu cette nuit ; car, sur ma vie, cet esprit, muet pour nous, lui parlera. Vous accordez-vous à vouloir que nous l’instruisions de cela, comme nous l’ordonnent nos affections, conformes à notre devoir ?' },
    { k: 'perso', t: 'marcellus' },
    { k: 'ligne', t: 'Faisons cela, je vous prie ; je sais où nous pourrons le trouver ce matin fort à propos.' },
    { k: 'scene', t: 'SCÈNE II' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Bien que le souvenir de la mort de Hamlet, notre frère bien-aimé, soit encore vert et vivace, bien qu’il nous convînt, à nous, de laisser nos cœurs dans la tristesse, et à notre royaume tout entier de montrer comme un seul front contracté par la même douleur, la raison, cependant, combattant la nature, nous a amenés à penser à lui avec une sage douleur et non sans quelque souvenir de nous-mêmes. C’est pourquoi voici celle qui fut d’abord notre sœur, maintenant notre reine, compagne de notre empire sur ces belliqueux États, et que, avec une joie déroutée, avec un œil brillant, tandis que l’autre versait des larmes, mêlant les réjouissances aux funérailles et les obsèques au mariage, pesant dans une balance égale le plaisir et l’affliction, nous avons prise pour femme. Nous n’avons point résisté en ceci à vos sagesses supérieures, qui ont eu leur libre allure dans tout le cours de cette affaire. Recevez tous nos remercîments.' },
    { k: 'ligne', t: 'Maintenant il s’agit, comme vous le savez, du jeune Fortinbras, qui, faisant peu de cas de ce que nous pouvons valoir, ou pensant que la mort récente de notre frère bien-aimé aurait ébranlé ce royaume et dérangé ses ressorts, et sans autre allié que ce fantôme de ses avantages rêvés, n’a pas manqué de nous insulter par un message, pour redemander les domaines perdus par son père, et que notre très-vaillant frère a acquis par tous les liens et avec tous les sceaux de la loi. Mais c’est assez parler de lui. Quant à nous et à l’objet de cette assemblée, voici quelle est l’affaire : nous avons écrit par ces lettres au roi de Norwége, oncle du jeune' },
    { k: 'ligne', t: 'Fortinbras, qui, impotent et alité, a à peine ouï parler du projet de son neveu, en l’invitant à en arrêter la suite ; car les levées, les enrôlements et la pleine organisation des corps, tout se fait parmi ses sujets. Et nous vous dépêchons aujourd’hui, brave Cornélius, et vous, Voltimand, pour porter nos salutations à ce vieux roi, sans vous donner pouvoir personnel pour traiter avec ce prince en dehors du cercle où peut s’étendre le développement de ces instructions. Adieu, et que votre diligence témoigne de votre dévouement.' },
    { k: 'perso', t: 'voltimand' },
    { k: 'ligne', t: 'En cela et en toutes choses, nous montrerons notre dévouement.' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Nous n’en doutons point. Adieu de bon cœur. (Voltimand et Cornélius sortent.) Et maintenant, Laërtes, qu’avez-vous de nouveau à nous dire ? Vous nous avez annoncé une demande ; qu’est-ce, Laërtes ? Vous ne pouvez point dire une chose raisonnable au roi de Danemark, et perdre vos paroles. Que peux-tu demander, Laërtes, qui ne soit d’avance mon offre plutôt que ta demande ? La tête n’est pas sœur du cœur, ni la main servante des lèvres plus étroitement que le trône de Danemark n’est lié à ton père. Que souhaites-tu, Laërtes ?' },
    { k: 'perso', t: 'laërtes' },
    { k: 'ligne', t: 'Mon redouté seigneur, je demande votre congé et votre agrément pour retourner en France. Quoique j’en sois parti avec empressement pour vous rendre hommage lors de votre couronnement, maintenant, je l’avoue, ce devoir une fois rempli, mes pensées et mes désirs se tournent de nouveau vers la France, et s’inclinent devant vous pour obtenir votre gracieux congé et votre indulgence.' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Avez-vous le congé de votre père ? Que dit Polonius ?' },
    { k: 'perso', t: 'polonius' },
    { k: 'ligne', t: 'Il m’a, mon seigneur, arraché par l’effort de ses instances une lente permission, et à la fin j’ai scellé son désir de mon pénible consentement. Je vous supplie de lui donner congé de partir.' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Prends l’heure qui te sourira, Laërtes ; tes moments sont à toi, et à toi mes meilleures volontés ; fais-en usage selon tes souhaits. Et maintenant, Hamlet, mon cousin, mon fils…' },
    { k: 'ligne', t: 'hamlet' },
    { k: 'ligne', t: ', à part. — Un peu plus que cousin, et un peu moins que fils.' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'D’où vient que les nuages pèsent encore sur vous ?' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Mais non, mon seigneur ; je ne suis que trop en plein soleil.' },
    { k: 'perso', t: 'la reine' },
    { k: 'ligne', t: 'Cher Hamlet, renonce à ces couleurs ténébreuses, et que ton œil regarde en ami le roi de Danemark. Ne va pas, sans fin, sous le voile baissé de tes paupières, cherchant ton noble père dans la poussière. Tu le sais, c’est le sort commun ; tout ce qui vit doit mourir et ne fait que traverser ce monde pour aller à l’éternité.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Oui, madame, c’est le sort commun.' },
    { k: 'perso', t: 'la reine' },
    { k: 'ligne', t: 'S’il en est ainsi, pourquoi cela te semble-t-il étrange ?' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Cela me semble, madame ! non, cela est. Sembler et moi, nous ne nous connaissons pas. Ce n’est pas seulement mon manteau noir comme l’encre, bonne mère, ni la traditionnelle livrée d’un deuil d’apparat, ni le souffle orageux d’une respiration pénible, non, ni la source abondante qui ruisselle dans les yeux, ni l’apparence abattue du visage, ni toutes les formes, tous les modes, tous les signes de la douleur, qui peuvent témoigner de moi vraiment. À bien dire, c’est là ce qui « semble : » car ce sont des actions qu’un homme peut jouer; mais je porte au dedans de moi ce que n’égale aucun signe, ce que ne disent pas tous ces harnais et cette livrée de la douleur.' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'C’est une tendre et honorable marque de votre nature, Hamlet, que de rendre à votre père ces lugubres devoirs. Mais, vous devez le savoir, votre père perdit un père ; ce père qu’il perdit avait perdu le sien ; et le survivant est tenu, par obligation filiale, à faire au mort, pendant quelque temps, hommage de sa douleur. Mais persévérer dans une affliction obstinée, c’est un acte d’opiniâtreté impie ; c’est un chagrin qui n’est point d’un homme. Cela fait voir une volonté très-indisciplinée envers le ciel, un cœur désarmé ou un esprit rebelle, une intelligence trop simple et sans étude : car ce qui doit être, à notre connaissance, de toute nécessité, ce qui est aussi habituel que la plus vulgaire des choses qui tombent sous les sens, pourquoi, dans notre révolte puérile, prendrions-nous cela tant à cœur ? Fi ! c’est un péché contre le ciel, un péché contre les morts, un péché contre la nature, une absurdité contre la raison, dont le texte habituel est la mort des pères, et qui n’a pas cessé de crier, depuis le premier cadavre jusqu’à celui qui est mort aujourd’hui : Cela doit être ainsi. Nous vous en prions, jetez bas cette infructueuse douleur, et considérez-nous comme un père ; car il faut que le monde le sache, vous êtes le plus proche de notre trône, et cette même excellence d’amour que le père le plus tendre porte à son fils, nous-même nous vous l’offrons. Quant à votre dessein de retourner aux écoles de Wittenberg, il est des plus contraires à nos désirs. Nous vous en supplions, soumettez-vous à rester ici pour la consolation et la joie de nos yeux, vous, le premier de notre cour, notre cousin et notre fils.' },
    { k: 'perso', t: 'la reine' },
    { k: 'ligne', t: 'Que les prières de ta mère ne soient pas perdues ; Hamlet, je t’en prie, demeure avec nous, ne va pas à Wittenberg.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Je vous obéirai de mon mieux en tout, madame.' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Bien, voilà une tendre et bonne réponse. Soyez en Danemark comme nous-mêmes. — Venez, madame ; cette douce et volontaire concession de Hamlet entre en souriant dans mon cœur ; en actions de grâces, je veux que le roi de Danemark ne boive pas aujourd’hui une joyeuse santé, sans que le grand canon le dise aux nuages, et le ciel répondra à chaque rasade du roi, en répétant le fracas du tonnerre terrestre. Allons.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Oh ! si cette solide, trop solide chair pouvait se fondre, s’écouler et se résoudre en une rosée ! Ou si, du moins, l’Éternel n’avait pas établi sa loi sacrée contre le meurtre de soi-même ! Ô Dieu ! ô Dieu combien pesantes et usées, et plates et sans profit me semblent toutes les pratiques de ce monde ! Fi de ce monde ! oh ! fi ! c’est un jardin non sarclé où tout monte en graine ; ce sont des herbes grossières et sauvages qui s’en emparent uniquement… Que les choses en soient venues là ! Mort depuis deux mois seulement… non, moins encore, il n’y a pas deux mois… Un si excellent roi ! qui était à celui-ci ce qu’Apollon est à un satyre… si tendre pour ma mère qu’il ne pouvait pas même souffrir que les vents du ciel s’approchassent de son visage trop rudement. Ciel et terre ! faut-il que je me souvienne ? Comment ? On l’aurait vue se pendre à lui comme si l’appétit en elle n’eût fait que s’accroître de ce dont il se nourrissait… et pourtant, en un mois… Ne pensons pas à cela. Fragilité, ton nom est femme ! Un petit mois, et avant que ces souliers fussent vieux, avec lesquels elle avait suivi le corps de mon pauvre père, tout en pleurs, comme une Niobé… Comment ? Elle, elle-même ? Ô ciel une bête à qui manquent les discours de la raison se serait plus longtemps lamentée. — Mariée avec mon oncle, avec le frère de mon père, qui ne ressemble pas plus à mon père que moi à Hercule… en un mois, avant que le sel de ses larmes vicieuses eût cessé de rougir ses yeux endoloris, elle s’est mariée ! Ô criminelle hâte de se jeter—et si légèrement —dans un lit incestueux ! Cela n’est pas bien, cela ne peut tourner à bien. Mais brise-toi, mon cœur ; car je dois retenir ma langue.' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Salut à votre seigneurie.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Je suis charmé de vous voir en bonne santé. Horatio, n’est-ce pas ?… ou je ne sais plus qui je suis moi-même.' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Lui-même, mon seigneur, et votre très-humble serviteur pour toujours.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Dites mon bon ami, monsieur ; je veux échanger ce nom avec vous. Et quel motif vous ramène de Wittenberg, Horatio ? —Marcellus ?' },
    { k: 'perso', t: 'marcellus' },
    { k: 'ligne', t: 'Mon bon seigneur…' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Je suis charmé de vous voir. Bonjour, monsieur. Mais, en vérité, qu’est-ce qui vous a fait quitter Wittenberg ?' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Un naturel de vagabond, mon bon seigneur.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Je ne m’accommoderais pas d’entendre votre ennemi parler de la sorte vous ne voudrez pas faire à mon oreille cette violence de la rendre dépositaire de votre témoignage contre vous-même. Je sais bien que vous n’êtes pas un vagabond. Mais quelle affaire avez-vous à Elseneur ? Nous vous apprendrons à boire à pleins bords avant que vous repartiez d’ici.' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Mon seigneur, j’étais venu pour voir les funérailles de votre père.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Je te prie, camarade, ne te moque pas de moi ; je pense que c’est pour voir les noces de ma mère.' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Il est vrai, mon seigneur, qu’elles ont suivi de bien près.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Économie, Horatio, économie pure ! Les viandes cuites pour les funérailles ont été resservies froides sur les tables du mariage. Plût à Dieu que j’eusse rencontré dans le ciel mon meilleur ennemi, plutôt que d’avoir vu ce jour, Horatio ! —Mon père ! —Il me semble que je vois mon père ?' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Où, mon seigneur ?' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Avec les yeux de l’âme, Horatio.' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Je l’ai vu autrefois ; c’était un roi parfait.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'C’était un homme, pour tout dire en un mot, tel que je ne reverrai jamais son pareil.' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Mon seigneur, je crois l’avoir vu durant la nuit d’hier.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Vu ! Qui ?' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Mon seigneur, le roi votre père.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Le roi mon père !' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Modérez pour un instant votre surprise, en prêtant une oreille attentive, afin que je puisse, avec le témoignage de ces messieurs, vous raconter ce prodige.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Pour l’amour de Dieu, fais-toi entendre.' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Pendant deux nuits de suite, ces messieurs, Marcellus et Bernardo, étant en faction, à l’heure oisive et morte du milieu de la nuit, ont eu l’aventure que voici : une figure, semblable à votre père, armée de toutes pièces, exactement de pied en cap, apparaît devant eux, et, avec une démarche solennelle, passe lentement et gravement près d’eux. Trois fois il se promena devant leurs y eux accablés et fixes d’épouvante, à la distance de ce bâton, tandis que, dissous presque en je ne sais quelle gelée fondante, par l’effet de la peur, ils demeuraient muets et ne lui parlaient point. Ils m’ont fait part de cela comme d’un secret terrible ; et moi, la troisième nuit, j’ai monté la garde avec eux. Alors, tout comme ils me l’avaient raconté, à la même heure, en la même forme, chacune de leurs paroles se trouvant vraie et certaine, l’apparition est venue. J’ai reconnu votre père ; ces deux mains ne sont pas plus semblables.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Mais où cela s’est-il passé ?' },
    { k: 'perso', t: 'marcellus' },
    { k: 'ligne', t: 'Mon seigneur, sur la plate-forme où nous montions la garde.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Ne lui avez-vous point parlé ?' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Mon seigneur, c’est ce que j’ai fait. Mais il n’a fait nulle réponse ; une fois, pourtant, à ce qu’il m’a semblé, il a levé la tête et a commencé à se mouvoir comme s’il voulait parler ; mais, à ce moment même, le coq du matin a chanté à haute voix, et lui, à ce bruit, il a reculé en toute hâte, et s’est évanoui à nos yeux.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Cela est fort étrange.' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Aussi sûrement que j’existe, mon honorable seigneur, cela est vrai ; et nous avons pensé que notre devoir nous prescrivait de vous en donner connaissance.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'En vérité, en vérité, messieurs, cela me trouble. Montez-vous la garde ce soir ?' },
    { k: 'perso', t: 'tous' },
    { k: 'ligne', t: 'Oui, mon seigneur.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Armé, dites-vous ?' },
    { k: 'perso', t: 'tous' },
    { k: 'ligne', t: 'Armé, mon seigneur.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'De la tête aux pieds ?' },
    { k: 'perso', t: 'tous' },
    { k: 'ligne', t: 'Mon seigneur, de pied en cap.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Alors, vous n’avez-pas vu son visage.' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Oh si, mon seigneur ; sa visière était levée.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Eh bien ! avait-il un aspect irrité ?' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Un air de tristesse plutôt que de colère.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Pâle ou rouge ?' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Non, très-pâle.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Et il fixait les yeux sur vous ?' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Constamment.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Je voudrais avoir été là.' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Cela vous aurait fortement frappé.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Sans doute, sans doute. A-t-il demeuré longtemps ?' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Le temps de compter jusqu’à cent, sans trop se presser ?' },
    { k: 'ligne', t: 'marcellus' },
    { k: 'ligne', t: 'bernardo' },
    { k: 'ligne', t: 'et' },
    { k: 'ligne', t: '. — Plus longtemps ! plus longtemps !' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Non pas quand je l’ai vu.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Sa barbe était grisonnante, n’est-ce pas ?' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Comme lorsque je l’ai vu durant sa vie ; comme un blason de sable semé d’argent .' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Je veillerai cette nuit, peut-être paraîtra-t-il encore.' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Je le garantis, il paraîtra.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'S’il revêt encore la forme de mon noble père, je lui parlerai, dût l’enfer béant m’ordonner de me tenir en paix. Je vous prie tous, si vous avez caché cette vision, persistez dans votre silence ; et, quelque chose qui puisse encore advenir cette nuit, livrez-le à votre réflexion, mais point à votre langue. Je récompenserai votre affection ! Ainsi, adieu. Sur la plate-forme, entre onze heures et minuit, j’irai vous trouver.' },
    { k: 'perso', t: 'tous' },
    { k: 'ligne', t: 'Nos respects à votre seigneurie.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Non, votre affection, comme la mienne est à vous. Adieu ! (Horatio, Marcellus et Bernardo sortent.) — L’âme de mon père tout armée ! tout ne va pas bien. Je soupçonne quelque mauvais mystère. Oh ! je voudrais que la nuit fût venue ! Jusque-là, sois calme, mon âme ! Les mauvaises actions, quand la terre entière pèserait sur elles, surgiront aux yeux des hommes.' },
    { k: 'scene', t: 'SCÈNE III' },
    { k: 'perso', t: 'laërtes' },
    { k: 'ligne', t: 'Mes bagages sont embarqués ; adieu ! Et maintenant, sœur, quand les vents en offriront l’occasion et qu’un convoi nous viendra en aide, ne vous endormez pas, mais donnez-moi de vos nouvelles.' },
    { k: 'perso', t: 'ophélia' },
    { k: 'ligne', t: 'Pouvez-vous en douter ?' },
    { k: 'perso', t: 'laërtes' },
    { k: 'ligne', t: 'Quant à Hamlet, et au badinage de ses gracieusetés, regardez cela comme une fantaisie de mode et un jeu auquel son sang s’amuse, — comme une violette née en la jeunesse de la nature qui s’éveille, — hâtive, mais passagère, suave, mais sans durée ; le parfum et la distraction d’une minute, rien de plus.' },
    { k: 'perso', t: 'ophélia' },
    { k: 'ligne', t: 'Quoi ! rien de plus ?' },
    { k: 'perso', t: 'laërtes' },
    { k: 'ligne', t: 'Non, croyez-moi, rien de plus ; car la nature, dans son progrès, ne développe pas seulement les muscles et la masse du corps, mais à mesure que s’agrandit ce temple, s’étendent aussi largement, pour la pensée et pour l’âme, les charges de leur dignité intérieure. Peut-être vous aime-t-il maintenant ; peut-être aucune souillure, aucune fraude n’altèrent maintenant la vertu de ses volontés ; mais vous devez craindre, en pesant sa grandeur, que ses volontés ne lui appartiennent pas. Il est lui-même sujet de sa naissance ; il ne lui est pas possible, comme aux gens qui ne comptent pas, de se tailler à lui-même sa destinée, car de son choix dépendent le salut et la santé de tout l’État ; et c’est pourquoi son choix doit être restreint à ce que demande ou permet le corps dont il est la tête. Si donc Hamlet dit qu’il vous aime, il est de votre sagesse de le croire seulement jusqu’à ce point où peut aller, selon le rôle et le rang qui lui sont propres, son droit d’agir comme il a parlé, c’est-à-dire jusque-là seulement où peut aller avec lui la grande voix du Danemark. Pesez donc la perte que votre honneur aurait à subir, si, d’une oreille trop crédule, vous écoutiez ses chansons, ou perdiez votre cœur, ou ouvriez à ses importunités sans frein le trésor de votre chasteté. Craignez cela, Ophélia, craignez cela, chère sœur ; tenez-vous toujours en deçà de votre affection, hors de l’atteinte et du danger des désirs. La vierge la plus ménagère d’elle-même est déjà assez prodigue si elle démasque sa beauté aux regards de la lune. La vertu même n’échappe point aux traits de la calomnie ; le ver ronge les enfants du printemps, trop souvent même avant que leurs boutons soient épanouis ; et c’est au matin de la jeunesse, sous ses limpides rosées, que les souffles contagieux ont plus de menaces. Soyez donc prudente : la meilleure sauvegarde, c’est la peur : assez souvent la jeunesse se révolte d’elle-même, quoiqu’elle n’ait près d’elle personne qui l’y pousse.' },
    { k: 'perso', t: 'ophélia' },
    { k: 'ligne', t: 'Je conserverai l’impression de cette leçon salutaire, comme un gardien pour mon cœur. Mais, mon bon frère, ne faites pas comme quelques rudes pasteurs : il ne faut pas me montrer une route escarpée et épineuse vers le ciel, et, comme un libertin vantard et insouciant, suivre soi-même le sentier fleuri de la licence, et s’inquiéter peu de ses propres leçons.' },
    { k: 'perso', t: 'laërtes' },
    { k: 'ligne', t: 'Oh ne craignez pas pour moi. Je m’arrête trop longtemps. Mais voici venir mon père. (Polonius entre.) Une double bénédiction est une double faveur. L’occasion me rit pour un second adieu.' },
    { k: 'perso', t: 'polonius' },
    { k: 'ligne', t: 'Encore ici, Laërtes ! À bord, à bord ! c’est une honte : le vent est là qui pousse au dos de votre voile, et vous vous faites attendre ! Allons, que ma bénédiction soit avec vous (il met sa main sur la tête de Laërtes) ; et songe à graver en ta mémoire ces quelques préceptes : « Ne donne pas à toutes tes pensées une langue, ni à aucune pensée non calculée son exécution. Sois familier, mais jamais banal. Les amis que tu auras, et dont le choix sera éprouvé, attache-les à ton âme par des crampons d’acier ; mais n’use pas la paume de ta main à fêter tout camarade éclos d’hier et encore sans plumes. Garde-toi d’entamer une querelle ; mais une fois engagé, comporte-toi de manière que l’adversaire prenne garde à toi. Prête l’oreille à tous, mais ne livre tes paroles qu’à peu de gens. Recueille l’opinion de chacun, mais réserve ton jugement. Que tes habits soient aussi coûteux que ta bourse le permet, sans recherches singulières ; riches, sans être voyants ; car l’ajustement révèle souvent l’homme ; et les gens les plus relevés en France par leur rang et par leur position sont, surtout en cela, des modèles de goût et de dignité. Ne sois ni emprunteur, ni prêteur, car le prêt fait souvent perdre et l’argent et l’ami, et l’emprunt émousse le tranchant de l’économie. Ceci par-dessus tout : sois vrai envers toi-même ; et, comme la nuit suit le jour, ceci doit s’en suivre que tu ne pourras être faux envers personne. » Adieu ! que ma bénédiction fasse pénétrer tout cela en toi.' },
    { k: 'perso', t: 'laërtes' },
    { k: 'ligne', t: 'Je prends humblement congé de vous, mon seigneur.' },
    { k: 'perso', t: 'polonius' },
    { k: 'ligne', t: 'L’heure vous réclame. Allez, vos serviteurs vous attendent.' },
    { k: 'perso', t: 'laërtes' },
    { k: 'ligne', t: 'Adieu, Ophélia, et souvenez-vous bien de ce que je vous ai dit.' },
    { k: 'perso', t: 'ophélia' },
    { k: 'ligne', t: 'Cela est enfermé en ma mémoire, et vous en garderez vous-même la clef.' },
    { k: 'perso', t: 'laërtes' },
    { k: 'ligne', t: 'Adieu !' },
    { k: 'perso', t: 'polonius' },
    { k: 'ligne', t: 'Qu’est-ce, Ophélia ? que vous a-t-il dit ?' },
    { k: 'perso', t: 'ophélia' },
    { k: 'ligne', t: 'C’est, ne vous en déplaise, quelque chose touchant le seigneur Hamlet.' },
    { k: 'perso', t: 'polonius' },
    { k: 'ligne', t: 'Certes, c’est fort à propos. On m’a dit que depuis peu il vous avait très-souvent consacré ses moments de loisir intime, et que vous-même aviez été très-libérale et prodigue de vos audiences ; s’il en est ainsi (comme on me l’a raconté, par voie de précaution), je dois vous dire que vous ne comprenez pas assez clairement par vous-même ce qui convient à ma fille et à votre honneur. Qu’y a-t-il entre vous ? confiez-moi la vérité.' },
    { k: 'perso', t: 'ophélia' },
    { k: 'ligne', t: 'Il m’a dernièrement, mon seigneur, fait beaucoup d’offres de son affection.' },
    { k: 'perso', t: 'polonius' },
    { k: 'ligne', t: 'Son affection ? Bah ! vous parlez comme une fillette encore toute verdelette qui n’a pas été passée au crible dans des circonstances de ce péril ; croyez-vous à ses offres, comme vous les appelez ?' },
    { k: 'perso', t: 'ophélia' },
    { k: 'ligne', t: 'Je ne sais pas, mon seigneur, ce que je dois penser.' },
    { k: 'perso', t: 'polonius' },
    { k: 'ligne', t: 'Eh bien ! je vais vous l’apprendre. Pensez que vous n’êtes qu’un petit enfant, et que vous avez pris pour argent comptant des offres qui ne sont que fausse monnaie. Offrez-vous à vous-même un tarif plus cher de votre valeur, ou (pour ne pas essouffler plus longtemps ce pauvre mot, dont j’abuse ainsi), vous n’aurez plus qu’à m’offrir le titre de sot.' },
    { k: 'perso', t: 'ophélia' },
    { k: 'ligne', t: 'Mon seigneur, il m’a importunée de son amour, mais d’une manière honorable.' },
    { k: 'perso', t: 'polonius' },
    { k: 'ligne', t: 'Ah oui. Vous pouvez appeler cela de belles manières !… Allez, allez !' },
    { k: 'perso', t: 'ophélia' },
    { k: 'ligne', t: 'Et il donnait autorité à ses discours, mon seigneur, par presque tous les plus saints serments du ciel.' },
    { k: 'perso', t: 'polonius' },
    { k: 'ligne', t: 'Ah ! oui, piéges à attraper des bécasses ! Je sais, quand le sang brûle, combien l’âme est prodigue à prêter à la langue des serments. Ce sont des éclairs, ma fille, donnant plus de lumière que de chaleur, qui perdent aussitôt chaleur et lumière, et dont les promesses mêmes s’éteignent aussitôt faites. Vous ne devez pas les prendre pour du feu. À partir de cette heure, soyez un peu plus avare de votre virginale présence ; mettez vos entretiens à plus haut prix, et que votre conversation ne soit pas à commandement. Quant au seigneur Hamlet, ce que vous en devez croire, c’est qu’il est jeune et qu’il lui est permis d’aller au bout d’une longe plus longue que ne saurait être la vôtre. Bref, Ophélia, ne croyez pas à ses serments ; ce sont des enjôleurs, ils n’ont pas la couleur dont ils sont revêtus en dehors ; ce ne sont rien qu’entremetteurs de projets fort profanes, qui ne semblent respirer que saintes et dévotes instances, afin de mieux tromper. Une fois pour toutes, et pour parler clairement, je ne veux pas que désormais vous fassiez mauvais usage de votre loisir en parlant au seigneur Hamlet, ou en l’écoutant ; prenez-y garde, entendez-vous, et passez votre chemin.' },
    { k: 'perso', t: 'ophélia' },
    { k: 'ligne', t: 'J’obéirai, mon seigneur.' },
    { k: 'scene', t: 'SCÈNE IV' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'L’air est subtil et mordant ; il fait très-froid.' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Oui, c’est un air aigre et qui pique.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Quelle heure est-il à présent ?' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Peu s’en faut, je crois, qu’il ne soit minuit.' },
    { k: 'perso', t: 'marcellus' },
    { k: 'ligne', t: 'Non, il est sonné.' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Vraiment ? je ne l’ai pas entendu. Alors, le moment approche, où l’esprit a l’habitude de se promener. (On entend dans le palais une fanfare de trompettes et des décharges d’artillerie.) Qu’est-ce que cela signifie, mon seigneur ?' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Le roi passe la nuit et boit à toute sa soif ; il tient séance d’orgie et danse en chancelant la gigue impudente, et à chaque fois qu’il avale ses rasades de vin du Rhin, la timbale et la trompette se mettent à braire ainsi pour le triomphe des santés qu’il porte.' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Est-ce la coutume ?' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Oui, ma foi ! c’est la coutume. Mais selon mon sentiment, encore que je sois enfant de ce pays et né pour en prendre les manières, c’est une coutume qu’il est plus honorable d’enfreindre que d’observer. Ces divertissements qui appesantissent les têtes nous font, de l’orient à l’occident, citer et condamner par les autres nations ; elles nous appellent ivrognes, et souillent notre nom du sobriquet de pourceaux. Et en vérité, quels que soient nos exploits et malgré la hauteur où ils atteignent, cela leur retire la sève même et la moelle de la gloire qu’ils nous mériteraient. De même, il arrive fréquemment aux individus que, s’ils ont en eux quelque tache d’un vice naturel ; si, par exemple, ils sont, de naissance (et par conséquent sans en être coupables, puisque la créature n’a pas le choix de son origine), dominés par l’excès de telle ou telle humeur du tempérament qui renverse souvent les remparts et les forteresses de la raison, ou si quelque habitude met en eux un levain qui les fasse trop sortir du moule des manières approuvées ; parce que ces hommes, dis-je, portent la marque d’un seul défaut, soit que ce défaut soit une livrée dont la nature les a revêtus, ou une cicatrice que leur a faite le hasard, leurs autres vertus (fussent-elles aussi pures que la grâce céleste et aussi infinies que l’homme les peut posséder) seront, dans l’opinion générale, gâtées par ce tort unique, et la goutte d’alliage impur abaisse souvent au taux de son propre mépris toute la noble substance où elle est mêlée.' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Regardez, mon seigneur, il vient.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Anges et ministres de grâce, défendez-nous ! Que tu sois un esprit de bénédiction ou un lutin damné, que tu apportes avec toi le souffle du ciel ou la vapeur de l’enfer, que tes intentions soient perverses ou charitables, tu te présentes sous une forme si provoquante, que je dois te parler. Je t’appelle, Hamlet, roi, père, souverain du Danemark ! Oh ! réponds-moi : ne me laisse pas éclater d’angoisse sans rien savoir. Pourquoi tes ossements sanctifiés, et ensevelis dans la mort, ont-ils rompu leur linceul ? Pourquoi le sépulcre, où nous t’avons vu tranquillement enclos, a-t-il ouvert ses pesantes mâchoires de marbre pour te rejeter ici ? Que signifie ceci ? Pour que toi, corps mort, de nouveau couvert de tout ton acier, tu reviennes ainsi revoir les lueurs de la lune, et rendre la nuit hideuse, et pour que nous, pauvres plastrons de la nature, nous soyons si horriblement ébranlés jusqu’au fond de notre être par des pensées qui excèdent la portée de nos âmes, — dis, qu’y a-t-il ? pourquoi cela ? que devons-nous faire ?' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Il vous fait signe d’aller vers lui, comme s’il avait quelque communication à vous faire, à vous seul.' },
    { k: 'perso', t: 'marcellus' },
    { k: 'ligne', t: 'Voyez avec quel geste courtois il vous invite à le suivre dans un endroit plus écarté. Mais n’allez pas avec lui.' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Non, certes, en aucune façon.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Il ne veut point parler ici ; je veux le suivre.' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'N’en faites rien, mon seigneur.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Pourquoi ? qu’ai-je à craindre ? je donnerais ma vie pour une épingle ; et quant à mon âme, que pourrait-il lui faire, étant immortelle comme lui ? Il me fait signe de nouveau ; je vais le suivre.' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Eh quoi ! s’il vous attire vers les flots, mon seigneur, ou sur la terrible cime de ce rocher qui, surplombant sa base, s’avance au-dessus de la mer ; s’il prend là quelque autre forme horrible qui vous prive de l’empire de la raison et vous entraîne dans la démence ? Pensez-y, le lieu même pourrait, sans nulle autre cause, jeter des boutades de désespoir dans le cerveau de tout homme qui voit une hauteur de tant de brasses entre la mer et lui, et qui l’entend rugir au-dessous.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Il me fait signe encore. — Marche, je te suivrai.' },
    { k: 'perso', t: 'marcellus' },
    { k: 'ligne', t: 'Vous n’irez point, mon seigneur.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Lâchez-moi donc.' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Soyez raisonnable, n’y allez pas.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Mon destin me hèle, et rend la plus petite artère du corps que voici aussi roide que les nerfs du lion de Némée. (Le fantôme fait un signe.) Il m’appelle encore ; lâchez-moi, messieurs. (Il se dégage.) Par le ciel ! je ferai un fantôme du premier qui m’arrêtera… Je l’ai dit… — Allons… marche… je te suivrai.' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Il est mis tout hors de lui par son imagination.' },
    { k: 'perso', t: 'marcellus' },
    { k: 'ligne', t: 'Suivons-le ; il ne convient pas que nous lui obéissions ainsi.' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Oui, marchons. Quelle issue aura tout ceci ?' },
    { k: 'perso', t: 'marcellus' },
    { k: 'ligne', t: 'Il y a quelque chose de vermoulu dans l’état du Danemark.' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Le ciel en décidera.' },
    { k: 'perso', t: 'marcellus' },
    { k: 'ligne', t: 'Eh bien ! suivons-le.' },
    { k: 'scene', t: 'SCÈNE V' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Où veux-tu me conduire ? Parle, je n’irai pas plus loin.' },
    { k: 'perso', t: 'le fantôme' },
    { k: 'ligne', t: 'Écoute-moi.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Je le veux.' },
    { k: 'perso', t: 'le fantôme' },
    { k: 'ligne', t: 'L’heure est presque arrivée où je dois retourner dans les flammes sulfureuses et torturantes.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Hélas ! pauvre âme !' },
    { k: 'perso', t: 'le fantôme' },
    { k: 'ligne', t: 'Ne me plains pas ; mais prête une attention sérieuse à ce que je vais te révéler.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Parle, je suis tenu d’écouter.' },
    { k: 'perso', t: 'le fantôme' },
    { k: 'ligne', t: 'Et de venger aussi, quand tu auras entendu.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Quoi donc ?' },
    { k: 'perso', t: 'le fantôme' },
    { k: 'ligne', t: 'Je suis l’esprit de ton père, condamné pour un certain temps à errer durant la nuit, et, durant le jour, à jeûner, confiné dans les flammes, jusqu’à ce que la souillure des crimes commis pendant les jours de ma vie soit consumée et purifiée. S’il ne m’était pas défendu de dire les secrets de ma prison, je pourrais dérouler un récit dont la plus légère parole bouleverserait ton âme, glacerait ton jeune sang, pousserait hors de leurs orbites tes deux yeux comme des étoiles, disperserait les boucles noires et agencées de ta tête, et ferait que chacun de tes cheveux se dresserait à part sur sa racine, comme les piquants sur le porc-épic craintif. Mais ces révélations de l’éternité ne sont pas faites pour des oreilles de chair et de sang. Écoute,… écoute,… oh ! écoute !… si tu as jamais aimé ton tendre père…' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Ô ciel !' },
    { k: 'perso', t: 'le fantôme' },
    { k: 'ligne', t: 'Venge-le d’un meurtre affreux et dénaturé.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'D’un meurtre ?' },
    { k: 'perso', t: 'le fantôme' },
    { k: 'ligne', t: 'D’un meurtre affreux ; et dans le meilleur cas tel est un meurtre ; mais celui-ci fut le plus affreux, le plus inouï, le plus dénaturé.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Hâte-toi de m’instruire, afin que moi, sur des ailes aussi rapides que la réflexion ou que les pensées de l’amour, je puisse voler à ma vengeance.' },
    { k: 'perso', t: 'le fantôme' },
    { k: 'ligne', t: 'Je te trouve prêt ; et quand tu serais plus inerte que l’herbe grasse qui pourrit à loisir sur les bords du Léthé, ne serais-tu pas excité par ceci ? Maintenant, Hamlet, écoute : on a donné à entendre qu’un serpent m’avait piqué pendant que je dormais dans mon verger ; c’est ainsi que la publique oreille du Danemark a été grossièrement abusée par un rapport forgé sur ma mort. Mais sache, toi, noble jeune homme, que le serpent dont la piqûre frappa la vie de ton père porte maintenant sa couronne.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Ô mon âme prophétique ! Mon oncle !' },
    { k: 'perso', t: 'le fantôme' },
    { k: 'ligne', t: 'Oui, cette brute incestueuse, adultère, par la magie de son esprit, par des dons perfides (ô damnable esprit, damnables dons, qui ont le pouvoir de séduire ainsi !) gagna à sa honteuse convoitise la volonté de ma reine, si vertueuse en apparence. Ô Hamlet ! quelle décadence il y eut là ! De moi, de qui l’amour était d’une dignité telle qu’il marchait toujours, mains jointes, avec le serment que je lui avais fait au mariage, descendre jusqu’à un misérable dont les dons naturels étaient si pauvres auprès des miens ! Mais, ainsi que la vertu ne sera jamais ébranlée, quand même la luxure la courtiserait sous une forme divine ; ainsi l’impureté, quoique unie à un ange rayonnant, se rassasiera vite en un lit céleste, et se ruera aussitôt sur l’immonde curée. Mais doucement ! Je crois sentir l’air du matin ! abrégeons. Comme je dormais dans mon verger, ainsi que c’était toujours mon usage après midi, ton oncle envahit furtivement l’heure de ma sécurité, avec une fiole du suc maudit de la jusquiame, et il répandit dans les porches de mes oreilles cette essence qui distille la lèpre, et dont l’action est en telle hostilité avec le sang de l’homme que, prompte comme le vif-argent, elle court à travers toutes les barrières naturelles et toutes les allées du corps, et que, par une force subite, comme une goutte acide dans le lait, elle fait figer et cailler le sang le plus coulant et le plus sain. Ainsi du mien ; et une dartre toute soudaine enveloppa comme d’une écorce qui me fit ressembler à Lazare, d’une croûte honteuse et dégoûtante, la surface lisse de tout mon corps. Voilà comme, en dormant, par la main d’un frère, je fus d’un seul coup frustré de ma vie, de ma couronne, de ma reine, fauché en pleine floraison de mes péchés, sans sacrements, sans préparation, sans les saintes huiles, sans avoir fait mon examen, et envoyé là où il faut rendre compte, avec toutes mes fautes pesant sur ma tête. Ô horrible ! ô horrible ! très-horrible ! Si la nature vit encore en toi, ne supporte pas cela ! Ne laisse pas le lit royal du Danemark servir de couche à la luxure et à l’inceste damné. Mais quelle que soit la voie par où tu poursuivras cette action, ne souille pas ta pensée, et ne laisse point ton âme projeter la moindre chose contre ta mère ; abandonne-la au ciel et à ces épines qui habitent dans son sein pour la piquer et la percer. Adieu une fois pour toutes ! Le ver luisant montre que le matin approche ; sa flamme inefficace commence à pâlir. Adieu, adieu, adieu, souviens-toi de moi.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Ô vous toutes, armées du ciel ! Ô terre ! quoi de plus ? dois-je vous associer aussi l’enfer ? Arrête, arrête, mon cœur ; et vous, mes nerfs, ne vieillissez pas tout à coup, mais soutenez-moi de toute votre roideur. Me souvenir de toi ? Oui, pauvre âme, tant que la mémoire conservera un siège dans ce crâne bouleversé. Me souvenir de toi ? Oui, j’effacerai du registre de ma mémoire tous les vulgaires souvenirs qui m’étaient chers, toutes les sentences des livres, toutes les formes, toutes les impressions du passé que la jeunesse et l’observation y ont inscrites ; sur les pages et dans tout le volume de mon cerveau, ton commandement seul vivra, dégagé de tout sujet moins noble… Oui, par le ciel ! — Ô femme perverse entre toutes ! Ô scélérat ! scélérat ! souriant et damné scélérat ! Ici, mes tablettes ! car il importe d’y noter qu’un homme peut sourire, et sourire, et être un scélérat. Je suis sûr, du moins, que cela peut être ainsi en Danemark (il écrit) vous y êtes, mon oncle. Et maintenant, à mon mot d’ordre ! C’est : « Adieu, adieu, souviens-toi de moi. » Je l’ai juré.' },
    { k: 'ligne', t: 'horatio' },
    { k: 'ligne', t: ', derrière la scène. — Mon seigneur, mon seigneur !' },
    { k: 'ligne', t: 'marcellus' },
    { k: 'ligne', t: ', derrière la scène. — Seigneur Hamlet !' },
    { k: 'ligne', t: 'horatio' },
    { k: 'ligne', t: ', derrière la scène. — Dieu le garde !' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Ainsi soit-il !' },
    { k: 'ligne', t: 'marcellus' },
    { k: 'ligne', t: ', derrière la scène. — Holà ! ho ! ho ! mon seigneur !' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Holà ! oh, oh, petit ! Viens, l’oiseau, viens !' },
    { k: 'perso', t: 'marcellus' },
    { k: 'ligne', t: 'Où en êtes-vous, mon noble seigneur ?' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Quelles nouvelles, mon seigneur ?' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Oh ! prodigieuses !' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Mon bon seigneur ! dites-les.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Non ; vous les révélerez.' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Pas moi, mon seigneur ; par le ciel !' },
    { k: 'perso', t: 'marcellus' },
    { k: 'ligne', t: 'Ni moi, mon seigneur.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Qu’en dites-vous donc ? Un cœur d’homme eût-il pu le croire ?… Mais vous serez secrets ?' },
    { k: 'ligne', t: 'horatio' },
    { k: 'ligne', t: 'marcellus' },
    { k: 'ligne', t: 'et' },
    { k: 'ligne', t: '. — Oui, par le ciel, mon seigneur !' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Il n’y a nulle part, dans tout le Danemark, un scélérat… qui ne soit un fieffé coquin.' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Il n’est pas besoin, mon seigneur, d’un fantôme qui sorte du tombeau pour nous dire cela.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Oui, vraiment, vous dites vrai, et par conséquent, sans aucun détail de plus, je tiens pour convenable que nous nous serrions la main et que nous nous séparions, vous, pour aller où vous conduiront vos affaires et vos penchants, car chaque homme a ses affaires et ses penchants, quels qu’ils soient ; et moi, pour mon propre et pauvre compte, voyez-vous, j’irai prier.' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Ce ne sont que paroles d’égarement et de vertige, mon seigneur.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Je suis fâché qu’elles vous offensent ; sincèrement oui, ma foi, sincèrement.' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Il n’y a point là d’offense, mon seigneur.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Si fait, par saint Patrice ! il y en a une, Horatio, et même une grande offense. Quant à cette vision, c’est un honnête fantôme, permettez-moi de vous dire cela ; et pour ce qui est de votre désir de connaître ce qu’il y a entre nous, réprimez-le comme vous pourrez. Et maintenant, mes bons amis, comme camarades, compagnons d’armes et amis, accordez-moi une pauvre faveur.' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Qu’est-ce, mon seigneur ? Nous le ferons.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Ne faites jamais connaître ce que vous avez vu cette nuit.' },
    { k: 'ligne', t: 'horatio' },
    { k: 'ligne', t: 'marcellus' },
    { k: 'ligne', t: 'et' },
    { k: 'ligne', t: '. — Mon seigneur, nous n’en dirons rien.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Bien, mais jurez-le.' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Sur ma foi, monseigneur, ce ne sera pas moi.' },
    { k: 'perso', t: 'marcellus' },
    { k: 'ligne', t: 'Ni moi, mon seigneur, sur ma foi.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Sur mon épée.' },
    { k: 'perso', t: 'marcellus' },
    { k: 'ligne', t: 'Nous avons déjà juré, mon seigneur.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'N’importe, sur mon épée ; n’importe.' },
    { k: 'ligne', t: 'le fantôme' },
    { k: 'ligne', t: ', sous la terre. — Jurez !' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Ah ! ah ! mon garçon, c’est ton avis ? Es-tu là, bonne pièce ? Allons, vous entendez le camarade, là-bas, à la cave ; consentez à jurer.' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Dites la formule du serment, mon seigneur.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Ne parlez jamais de ce que vous avez vu ici. Jurez par mon épée.' },
    { k: 'ligne', t: 'le fantôme' },
    { k: 'ligne', t: ', sous la terre. — Jurez !' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Hic et ubique ? Changeons donc de place. Venez ici, messieurs, et replacez vos mains sur mon épée. Jurez par mon épée de ne jamais parler de ce que vous avez entendu !' },
    { k: 'ligne', t: 'le fantôme' },
    { k: 'ligne', t: ', sous la terre. — Jurez par son épée !' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Bien dit, vieille taupe. Peux-tu travailler si vite sous terre ? Un précieux mineur !… Allons encore plus loin, mes bons amis.' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Oh par le jour et la nuit, voilà un prodige étrange !' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Faites-lui donc l’accueil qu’on fait à un étranger. Il y a plus de choses au ciel et sur la terre, Horatio, qu’il n’en est rêvé dans votre philosophie. Mais allons ; ici comme auparavant, jurez que jamais (et en aide vous soit la miséricorde de Dieu !) si étrange et si bizarre que je puisse me montrer, comme je trouverai peut-être à propos par la suite de m’habiller d’un caractère fantasque, jamais, me voyant en de tels moments, vous ne croiserez les bras de la sorte, ni ne secouerez ainsi la tête, ni ne prononcerez quelqu’une de ces phrases équivoques, comme « Bien, bien, nous savons ; » ou « Nous pourrions, si nous voulions… ; » ou ! « Si nous avions envie de parler… ; » ou : « Si l’on pouvait, il y aurait… ; » ou telle autre parole ambiguë donnant à entendre que vous savez quelque chose de moi… Jurez vous cela ?… Que la grâce et la miséricorde vous soient donc en aide au besoin !' },
    { k: 'ligne', t: 'le fantôme' },
    { k: 'ligne', t: ', sous la terre. — Jurez !' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Calme-toi, calme-toi, âme en peine !… Ainsi, messieurs, je me recommande à vous de toute mon affection, et tout ce qu’un aussi pauvre homme que Hamlet pourra faire pour vous exprimer son attachement et son amitié, Dieu aidant, ne vous manquera pas. Allons-nous en ensemble ; et toujours le doigt sur les lèvres, je vous prie. Notre siècle est en désarroi. Ô fatalité maudite, que je sois jamais né pour le remettre en ordre ! Allons, venez, partons ensemble.' },
    { k: 'acte', t: 'ACTE DEUXIÈME' },
    { k: 'scene', t: 'SCÈNE I' },
    { k: 'perso', t: 'polonius' },
    { k: 'ligne', t: 'Donnez-lui cet argent et ces lettres, Reynaldo.' },
    { k: 'perso', t: 'reynaldo' },
    { k: 'ligne', t: 'Ainsi ferai-je, mon seigneur.' },
    { k: 'perso', t: 'polonius' },
    { k: 'ligne', t: 'Vous serez sage à miracle, bon Reynaldo, si vous voulez bien, avant de lui faire visite, vous enquérir de sa conduite.' },
    { k: 'perso', t: 'reynaldo' },
    { k: 'ligne', t: 'Mon seigneur, j’étais dans cette intention.' },
    { k: 'perso', t: 'polonius' },
    { k: 'ligne', t: 'Bien dit, ma foi, très-bien dit. Suivez ceci, monsieur. Commencez-moi par demander quels Danois se trouvent à Paris, comment ils y sont, qui ils sont, leurs ressources, leur demeure, leurs compagnies, leurs dépenses ; et quand, par cette enceinte continue de questions, en allant à la dérive, vous trouverez qu’on connaît mon fils, côtoyez de plus près, plutôt que d’aborder tout de suite par des questions particulières. Présentez-vous, par exemple, comme ayant de lui quelque lointaine connaissance. Ainsi, dites « Je connais son père et ses amis, et même lui un peu. » Vous comprenez cela, Reynaldo ?' },
    { k: 'perso', t: 'reynaldo' },
    { k: 'ligne', t: 'Oui, très-bien, mon seigneur.' },
    { k: 'perso', t: 'polonius' },
    { k: 'ligne', t: '« Et lui, un peu… mais, » pourrez-vous ajouter, « pas très-bien. Au reste, si c’est celui que je veux dire, il est fort dérangé, adonné à ceci, à cela. » Et alors mettez à sa charge tel conte bleu qu’il vous plaira. Ah ça ! pourtant, rien d’assez bas pour le déshonorer. Prenez garde à cela, monsieur. Mais seulement cette légèreté, ce désordre, ces écarts ordinaires qui sont les compagnons notoires et bien connus de la jeunesse et de la liberté.' },
    { k: 'perso', t: 'reynaldo' },
    { k: 'ligne', t: 'Comme de jouer, mon seigneur.' },
    { k: 'perso', t: 'polonius' },
    { k: 'ligne', t: 'Oui ; ou de boire, de bretailler, de jurer, de quereller, de courir les filles ; … vous pouvez aller jusque-là.' },
    { k: 'perso', t: 'reynaldo' },
    { k: 'ligne', t: 'Mon seigneur, cela le déshonorerait.' },
    { k: 'perso', t: 'polonius' },
    { k: 'ligne', t: 'Ma foi, non, si vous savez, tout en l’accusant, tempérer la chose. Il ne faudra pas mettre à sa charge un surcroît de scandale, comme de le donner pour livré à la débauche. Ce n’est pas là ce que je veux dire. Mais murmurez si délicatement ses fautes qu’elles puissent passer pour les torts de la liberté, pour les éclairs et les éclats d’une âme en feu, pour une fougue naturelle au sang indompté dont tous, à cet âge, sentent les assauts.' },
    { k: 'perso', t: 'reynaldo' },
    { k: 'ligne', t: 'Mais, mon bon seigneur…' },
    { k: 'perso', t: 'polonius' },
    { k: 'ligne', t: 'Pourquoi je vous charge de faire cela ?' },
    { k: 'perso', t: 'reynaldo' },
    { k: 'ligne', t: 'Oui, mon seigneur, je voudrais le savoir.' },
    { k: 'perso', t: 'polonius' },
    { k: 'ligne', t: 'Eh bien ! monsieur, voici mon but ; et ce stratagème, je crois, est d’un succès garanti. Quand vous aurez attribué à mon fils ces légers défauts, comme s’il s’agissait d’un objet qui, à l’user, se serait un peu taché, — suivez-moi bien, — si le partenaire de votre entretien, celui que vous voudriez sonder, a jamais vu le jeune homme sur qui portent vos murmures coupable de quelqu’un des forfaits susdits, soyez assuré qu’il finira par vous dire en conclusion : « Mon bon monsieur, » ou « mon ami, » ou « monsieur, » selon la façon de parler ou le titre usité dans le pays, ou par la personne en question…' },
    { k: 'perso', t: 'reynaldo' },
    { k: 'ligne', t: 'Très-bien, mon seigneur.' },
    { k: 'perso', t: 'polonius' },
    { k: 'ligne', t: 'Et alors, monsieur, il dira que… il dira… qu’est-ce que j’étais en train de dire ? Par la sainte messe ! j’étais en train de dire quelque chose… où en suis-je resté ?' },
    { k: 'perso', t: 'reynaldo' },
    { k: 'ligne', t: 'Et il finira par dire, en conclusion…' },
    { k: 'perso', t: 'polonius' },
    { k: 'ligne', t: 'Il finira par dire, en conclusion, oui, morbleu il finira par vous dire : « Je connais ce gentilhomme, je l’ai vu hier ou l’autre jour, ou à tel moment, ou à tel autre, avec tel ou tel ; et, comme vous dites, il était là à jouer ; où il avalait sa rasade, où il avait une dispute à la paume ; » ou peut-être : « je l’ai vu entrer dans une de ces maisons de commerce, » videlicet, un mauvais lieu,… ou telle autre chose. Voyez-vous maintenant ? Le hameçon de votre mensonge prendra ainsi la carpe de la vérité ; et, voilà comme, nous autres gens de bon sens et de pénétration, à force de machines et en essayant de biais, nous savons indirectement suivre notre direction. C’est ainsi, d’après mes instructions et mes avis ci-dessus, que vous en agirez avec mon fils. Y êtes-vous, ou n’y êtes-vous pas ?' },
    { k: 'perso', t: 'reynaldo' },
    { k: 'ligne', t: 'J’y suis, mon seigneur.' },
    { k: 'perso', t: 'polonius' },
    { k: 'ligne', t: 'Dieu soit avec vous ! Bon voyage.' },
    { k: 'perso', t: 'reynaldo' },
    { k: 'ligne', t: 'Mon bon seigneur…' },
    { k: 'perso', t: 'polonius' },
    { k: 'ligne', t: 'Observez ses penchants par vous-même.' },
    { k: 'perso', t: 'reynaldo' },
    { k: 'ligne', t: 'Ainsi ferai-je, mon seigneur.' },
    { k: 'perso', t: 'polonius' },
    { k: 'ligne', t: 'Et laissez-le chanter sa gamme.' },
    { k: 'perso', t: 'reynaldo' },
    { k: 'ligne', t: 'Bien, mon seigneur.' },
    { k: 'perso', t: 'polonius' },
    { k: 'ligne', t: 'Adieu ! — Qu’est-ce, Ophélia ? De quoi s’agit-il ?' },
    { k: 'perso', t: 'ophélia' },
    { k: 'ligne', t: 'Oh ! mon seigneur, mon seigneur, j’ai été si effrayée !' },
    { k: 'perso', t: 'polonius' },
    { k: 'ligne', t: 'De quoi, au nom du ciel ?' },
    { k: 'perso', t: 'ophélia' },
    { k: 'ligne', t: 'Mon seigneur, comme j’étais à coudre dans mon cabinet, le seigneur Hamlet, avec son pourpoint tout défait, sans chapeau sur la tête, ses bas froissés, sans jarretières, et tombant, enroulés, jusque sur sa cheville, pâle comme sa chemise, ses genoux se heurtant l’un contre l’autre, et avec un regard d’une expression aussi pitoyable que s’il avait été détaché du fond de l’enfer pour faire un récit d’horreurs… il est venu se poser devant moi.' },
    { k: 'perso', t: 'polonius' },
    { k: 'ligne', t: 'Fou pour l’amour de toi ?' },
    { k: 'perso', t: 'ophélia' },
    { k: 'ligne', t: 'Monseigneur, je ne sais pas ; mais vraiment, je le crains.' },
    { k: 'perso', t: 'polonius' },
    { k: 'ligne', t: 'Qu’a-t-il dit ?' },
    { k: 'perso', t: 'ophélia' },
    { k: 'ligne', t: 'Il m’a prise par le poignet et m’a serrée très-fort ; puis il s’écarte de toute la longueur de son bras, et tenant son autre main, ainsi, au dessus de son front, il tombe en une contemplation de mon visage comme s’il eût voulu le dessiner. Il est longtemps resté ainsi. Enfin, — une petite secousse à mon bras, et trois fois sa tête ainsi balancée de bas en haut, — il a poussé un soupir si pitoyable et si profond qu’il semblait devoir faire éclater tout son corps et mettre fin à son existence. Cela fait, il me laisse aller ; et, la tête tournée par-dessus son épaule, il paraissait trouver son chemin sans ses yeux, car il a passé la porte sans leur secours, et jusqu’au dernier moment, il a tenu leur lumière tournée vers moi.' },
    { k: 'perso', t: 'polonius' },
    { k: 'ligne', t: 'Allons, viens avec moi ; je vais trouver le roi. C’est là, au vrai, le délire de l’amour qui se ravage lui-même par la violence qui lui appartient, et entraîne la volonté à des entreprises désespérées, aussi souvent que toute autre passion qui soit sous le ciel pour affliger notre nature. J’en suis fâché. Mais quoi ? Lui avez-vous adressé dernièrement quelques paroles rudes ?' },
    { k: 'perso', t: 'ophélia' },
    { k: 'ligne', t: 'Non, mon bon seigneur ; mais, comme vous l’aviez commandé, j’ai repoussé ses lettres, et j’ai refusé ses visites.' },
    { k: 'perso', t: 'polonius' },
    { k: 'ligne', t: 'C’est cela qui l’a rendu fou. Je suis fâché de ne l’avoir pas observé avec plus d’attention et de discernement ; je craignais que ce ne fût seulement une plaisanterie, et qu’il ne se proposât ton naufrage. Mais maudits soient mes soupçons jaloux ! Il semble que ce soit le propre de notre âge de dépasser notre portée, en nos jugements, comme, parmi les gens plus jeunes, c’est le défaut commun de manquer de réflexion. Viens, allons vers le roi ; ceci doit être connu, dont le secret gardé pourrait causer plus de peine que ne causera de haine cet amour révélé. Allons.' },
    { k: 'scene', t: 'SCÈNE II' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Soyez les bienvenus, cher Rosencrantz, et vous, Guildenstern ! Outre le grand désir que, depuis longtemps, nous avions de vous voir, le besoin que nous avons de vos services a provoqué notre hâtif appel. Vous avez su quelque chose de la transformation de Hamlet ; je dis transformation, car en lui ni l’homme extérieur ni l’intérieur ne ressemblent plus à ce qu’il était. Quelle pourrait être la cause, autre que la mort de son père, qui l’a jeté à ce point hors de toute conscience de lui-même, je ne saurais l’imaginer. Vous donc qui avez été dès un si jeune âge élevés avec lui, et qui, depuis lors, avez vécu si voisins de sa jeunesse et de ses goûts, je vous prie tous deux de vouloir bien consacrer à notre cour quelque peu de votre loisir, afin de l’attirer vers les plaisirs par votre compagnie, et de saisir, par tous les indices que le hasard vous permettra de glaner, s’il y a quelque motif à nous inconnu qui l’afflige ainsi, et qui, venant à être découvert, serait à portée de nos remèdes.' },
    { k: 'perso', t: 'la reine' },
    { k: 'ligne', t: 'Mes bons messieurs, il a beaucoup parlé de vous ; et je suis sûre qu’il n’y a pas en ce monde deux hommes à qui il soit plus attaché. S’il vous plaît de nous montrer assez de courtoisie et de bon vouloir pour passer quelque temps avec nous, au secours et au profit de nos espérances, votre visite sera comblée de tous les remerciements qui conviennent à la gratitude d’un roi.' },
    { k: 'perso', t: 'rosencrantz' },
    { k: 'ligne', t: 'Vos Majestés pourraient, en vertu du souverain pouvoir qu’elles ont sur nous, donner à leur bon plaisir redouté la forme d’un ordre plutôt que d’une prière.' },
    { k: 'perso', t: 'guildenstern' },
    { k: 'ligne', t: 'Nous obéissons d’ailleurs tous les deux, et nous faisons ici hommage de nous-mêmes et de nos efforts tendus jusqu’au bout, mettant à vos pieds nos services pour être commandés par vous.' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Je vous remercie, Rosencrantz, et vous, aimable Guildenstern.' },
    { k: 'perso', t: 'la reine' },
    { k: 'ligne', t: 'Je vous remercie, Guildenstern, et vous, aimable Rosencrantz ; et je vous conjure d’aller à l’instant voir mon fils, hélas ! trop changé. — Que quelques-uns de vous conduisent ces messieurs là où est Hamlet.' },
    { k: 'perso', t: 'guildenstern' },
    { k: 'ligne', t: 'Que le ciel lui rende notre présence et nos soins agréables et salutaires !' },
    { k: 'perso', t: 'la reine' },
    { k: 'ligne', t: 'Hélas ! Ainsi soit-il !' },
    { k: 'perso', t: 'polonius' },
    { k: 'ligne', t: 'Les ambassadeurs sont revenus de Norwége, fort satisfaits, mon bon seigneur.' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Tu es toujours le père aux bonnes nouvelles.' },
    { k: 'perso', t: 'polonius' },
    { k: 'ligne', t: 'Vraiment, mon seigneur ? Soyez sûr, mon bon souverain, que je tiens mes services, comme je tiens mon âme, tout ensemble à la disposition de mon Dieu et de mon gracieux roi ; et je pense (ou bien cette mienne cervelle ne sait plus suivre la piste d’une affaire aussi sûrement qu’elle en avait coutume) je pense que j’ai trouvé la vraie cause de la démence de Hamlet.' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Ah ! dis-moi cela ! Voilà ce qu’il me tarde d’entendre !' },
    { k: 'perso', t: 'polonius' },
    { k: 'ligne', t: 'Donnez d’abord audience aux ambassadeurs ; mes nouvelles seront le dessert après ce grand festin.' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Fais-leur toi-même les honneurs, et introduis-les. (Polonius sort.) Il me dit, ma chère Gertrude, qu’il a trouvé le point capital et la source de tout le dérangement de notre fils.' },
    { k: 'perso', t: 'la reine' },
    { k: 'ligne', t: 'Je doute qu’il y en ait une autre que cette grande cause : la mort de son père et l’extrême hâte de notre mariage.' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Bien ! nous le sonderons. — Soyez les bienvenus, mes bons amis. Dites, Voltimand, que nous apportez-vous de la part de notre frère de Norwége ?' },
    { k: 'perso', t: 'voltimand' },
    { k: 'ligne', t: 'La plus riche réciprocité de compliments et de vœux. Dès notre première démarche, il a envoyé l’ordre de suspendre les recrutements de son neveu, qui lui paraissaient être des préparatifs contre le Polonais ; mais, y ayant mieux regardé, il les trouva réellement dirigés contre Votre Altesse. Alors, blessé de voir comment on avait abusé de sa maladie, de son âge, de son impuissance, il fait signifier ses ordres à Fortinbras, qui obéit sur-le-champ, reçoit les réprimandes du roi, et, finalement, fait serment devant son oncle de ne plus faire jamais essai de ses armes contre Votre Majesté. Sur quoi le vieux roi, débordé de joie, lui assigne un revenu annuel de trois mille écus, et lui donne commission d’employer contre le Polonais les soldats qu’il a levés auparavant. Ci-jointe une supplique (il remet un papier), que son contenu expliquera plus amplement, vous demandant qu’il vous plaise donner un libre passage à travers vos États pour cette expédition, sous telles conditions de sûreté et de bonne entente qui sont proposées ici.' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Cela nous convient fort, et à un moment de loisir plus réfléchi, nous lirons, nous répondrons, et nous aviserons à cette affaire. Cependant nous vous remercions de la peine que vous avez si bien su prendre : allez vous reposer ; ce soir, nous festoierons ensemble ; vous serez les très-bienvenus chez moi.' },
    { k: 'perso', t: 'polonius' },
    { k: 'ligne', t: 'Cette affaire est bien terminée. Mon souverain, et vous, madame, rechercher ce que doit être la majesté, ce qu’est l’obéissance, pourquoi le jour est le jour, la nuit, la nuit, et le temps, le temps, ce ne serait autre chose que perdre la nuit, le jour et le temps ; donc… puisque la brièveté est l’âme de l’esprit, duquel l’anatomie et les fleurs de parade extérieure ne sont qu’ennui, je serai bref. Votre noble fils est fou. Fou je l’appelle, car vouloir définir au vrai la folie, qu’est-ce ? si ce n’est n’être soi-même rien de moins que fou ? Mais laissons cela.' },
    { k: 'perso', t: 'la reine' },
    { k: 'ligne', t: 'Plus de choses et moins d’art.' },
    { k: 'perso', t: 'polonius' },
    { k: 'ligne', t: 'Madame, je vous jure que je n’emploie l’art aucunement. Que votre fils est fou, cela est vrai. Il est vrai que c’est une pitié. Et c’est une pitié que cela soit vrai. Sotte figure de rhétorique. Mais disons-lui adieu, car je ne veux pas employer l’art. Ainsi, accordons qu’il est fou ; et maintenant il nous reste à trouver la cause de cet effet, ou, pour mieux dire, la cause de ce méfait ; car cet effet est un méfait qui vient d’une cause. Voilà ce qui demeure démontré, et voici ce qui reste à démontrer. Pesez bien tout. J’ai une fille ; je l’ai, puisqu’elle est encore à moi ; une fille qui, dans son respect et son obéissance, suivez bien, m’a remis ceci. Maintenant, résumez et concluez…' },
    { k: 'ligne', t: 'C’est une mauvaise phrase, une phrase vulgaire. « Bienheureuse beauté » est un mot vulgaire. Mais écoutez ; poursuivons.' },
    { k: 'perso', t: 'la reine' },
    { k: 'ligne', t: 'Ceci lui a été adressé par Hamlet ?' },
    { k: 'perso', t: 'polonius' },
    { k: 'ligne', t: 'Ma bonne dame, attendez un moment, je serai exact.' },
    { k: 'ligne', t: 'Doute que les étoiles soient de feu,' },
    { k: 'ligne', t: 'Doute que le soleil tourne,' },
    { k: 'ligne', t: 'Doute que la vérité ne puisse être un mensonge ,' },
    { k: 'ligne', t: 'Mais ne doute jamais de mon amour.' },
    { k: 'ligne', t: 'Ô chère Ophélia ! je suis mal à l’aise dans ce mètre ; je n’ai pas l’art de calculer la longueur de mes gémissements. Mais que je t’aime bien, oh ! parfaitement bien, crois-le. Adieu.' },
    { k: 'ligne', t: 'À toi pour toujours, dame chérie, tant que cette machine mortelle lui appartiendra.' },
    { k: 'ligne', t: 'C’est là ce que ma fille, par obéissance, m’a montré ; et de plus, les instances de votre fils, à quelles dates, de quelles manières et en quels lieux elles se produisirent, elle a tout confié à mon oreille.' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Mais comment a-t-elle reçu son amour ?' },
    { k: 'perso', t: 'polonius' },
    { k: 'ligne', t: 'Quelle idée avez-vous de moi ?' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'L’idée d’un homme fidèle et honorable.' },
    { k: 'perso', t: 'polonius' },
    { k: 'ligne', t: 'Je ne demanderais, sur ce point, qu’à faire mes preuves. Mais que pourriez-vous penser si, lorsque j’ai vu ce chaleureux amour prendre son essor (car je m’en suis aperçu, je dois vous le dire, avant que ma fille m’eût parlé), que pourriez-vous penser de moi, vous et sa gracieuse Majesté la reine ici présente, si j’avais joué le rôle inerte d’un pupitre ou d’un portefeuille, ou si j’avais laissé mon cœur travailler sourdement et silencieusement, ou si j’avais regardé cet amour d’un œil nonchalant ? Que pourriez-vous penser ? Non, je me suis rondement mis en besogne et j’ai parlé ainsi à ma jeune damoiselle : « Le seigneur Hamlet est un prince au-dessus de ta sphère ; ceci ne doit pas être. » Et alors je lui ai donné pour préceptes de se tenir enfermée hors de ses atteintes, de n’admettre aucun messager, de ne recevoir aucun cadeau. Cela fait, elle a recueilli le fruit de mes avis, et lui (pour vous faire une courte histoire), se voyant rebuté, est tombé dans la tristesse ; de là dans le dégoût ; de là dans l’insomnie ; de là dans la faiblesse ; de là dans les rêveries flottantes, et, par ce déclin, dans la folie, où maintenant il s’égare, et qui nous met tous en deuil.' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Pensez-vous que ce soit cela ?' },
    { k: 'perso', t: 'la reine' },
    { k: 'ligne', t: 'Cela peut être, très-vraisemblablement.' },
    { k: 'perso', t: 'polonius' },
    { k: 'ligne', t: 'Est-il arrivé une seule fois (je voudrais bien le savoir) que j’aie dit positivement : cela est, et que cela se soit trouvé autrement ?' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Non, pas que je sache.' },
    { k: 'ligne', t: 'polonius' },
    { k: 'ligne', t: ', montrant sa tête et ses épaules. — Ôtez ceci de là, si cela est autrement. Pourvu que je sois guidé par les circonstances, je trouverai le point où la vérité est cachée, fût-elle cachée, en vérité, dans le centre de la terre.' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Comment pourrons-nous pousser plus loin l’enquête ?' },
    { k: 'perso', t: 'polonius' },
    { k: 'ligne', t: 'Vous savez que, parfois, il se promène quatre heures de suite ici, dans la galerie.' },
    { k: 'perso', t: 'la reine' },
    { k: 'ligne', t: 'Il s’y promène, en effet.' },
    { k: 'perso', t: 'polonius' },
    { k: 'ligne', t: 'Dans un de ces moments-là je lui lâcherai ma fille ; soyons alors, vous et moi, derrière une tapisserie ; observez leur rencontre ; s’il ne l’aime pas et si ce n’est pas ce qui l’a fait déchoir de la raison, ne me laissez plus être conseiller d’un royaume, envoyez-moi gouverner une ferme et des charretiers.' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Nous essayerons cela.' },
    { k: 'perso', t: 'la reine' },
    { k: 'ligne', t: 'Mais regardez de quel air de tristesse le pauvre malheureux vient en lisant.' },
    { k: 'perso', t: 'polonius' },
    { k: 'ligne', t: 'Éloignez-vous, je vous en conjure, éloignez-vous tous deux ; je vais l’aborder sur-le-champ : oh ! donnez-moi carte blanche. (Le roi, la reine et leur suite sortent.) Comment va mon bon seigneur Hamlet ?' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Bien, Dieu merci !' },
    { k: 'perso', t: 'polonius' },
    { k: 'ligne', t: 'Me connaissez-vous, mon seigneur ?' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Parfaitement bien : vous êtes un marchand de poisson.' },
    { k: 'perso', t: 'polonius' },
    { k: 'ligne', t: 'Non pas moi, mon seigneur.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'En ce cas, je voudrais que vous fussiez un aussi honnête homme.' },
    { k: 'perso', t: 'polonius' },
    { k: 'ligne', t: 'Honnête, mon seigneur ?' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Oui, monsieur ; être honnête, au train dont va ce monde, c’est être un homme trié sur dix mille.' },
    { k: 'perso', t: 'polonius' },
    { k: 'ligne', t: 'C’est très-vrai, mon seigneur.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Car si le soleil engendre des vers dans un chien mort ; — lui qui est un dieu, baisant une charogne… — avez-vous une fille ?' },
    { k: 'perso', t: 'polonius' },
    { k: 'ligne', t: 'J’en ai une, mon seigneur.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Ne la laissez pas se promener au soleil. La conception est une bonne chose : mais quant à la façon dont votre fille pourrait concevoir… ami, prenez-y garde.' },
    { k: 'perso', t: 'polonius' },
    { k: 'ligne', t: 'Qu’entendez-vous par là ? (À part.) Encore son refrain sur ma fille ! Cependant il ne m’a pas reconnu d’abord ; il a dit que j’étais un marchand de poisson. Il n’y est plus, il n’y est plus ! À vrai dire, dans ma jeunesse, j’ai subi bien des extrémités par le fait de l’amour ; à bien peu de chose près autant que ceci. Je veux lui parler encore. Que lisez-vous, mon seigneur ?' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Des mots, des mots, des mots !' },
    { k: 'perso', t: 'polonius' },
    { k: 'ligne', t: 'De quoi est-il question, mon seigneur ?' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Question ? Entre qui ?' },
    { k: 'perso', t: 'polonius' },
    { k: 'ligne', t: 'Je veux dire dans le livre que vous lisez, mon seigneur.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Des calomnies, monsieur ; car ce maraud de satirique dit que les vieillards ont des barbes grises ; que leurs figures sont ridées ; que leurs yeux sécrètent une ambre épaisse et comme une gomme de prunier, et qu’ils ont une abondante absence d’esprit, avec des jarrets très-faibles. Tout cela, monsieur, bien que j’y croie de tout mon pouvoir et de toute ma puissance, je tiens pourtant qu’il n’y a pas d’honnêteté à l’avoir ainsi couché par écrit ; car vous-même, monsieur, vous serez aussi vieux que je le suis, si jamais, comme un crabe, vous pouvez aller à reculons.' },
    { k: 'ligne', t: 'polonius' },
    { k: 'ligne', t: ', à part. — Quoique ce soient des folies, il y a pourtant de la suite là-dedans. Voulez-vous changer d’air, mon seigneur, et venir ailleurs ?' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Dans mon tombeau ?' },
    { k: 'perso', t: 'polonius' },
    { k: 'ligne', t: 'Ce serait assurément changer d’air tout à fait. Comme ses répliques sont parfois grosses de sens ! Heureux hasards, où souvent la folie frappe en plein, tandis que la raison et les saines pensées ne seraient pas aussi chanceuses à bien s’exprimer ! Je vais le laisser et aviser sur-le-champ aux moyens d’amener une rencontre entre lui et ma fille. Mon honorable seigneur, je prendrai très-humblement congé de vous.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Vous ne pouvez, monsieur, rien prendre de moi dont je fasse plus volontiers l’abandon… si ce n’est ma vie, si ce n’est ma vie, si ce n’est ma vie !' },
    { k: 'perso', t: 'polonius' },
    { k: 'ligne', t: 'Adieu, mon seigneur.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Ces ennuyeux vieux fous !' },
    { k: 'perso', t: 'polonius' },
    { k: 'ligne', t: 'Vous cherchez le seigneur Hamlet ; il est ici.' },
    { k: 'ligne', t: 'rosencrantz' },
    { k: 'ligne', t: ', à Polonius. — Dieu vous garde, monsieur !' },
    { k: 'perso', t: 'guildenstern' },
    { k: 'ligne', t: 'Mon honoré seigneur !…' },
    { k: 'perso', t: 'rosencrantz' },
    { k: 'ligne', t: 'Mon très-cher seigneur !…' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Mes bons, mes excellents amis ! comment vas-tu, Guildenstern ? Ah ! Rosencrantz ! Bons compagnons, comment allez-vous tous les deux ?' },
    { k: 'perso', t: 'rosencrantz' },
    { k: 'ligne', t: 'Comme le vulgaire des enfants de la terre.' },
    { k: 'perso', t: 'guildenstern' },
    { k: 'ligne', t: 'Heureux par cela même que nous ne sommes pas trop heureux. Nous ne sommes pas précisément le plus beau fleuron que la fortune porte à sa toque.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Ni les semelles que foulent ses souliers ?' },
    { k: 'perso', t: 'rosencrantz' },
    { k: 'ligne', t: 'Non, mon seigneur.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Alors vous vivez près de sa ceinture, dans le centre de ses faveurs ?' },
    { k: 'perso', t: 'guildenstern' },
    { k: 'ligne', t: 'Oui, ma foi ! nous sommes de ses amis privés.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Logés dans le secret giron de la fortune ? Oh ! oui, cela est vrai. C’est une catin. Quelles nouvelles ?' },
    { k: 'perso', t: 'rosencrantz' },
    { k: 'ligne', t: 'Aucune, mon seigneur ; si ce n’est que le monde est devenu honnête.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Alors le jugement dernier est proche ; mais votre nouvelle n’est pas vraie. Laissez-moi vous faire une question plus particulière : qu’avez-vous donc fait à la fortune, mes bons amis, pour qu’elle vous envoie en prison ici ?' },
    { k: 'perso', t: 'guildenstern' },
    { k: 'ligne', t: 'En prison, mon seigneur ?' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Le Danemark est une prison.' },
    { k: 'perso', t: 'rosencrantz' },
    { k: 'ligne', t: 'Alors le monde en est une aussi.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Une grande prison, dans laquelle il y a beaucoup de caveaux, de basses fosses et de cachots : le Danemark est un des pires.' },
    { k: 'perso', t: 'rosencrantz' },
    { k: 'ligne', t: 'Nous ne pensons pas ainsi, mon seigneur.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Soit ! c’est donc que, pour vous, le Danemark n’est pas un cachot ; car il n’y a de bien et de mal que selon l’opinion qu’on a. Pour moi, c’est une prison.' },
    { k: 'perso', t: 'rosencrantz' },
    { k: 'ligne', t: 'Soit ! C’est donc votre ambition qui vous le fait paraître ainsi ; il est trop étroit pour votre âme.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Ô Dieu ! je pourrais être enfermé dans une coque de noix, et m’estimer roi d’un espace infini, n’était que j’ai de mauvais rêves.' },
    { k: 'perso', t: 'guildenstern' },
    { k: 'ligne', t: 'Lesquels rêves sont assurément l’ambition ; car la substance même des ambitieux n’est rien de plus que l’ombre d’un rêve.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Un rêve lui-même n’est qu’une ombre.' },
    { k: 'perso', t: 'rosencrantz' },
    { k: 'ligne', t: 'Assurément, et je tiens que l’ambition est d’une essence si aérienne et si légère qu’elle n’est que l’ombre d’une ombre.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'En ce cas nos gueux sont des corps réels, et nos monarques et nos grands héros qui n’en finissent pas sont des ombres de gueux. — Irons-nous à la cour ? car, par ma foi, je ne suis pas en état de raisonner.' },
    { k: 'perso', t: 'rosencrantz et guildenstern' },
    { k: 'ligne', t: 'Nous y serons de votre suite.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Il ne s’agit pas de cela ; je ne veux point vous ranger avec le reste de mes serviteurs, car à vous parler en honnête homme, je suis terriblement accompagné. Mais dites-moi, — pour aller droit par les sentiers battus de l’amitié, — que venez-vous faire à Elseneur ?' },
    { k: 'perso', t: 'rosencrantz' },
    { k: 'ligne', t: 'Vous voir, mon seigneur, pas d’autre motif.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Gueux comme je le suis, je suis pauvre même en remerciements, mais je vous remercie, et soyez sûrs, mes chers amis, que mes remerciements sont trop chers à un sou. Ne vous a-t-on pas envoyé chercher ? Est-ce votre propre penchant ? est-ce une visite de plein gré ? Allons, allons ! agissez en toute justice avec moi. Allons, allons ! en vérité, parlez !' },
    { k: 'perso', t: 'guildenstern' },
    { k: 'ligne', t: 'Que pourrions-nous dire, mon seigneur ?' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Quoi que ce soit, mais que cela aille au fait. On vous a envoyé chercher, et il y a une sorte de confession dans vos regards que votre pudeur n’a pas l’habileté de colorer. Je le sais, le bon roi et la reine vous ont envoyé chercher.' },
    { k: 'perso', t: 'rosencrantz' },
    { k: 'ligne', t: 'À quelle fin, mon seigneur ?' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'C’est ce que vous avez à m’apprendre. Mais permettez-moi de vous conjurer, par les droits de notre camaraderie, par l’harmonie de notre jeunesse, par les devoirs de notre tendresse toujours maintenue, et par tous les motifs encore plus touchants qu’un meilleur orateur pourrait invoquer auprès de vous, soyez simples et droits envers moi : vous a-t-on envoyé chercher, oui ou non ?' },
    { k: 'ligne', t: 'rosencrantz' },
    { k: 'ligne', t: ', à Guildenstern. — Que dites-vous ?' },
    { k: 'ligne', t: 'hamlet' },
    { k: 'ligne', t: '(Haut)' },
    { k: 'ligne', t: ', à part. — Bon ! j’ai déjà un aperçu sur votre compte.' },
    { k: 'ligne', t: '. Si vous m’aimez, ne me tenez pas rigueur.' },
    { k: 'perso', t: 'guildenstern' },
    { k: 'ligne', t: 'Mon seigneur, on nous a envoyé chercher.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Je vais vous dire pourquoi. Ainsi mes aveux anticipés vous dispenseront de vos confidences, et votre discrétion envers le roi et la reine n’aura pas à muer d’une seule plume. J’ai, depuis peu (mais pourquoi ? je ne sais), perdu toute ma gaieté, laissé là tous mes exercices accoutumés ; et en vérité, il y a tant d’accablement dans ma disposition, que ce vaste assemblage, la terre, me semble un promontoire stérile ; que cet admirable pavillon, l’air, voyez-vous, ce firmament hardiment suspendu, cette majestueuse voûte incrustée de flammes d’or, eh bien ! cela ne me paraît rien autre chose qu’un immonde et pestilentiel amas de vapeurs. Quel chef-d’œuvre que l’homme ! combien noble par la raison ! combien infini par les facultés ! combien admirable et expressif par la forme et les mouvements ? dans l’action combien semblable aux anges ! dans les conceptions combien semblable à un dieu ! Il est la merveille du monde, le type suprême des êtres animés ! Eh bien ! à mes yeux, qu’est-ce que cette quintessence de la poussière ? L’homme ne me charme pas, ni la femme non plus, quoique par votre sourire vous paraissiez me démentir.' },
    { k: 'perso', t: 'rosencraktz' },
    { k: 'ligne', t: 'Mon seigneur, il n’y avait rien de cela dans mes pensées.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Pourquoi donc avez-vous ri, lorsque j’ai dit : « L’homme ne me plaît pas ? »' },
    { k: 'perso', t: 'rosencrantz' },
    { k: 'ligne', t: 'Parce que je me disais, mon seigneur, — si l’homme ne vous plaît pas, — quel maigre accueil les comédiens recevront de vous ! Nous les avons rencontrés en chemin ; ils viennent ici vous offrir leurs services.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Celui qui joue le roi sera le bienvenu ; Sa Majesté aura un tribut de moi ; l’aventureux chevalier pourra faire usage de son fleuret et de son écu ; l’amoureux ne soupirera pas gratis ; le bouffon pourra achever tranquillement son rôle ; le niais fera rire ceux-là même dont les poumons sont secoués par une toux sèche, et la princesse nous contera ses sentiments en toute liberté, dût le vers blanc boiter pour la suivre. Quels sont ces comédiens ?' },
    { k: 'perso', t: 'rosencrantz' },
    { k: 'ligne', t: 'Ceux-là même que vous aviez coutume de voir avec plaisir, les tragédiens de la Cité.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Et par quel hasard sont-ils devenus ambulants ? Leur résidence fixe, autant pour la réputation que pour le profit, valait mieux à tous égards.' },
    { k: 'perso', t: 'rosencrantz' },
    { k: 'ligne', t: 'Je pense que leur empêchement vient de la récente innovation.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Se maintiennent-ils dans la même estime que lorsque j’étais en ville ? Sont-ils aussi suivis ?' },
    { k: 'perso', t: 'rosencrantz' },
    { k: 'ligne', t: 'Non, en vérité, ils ne le sont pas.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'D’où vient cela ? Est-ce qu’ils se rouillent ?' },
    { k: 'perso', t: 'rosencrantz' },
    { k: 'ligne', t: 'Non, leurs efforts n’ont rien perdu de leur allure accoutumée. Mais il y a, monsieur, une nichée d’enfants, de fauconneaux à la brochette, qui piaillent à force tout au haut du dialogue, et sont claqués à outrance pour cela ; ils sont aujourd’hui à la mode, et ils ont tant décrié le théâtre ordinaire (c’est ainsi qu’ils l’appellent) que beaucoup de gens portant l’épée ont peur des plumes d’oie et n’osent presque plus y venir.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Comment, sont-ce des enfants ? Qui les entretient ? Comment est réglé leur écot ? Poursuivront-ils cette profession aussi longtemps seulement qu’ils pourront chanter ? Ne diront-ils point, par la suite, s’ils arrivent eux-mêmes à être comédiens ordinaires (ainsi que cela est vraisemblable, s’ils n’ont rien de mieux à faire), que les auteurs de leur troupe leur ont fait tort, en les faisant d’avance déclamer contre leur futur héritage ?' },
    { k: 'perso', t: 'rosencrantz' },
    { k: 'ligne', t: 'Ma foi ! il y a eu beaucoup à faire de part et d’autre, et la nation estime que ce n’est pas un péché de les exciter à la dispute. Il n’y a eu pendant un temps point d’argent à gagner avec une pièce, à moins que le poëte et le comédien n’en vinssent à se gourmer avec leurs rivaux en plein dialogue.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Est-il possible ?' },
    { k: 'perso', t: 'guildenstern' },
    { k: 'ligne', t: 'Oh il y a eu déjà beaucoup d’effusion de cervelles.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Sont-ce les enfants qui l’emportent ?' },
    { k: 'perso', t: 'rosencrantz' },
    { k: 'ligne', t: 'Oui, mon seigneur, ils emportent tout, Hercule et son fardeau avec lui .' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Ce n’est pas fort étrange, car mon oncle est roi de Danemark ; et ceux qui, du vivant de mon père, lui auraient fait la moue, donnent maintenant vingt, quarante, cinquante, cent ducats par tête pour avoir son portrait en miniature. Par la sambleu ! il y a là quelque chose qui est plus que naturel ; si la philosophie pouvait le découvrir !' },
    { k: 'perso', t: 'guildenstern' },
    { k: 'ligne', t: 'Ce sont les comédiens.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Messieurs, vous êtes les bienvenus à Elseneur. Vos mains. Approchez : la marque ordinaire d’un bon accueil, ce sont les compliments et les cérémonies ; permettez que je vous traite de cette façon, de peur que mes manières, en recevant les comédiens, à qui je dois, je vous en préviens, montrer beaucoup d’égards, ne paraissent plus polies qu’envers vous. Vous êtes les bienvenus ; mais cet oncle qui est mon père, et cette tante qui est ma mère, sont abusés.' },
    { k: 'perso', t: 'guildenstern' },
    { k: 'ligne', t: 'En quoi, mon cher seigneur ?' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Je ne suis fou que lorsque le vent est nord-nord-ouest ; quand le vent est au sud, je distingue très-bien un faucon d’un héron.' },
    { k: 'perso', t: 'polonius' },
    { k: 'ligne', t: 'Grand bien vous fasse, messieurs.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Écoutez, Guildenstern… et vous aussi… pour chaque oreille un auditeur… ce grand marmot que vous voyez là n’est pas encore hors du maillot.' },
    { k: 'perso', t: 'rosencrantz' },
    { k: 'ligne', t: 'Peut-être y est-il revenu, car on dit que le vieillard est une seconde fois enfant.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Je vous fais ma prophétie qu’il vient pour me parler des comédiens ; garde à vous !… Vous avez raison, monsieur ; lundi matin, c’est bien cela, en vérité.' },
    { k: 'perso', t: 'polonius' },
    { k: 'ligne', t: 'Mon seigneur, j’ai des nouvelles à vous apprendre.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: '« Mon seigneur, j’ai des nouvelles à vous apprendre. » Du temps que Roscius était acteur à Rome…' },
    { k: 'perso', t: 'polonius' },
    { k: 'ligne', t: 'Les acteurs sont ici, mon seigneur.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Bah ! bah !' },
    { k: 'perso', t: 'polonius' },
    { k: 'ligne', t: 'Sur mon honneur.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Alors arrive chaque acteur sur son âne…' },
    { k: 'perso', t: 'polonius' },
    { k: 'ligne', t: 'Les meilleurs acteurs du monde, pour la tragédie, pour la comédie, le drame historique, la pastorale comique, l’histoire pastorale, la tragédie historique, la tragi-comédie, les pièces avec unité, ou les poëmes sans règles, Sénèque ne peut être trop lourd, ni Plaute trop léger pour eux ; pour le genre régulier, comme pour le genre libre, ils n’ont pas leurs pareils.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Ô Jephté, juge d’Israël !' },
    { k: 'ligne', t: 'Quel trésor tu avais !' },
    { k: 'perso', t: 'polonius' },
    { k: 'ligne', t: 'Quel trésor avait-il, mon seigneur ?' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Quel trésor !' },
    { k: 'ligne', t: 'Une fille très-belle, et rien de plus,' },
    { k: 'ligne', t: 'Il l’aimait mieux que bien.' },
    { k: 'ligne', t: 'polonius' },
    { k: 'ligne', t: ', à part. — Encore question de ma fille !' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Ne suis-je pas dans le vrai, vieux Jephté ?' },
    { k: 'perso', t: 'polonius' },
    { k: 'ligne', t: 'Si vous m’appelez Jephté, mon seigneur, j’ai une fille que j’aime mieux que bien.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Non, cela ne fait pas suite.' },
    { k: 'perso', t: 'poloinius' },
    { k: 'ligne', t: 'Qu’est-ce donc qui fait suite, mon seigneur ?' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Eh bien !' },
    { k: 'ligne', t: 'Comme par hasard,' },
    { k: 'ligne', t: 'Dieu le sait !…' },
    { k: 'ligne', t: 'Et puis vous savez :' },
    { k: 'ligne', t: 'Il advint donc,' },
    { k: 'ligne', t: 'Comme on pouvait le croire ?' },
    { k: 'ligne', t: '(Quatre ou cinq comédiens entrent.)' },
    { k: 'ligne', t: 'Le premier couplet de la pieuse complainte vous en apprendra plus long car, regardez ! voici venir mon interruption.' },
    { k: 'ligne', t: 'Vous êtes les bienvenus, mes maîtres, tous les bienvenus. — Je suis enchanté de te voir bien portant. — Bonjour, mes bons amis. — Oh ! mon vieil ami, qu’est-ce donc ? ta tête a pris de la frange depuis la dernière fois que je t’ai vu ; viens-tu en Danemark pour me faire la barbe ? Eh quoi ! ma jeune dame et princesse, par Notre-Dame ! Votre Seigneurie est plus près du ciel que la dernière fois où je vous vis, de toute la hauteur d’un socque à l’italienne ! Dieu veuille que votre voix, comme une pièce d’or qui n’a plus cours, ne se soit pas fêlée au delà de l’anneau ! Mes maîtres, vous êtes tous les bienvenus. Allons, sus tout de suite, sus, comme des fauconniers de France, et volons au premier gibier que nous voyons. Il nous faut une tirade à l’instant ; donnez-nous un avant-goût de votre talent ; allons, quelque tirade passionnée.' },
    { k: 'perso', t: 'le premier comédien' },
    { k: 'ligne', t: 'Quelle tirade, mon seigneur ?' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Je t’ai entendu une fois dire une tirade, mais elle n’a jamais été jouée sur le théâtre, ou si elle l’a été, elle n’est pas allée au delà d’une fois ; car la pièce, je m’en souviens, ne plaisait pas à la multitude ; c’était du caviar pour le plus grand nombre ; mais, à mon avis, et selon d’autres personnes dont les jugements en cette matière donnent le ton aux miens de bien plus haut, c’était une excellente pièce ; des scènes bien filées, écrites avec autant de réserve que de finesse. Je me souviens que quelqu’un disait qu’il n’y avait point d’épices dans les vers pour donner à la pensée du montant, ni dans les phrases une pensée qui pût convaincre l’auteur d’affectation ; il disait que c’était une œuvre d’un goût estimable, aussi saine que douce, et bien plutôt belle que parée . Il y avait surtout un morceau que j’aimais beaucoup ; c’était le récit d’Énée à Didon, et surtout le passage où il parle du meurtre de Priam. Si cela vit encore en votre mémoire, commencez à ce vers, voyons un peu, voyons :' },
    { k: 'ligne', t: 'Le hérissé Pyrrhus, pareil à la bête hyrcanienne…' },
    { k: 'ligne', t: 'Ce n’est pas cela ; cela commence par Pyrrhus.' },
    { k: 'ligne', t: 'Le hérissé Pyrrhus, dont les armes de sable, noires comme son projet, ressemblaient à la nuit quand il était couché dans le sinistre cheval, porte maintenant ces redoutables et noires couleurs barbouillées d’un blason plus lugubre : de pied en cap, maintenant il est tout gueules, horriblement colorié du sang des pères, des mères, des filles, des fils, cuit et empâté par les rues brûlantes qui prêtent une tyrannique et damnée lueur au meurtre de leur seigneur et maître. Rôti dans son courroux et dans ces flammes, et ainsi bardé de caillots coagulés, avec des yeux semblables à des escarboucles, l’infernal Pyrrhus, cherche le vieil ancêtre Priam… »' },
    { k: 'ligne', t: 'Continuez, à présent.' },
    { k: 'perso', t: 'polonius' },
    { k: 'ligne', t: 'Devant Dieu ! mon seigneur, bien déclamé, avec bon accent et bon discernement !' },
    { k: 'perso', t: 'polonius' },
    { k: 'ligne', t: 'Ce discours est trop long.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Il ira chez le barbier en même temps que votre barbe. Je t’en prie, continue ; il lui faut quelque gigue ou quelque conte de mauvais lieu ; sans cela il s’endort ; continue. Passons à Hécube.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'La reine encapuchonnée !' },
    { k: 'perso', t: 'polonius' },
    { k: 'ligne', t: 'Est-ce bien ? Oui, « reine encapuchonnée » est bien.' },
    { k: 'perso', t: 'polonius' },
    { k: 'ligne', t: 'Regardez s’il n’a pas changé de couleur ; il a les larmes aux yeux. Je t’en prie, restons-en là.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'C’est bon ! je te ferai bientôt déclamer le reste. Mon bon seigneur, voulez-vous veiller à ce que les comédiens soient bien pourvus ? Vous entendez, il faut en user bien avec eux, car ils sont l’essence et la chronique abrégée des temps. Il vaudrait mieux pour vous avoir une méchante épitaphe après votre mort, que d’être maltraité par eux durant votre vie.' },
    { k: 'perso', t: 'polonius' },
    { k: 'ligne', t: 'Mon seigneur, je les traiterai selon leur mérite.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Eh ! l’homme beaucoup mieux, par la tête-bleu ! Traitez-moi chaque homme selon son mérite, et qui donc, en ce cas, échappera aux étrivières ? Traitez-les selon votre propre rang et votre dignité ; moindres seront leurs droits, plus méritoire sera votre bonté. Emmenez-les.' },
    { k: 'perso', t: 'polonius' },
    { k: 'ligne', t: 'Venez, messieurs.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Suivez-le, mes amis ; nous verrons une pièce demain. Écoute, mon vieil ami : pouvez-vous jouer le Meurtre de Gonzague ?' },
    { k: 'perso', t: 'le premier comedien' },
    { k: 'ligne', t: 'Oui, mon seigneur.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Eh bien ! nous donnerons cela demain au soir. Vous pourriez, au besoin, étudier un discours de quelques douze ou seize vers que je voudrais mettre par écrit et y insérer ? ne pourriez-vous pas ?' },
    { k: 'perso', t: 'le premier comédien' },
    { k: 'ligne', t: 'Oui, mon seigneur.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Très-bien. Suivez ce seigneur, et faites attention à ne pas vous moquer de lui. (Polonius et les comédiens sortent.) — (À Rosencrantz et à Guildenstern.) Mes bons amis, je vous laisse jusqu’à ce soir ; vous êtes les bienvenus à Elseneur.' },
    { k: 'perso', t: 'rosencrantz' },
    { k: 'ligne', t: 'Mon bon seigneur !' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Or çà, Dieu soit avec vous ! — Maintenant je suis seul. Oh ! quel drôle et quel rustre inerte je suis ! N’est-ce pas chose monstrueuse que ce comédien que voici, dans une pure fiction, dans une passion rêvée, puisse, selon sa propre idée, contraindre son âme à ce point que, par le travail de son âme, son visage entier blêmisse. Et des pleurs dans ses yeux ! l’égarement dans sa physionomie ! une voix brisée ! et toute son action appropriant les formes à l’idée ! Et tout cela pour rien ! pour Hécube ! Qu’est-ce que lui est Hécube, ou qu’est-ce qu’il est à Hécube, lui, pour qu’il pleure pour elle ? Que ferait-il donc s’il avait, pour se passionner, le motif et le mot d’ordre que j’ai ? Il inonderait de larmes le théâtre, il déchirerait l’oreille de la multitude par de formidables paroles, il rendrait fou le coupable et épouvanterait l’innocent ; il confondrait l’ignorant et frapperait de stupeur, sur ma parole ! les facultés mêmes d’entendre et de voir. Et moi ! moi, cependant, plat coquin, courage de boue, je suis là à parler comme un Jeannot rêveur , mal imprégné de la fécondité de ma cause, et je ne puis rien dire, non, rien pour un roi dont le domaine et la très-chère vie ont subi un infernal échec. Suis-je un lâche ? Qui vient m’appeler drôle ? se jeter au travers de mon chemin ? m’arracher la barbe et me la souffler à la face ? me tirer par le nez ? me donner des démentis par la gorge, jusqu’à me les enfoncer dans les poumons ? Qui me fait cela ? ah ! qu’est-ce donc ? Je prendrais bien la chose, car il faut assurément que j’aie un foie de pigeonneau, et que je manque du fiel qui doit rendre amère l’oppression ; autrement, avant cette heure, j’aurais engraissé déjà tous les vautours de la contrée avec les entrailles de ce laquais ! Ô sanglant, sensuel coquin ! Traître sans remords, sans pudeur, dénaturé coquin ! Eh bien ! quoi ? Quel âne suis-je donc ? Ceci est très-brave que, moi, fils d’un bien-aimé père assassiné, moi, excité à ma vengeance par le ciel et l’enfer, j’aie besoin comme une catin de décharger mon cœur en paroles et que je tombe dans les malédictions comme une vraie coureuse de rues, comme une fille de cuisine ! Fi donc ! fi ! En avant, mon cerveau ! Un instant : j’ai entendu dire que des créatures coupables, assistant à une pièce de théâtre, avaient, par l’artifice même de la scène, été frappées à l’âme de telle sorte que, sur l’heure, elles avaient déclaré leurs forfaits . Car le meurtre, quoiqu’il n’ait pas de langue, saura parler par quelque organe miraculeux. Je ferai jouer, par ces comédiens, quelque chose qui ressemble au meurtre de mon père, devant mon oncle, et j’observerai son apparence, je le sonderai jusqu’au vif ; s’il se trouble, je sais mon chemin. L’esprit que j’ai vu pourrait bien être un démon ; le démon a le pouvoir de prendre une forme qui plaît ; oui, et peut-être, grâce à ma faiblesse et à ma mélancolie (car il est très-puissant sur les tempéraments ainsi faits), m’abuse-t-il pour me damner. Je veux me fonder sur des preuves plus directes que cela. Oui, cette pièce est le piège où je surprendrai la conscience du roi.' },
    { k: 'acte', t: 'ACTE TROISIÈME' },
    { k: 'scene', t: 'SCÈNE I' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Et vous ne pouvez pas, en faisant dériver la conversation, savoir de lui pourquoi il montre ce désordre, déchirant si cruellement tous ses jours de repos par une turbulente et dangereuse démence ?' },
    { k: 'perso', t: 'rosencrantz' },
    { k: 'ligne', t: 'Il avoue bien qu’il se sent lui-même dérouté ; mais pour quel motif, il ne veut en aucune façon le dire.' },
    { k: 'perso', t: 'guildenstern' },
    { k: 'ligne', t: 'Et nous ne le trouvons pas disposé à se laisser sonder ; mais avec une folie rusée, il nous échappe, quand nous voudrions l’amener à quelque aveu sur son véritable état.' },
    { k: 'perso', t: 'la reine' },
    { k: 'ligne', t: 'Vous a-t-il bien recus ?' },
    { k: 'perso', t: 'rosencrantz' },
    { k: 'ligne', t: 'Tout à fait en galant homme.' },
    { k: 'perso', t: 'guildenstern' },
    { k: 'ligne', t: 'Mais avec beaucoup d’effort dans sa manière.' },
    { k: 'perso', t: 'rosencrantz' },
    { k: 'ligne', t: 'Avare de paroles, mais quant à nos questions seulement ; très-libre dans ses répliques.' },
    { k: 'perso', t: 'la reine' },
    { k: 'ligne', t: 'L’avez-vous provoqué à quelque passe-temps ?' },
    { k: 'perso', t: 'rosencrantz' },
    { k: 'ligne', t: 'Madame, il s’est justement trouvé que nous avons rencontré sur notre chemin certains comédiens ; nous lui avons parlé d’eux, et nous avons cru voir en lui une espèce de joie d’entendre cette nouvelle. Ils sont quelque part dans le palais ; et, à ce que je crois, ils ont déjà l’ordre de jouer ce soir devant lui.' },
    { k: 'perso', t: 'polonius' },
    { k: 'ligne', t: 'Cela est très-vrai, et il m’a prié d’engager Vos Majestés à entendre et à voir cette affaire.' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'De tout mon cœur, et j’ai beaucoup de contentement à apprendre qu’il soit porté à cela. Mes chers messieurs, aiguisez encore en lui ce goût et poussez plus avant ses projets vers de tels plaisirs.' },
    { k: 'perso', t: 'rosencrantz' },
    { k: 'ligne', t: 'Ainsi ferons-nous, mon seigneur.' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Douce Gertrude, laissez-nous aussi ; car nous avons, sans nous découvrir, mandé Hamlet ici, afin qu’il y puisse, comme par hasard, se trouver en face d’Ophélia. Son père et moi, espions sans reproche, nous nous placerons de manière que, voyant sans être vus, nous puissions juger avec certitude de leur rencontre, et conclure d’après lui-même, selon qu’il se sera comporté, si c’est le renversement de son amour, ou non, qui le fait ainsi souffrir.' },
    { k: 'perso', t: 'la reine' },
    { k: 'ligne', t: 'Je vais vous obéir. Et quant à vous, Ophélia, je souhaite que vos rares beautés soient l’heureuse cause de l’égarement de Hamlet ; car je pourrai ainsi espérer que vos vertus, au grand honneur de tous deux, le remettront dans la bonne voie.' },
    { k: 'perso', t: 'ophélia' },
    { k: 'ligne', t: 'Madame, je souhaite que cela se puisse.' },
    { k: 'perso', t: 'polonius' },
    { k: 'ligne', t: 'Ophélia, promenez-vous ici… Gracieux maître, s’il vous plaît, nous irons nous placer. (À Ophélia.) Lisez dans ce livre ; cette apparence d’une telle occupation pourra colorer votre solitude… Nous sommes souvent blâmables en ceci… la chose n’est que trop démontrée… avec le visage de la dévotion et une démarche pieuse, nous faisons le diable lui-même blanc et doux comme sucre, de la tête aux pieds.' },
    { k: 'ligne', t: 'le roi' },
    { k: 'didascalie', t: ', (à part)' },
    { k: 'ligne', t: '. — Oh ! cela est trop vrai ! De quelle cuisante lanière ce langage fouette ma conscience ! La joue de la prostituée, savamment plâtrée d’une fausse beauté, n’est pas plus laide sous la matière dont elle s’aide, que ne l’est mon action sous mes paroles peintes et repeintes ! Ô pesant fardeau !' },
    { k: 'perso', t: 'polonius' },
    { k: 'ligne', t: 'Je l’entends venir, retirons-nous, mon seigneur. (Le roi et Polonius sortent.) (Hamlet entre).' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Être ou n’être pas, voilà la question… Qu’y a-t-il de plus noble pour l’âme ? supporter les coups de fronde et les flèches de la fortune outrageuse ? ou s’armer en guerre contre un océan de misères et, de haute lutte, y couper court ?… Mourir… dormir… plus rien… et dire que, par un sommeil, nous mettons fin aux serrements de cœur et à ces mille attaques naturelles qui sont l’héritage de la chair ! C’est un dénoûment qu’on doit souhaiter avec ferveur. Mourir… dormir… dormir ! rêver peut-être ? Ah ! là est l’écueil : car dans ce sommeil de la mort, ce qui peut nous venir de rêves, quand nous nous sommes soustraits à tout ce tumulte humain, cela doit nous arrêter. Voilà la réflexion qui nous vaut cette calamité d’une si longue vie ! Car qui supporterait les flagellations et les humiliations du présent, l’injustice de l’oppresseur, l’affront de l’homme orgueilleux, les angoisses de l’amour méprisé, les délais de la justice, l’insolence du pouvoir, et les violences que le mérite patient subit de la main des indignes ? — quand il pourrait lui-même se donner son congé avec un simple poignard ! — Qui voudrait porter ce fardeau, geindre et suer sous une vie accablante, n’était que la crainte de quelque chose après la mort, la contrée non découverte dont la frontière n’est repassée par aucun voyageur, embarrasse la volonté et nous fait supporter les maux que nous avons, plutôt que de fuir vers ceux que nous ne connaissons pas ? Ainsi la conscience fait de nous autant de lâches ; ainsi la couleur native de la résolution est toute blêmie par le pâle reflet de la pensée, et telle ou telle entreprise d’un grand élan et d’une grande portée, à cet aspect, se détourne de son cours et manque à mériter le nom d’action… Doucement, maintenant ! Voici la belle Ophélia. Nymphe, dans tes oraisons, puissent tous mes péchés être rappelés !' },
    { k: 'perso', t: 'ophélia' },
    { k: 'ligne', t: 'Mon bon seigneur, comment se porte Votre Honneur depuis tant de jours ?' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Je vous remercie humblement. Bien, bien, bien.' },
    { k: 'perso', t: 'ophélia' },
    { k: 'ligne', t: 'Mon seigneur, j’ai de vous des souvenirs que, depuis longtemps, il me tarde de vous rendre ; je vous prie, recevez-les maintenant.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Non, ce n’est pas moi ; je ne vous ai jamais rien donné.' },
    { k: 'perso', t: 'ophélia' },
    { k: 'ligne', t: 'Mon honoré seigneur, vous savez bien que si ; et même avec ces dons allaient des paroles faites d’une si suave haleine qu’elles rendaient les choses plus précieuses ; leur parfum est perdu, reprenez-les ; car pour une âme noble, le plus riche bienfait devient pauvre lorsque le bienfaiteur se montre malveillant. Les voici, mon seigneur.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Ah ! ah ! êtes-vous honnête ?' },
    { k: 'perso', t: 'ophélia' },
    { k: 'ligne', t: 'Mon seigneur ?' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Êtes-vous belle ?' },
    { k: 'perso', t: 'ophélia' },
    { k: 'ligne', t: 'Que veut dire Votre Seigneurie ?' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Que si vous êtes honnête et belle, il faut bien prendre garde que votre beauté n’ait aucun commerce avec votre honnêteté.' },
    { k: 'perso', t: 'ophélia' },
    { k: 'ligne', t: 'Mais la beauté, mon seigneur, peut-elle être en meilleure compagnie qu’avec l’honnêteté ?' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Oui, vraiment ; car le pouvoir de la beauté aura transformé l’honnêteté, de ce qu’elle est, en une sale entremetteuse plus tôt que la force de l’honnêteté n’aura transfiguré la beauté à son image. C’était, il y a quelque temps, un paradoxe, mais le temps présent le prouve. Je vous ai aimée jadis.' },
    { k: 'perso', t: 'ophélia' },
    { k: 'ligne', t: 'En vérité, mon seigneur, vous me l’avez fait croire.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Vous n’auriez pas dû me croire ; car la vertu a beau greffer notre vieille souche, nous nous sentirons toujours de notre origine. Je ne vous aimais pas.' },
    { k: 'perso', t: 'ophélia' },
    { k: 'ligne', t: 'Je n’en ai été que plus déçue.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Va-t’en dans un cloître. Pourquoi voudrais-tu te faire mère et nourrice de pécheurs ? Je suis moi-même passablement honnête, et pourtant je pourrais m’accuser de choses telles qu’il vaudrait mieux que ma mère ne m’eût pas mis au monde ; je suis très-orgueilleux, vindicatif, ambitieux ; j’ai en cortège autour de moi plus de péchés que je n’ai de pensées pour les loger, d’imagination pour leur donner une forme, ou de temps pour les commettre. Qu’est-ce que des gens comme moi ont à faire de traînasser entre la terre et le ciel ? Nous sommes tous de fieffés coquins, ne crois aucun de nous. Va-t’en droit ton chemin jusqu’à un cloître. Où est votre père ?' },
    { k: 'perso', t: 'ophélia' },
    { k: 'ligne', t: 'À la maison, mon seigneur.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Qu’on ferme la porte sur lui, afin qu’il ne puisse pas jouer le rôle d’un sot ailleurs qu’en sa propre maison. Adieu !' },
    { k: 'perso', t: 'ophélia' },
    { k: 'ligne', t: 'Oh ! secourez-le, cieux cléments !' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Si tu te maries, je te donnerai pour dot cette malédiction : sois aussi chaste que la glace, aussi pure que la neige, tu n’échapperas pas à la calomnie. Va-t’en dans un cloître ; adieu ! Ou si tu veux à toute force te marier, épouse un sot ; car les hommes sages savent bien quels monstres vous faites d’eux. Au cloître, allons, et au plus vite ! Adieu.' },
    { k: 'perso', t: 'ophélia' },
    { k: 'ligne', t: 'Ô puissances célestes, guérissez-le !' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'J’ai aussi entendu parler de vos peintures, bien à ma suffisance. Dieu vous a donné un visage, et vous vous en faites vous-mêmes un autre. Vous dansez, vous trottez, vous chuchotez, vous débaptisez les créatures de Dieu, et vous mettez votre frivolité sur le compte de votre ignorance. Allez, je ne veux plus de cela ; c’est cela qui m’a rendu fou. Je vous le dis, nous ne ferons plus de mariage ; ceux qui sont mariés déjà vivront ainsi, tous, excepté un ; les autres resteront comme ils sont. Au cloître ! Allez.' },
    { k: 'perso', t: 'ophélia' },
    { k: 'ligne', t: 'Oh ! quel noble esprit est là en ruines ! Courtisan, soldat, savant, le regard, la langue, l’épée ! L’attente et la fleur de ce beau royaume, le miroir de la mode et le moule des bonnes formes, le seul observé de tous les observateurs, tout à fait, tout à fait à bas ! Et moi, de toutes les femmes la plus accablée et la plus misérable, moi qui ai sucé le miel de ses vœux mélodieux, maintenant je vois cette noble et tout à fait souveraine raison, telle que les plus douces cloches quand elles se fêlent, rendre des sons faux et durs ! cette forme incomparable et ces traits de jeunesse épanouie flétris par de tels transports ! Oh ! le malheur est sur moi ! Avoir vu ce que j’ai vu et voir ce que je vois !' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'L’amour ? non, ses affections ne suivent pas cette route ; et ce qu’il disait, quoique manquant un peu de suite, ne ressemblait pas à de la folie. Il y a dans son âme quelque chose sur quoi sa mélancolie s’est établie à couver, et je soupçonne fort que l’éclosion et le produit seront quelque danger. Pour le prévenir, je viens, par une résolution vive, de régler tout ainsi : il partira en hâte pour l’Angleterre, et ira réclamer nos tributs négligés. Peut-être les mers, la différence des pays et la variété des objets, pourront-elles chasser ce je ne sais quoi qui est l’idée fixe de son cœur et où se heurte sans cesse son cerveau qui le jette ainsi hors de l’usage de lui-même. Qu’en pensez-vous ?' },
    { k: 'perso', t: 'polonius' },
    { k: 'ligne', t: 'Cela fera bon effet ; mais néanmoins je crois que l’origine et le commencement de son chagrin proviennent d’un amour maltraité. — Eh bien ! Ophélia, vous n’avez pas besoin de nous dire ce que le seigneur Hamlet a dit ; nous avons tout entendu. — Mon seigneur, agissez comme il vous plaît ; mais, si vous le trouvez bon, faites qu’après la représentation, la reine sa mère, toute seule avec lui, le presse de dévoiler son chagrin. Qu’elle le traite rondement ; et moi, si tel est votre bon plaisir, je me placerai dans le vent de toute leur conversation. Si elle ne le pénètre pas, envoyez-le en Angleterre, ou confinez-le dans le lieu que votre sagesse croira le meilleur.' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'C’est ce que nous ferons ; la folie d’un homme de haut rang ne peut rester sans surveillance.' },
    { k: 'scene', t: 'SCÈNE II' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Dites ce discours, je vous prie, comme je l’ai prononcé devant vous, en le laissant légèrement courir sur la langue ; mais si vous le déclamez à pleine bouche, comme font beaucoup de nos acteurs, j’aurais tout aussi bien pour agréable que mes vers fussent dits par le crieur de la ville. N’allez pas non plus trop scier l’air en long et en large avec votre main, de cette façon ; mais usez de tout sobrement, car dans le torrent même et la tempête et, pour ainsi dire, le tourbillon de votre passion, vous devez prendre sur vous et garder une tempérance qui puisse lui donner une douceur coulante. Oh ! cela me choque dans l’âme d’entendre un robuste gaillard, grossi d’une perruque, déchiqueter une passion, la mettre en lambeaux, en vrais haillons, pour fendre les oreilles du parterre, qui, le plus souvent, n’est à la hauteur que d’une absurde pantomime muette, ou de beaucoup de bruit. Je voudrais qu’un tel gaillard fût fouetté, pour charger ainsi les Termagants ; c’est se faire plus Hérode qu’Hérode lui-même. Je vous en prie, évitez cela.' },
    { k: 'perso', t: 'premier comédien' },
    { k: 'ligne', t: 'J’assure Votre Altesse…' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Ne soyez pas non plus trop apprivoisé, mais que votre propre discernement soit votre guide ; réglez l’action sur les paroles, et les paroles sur l’action, avec une attention particulière à n’outre-passer jamais la convenance de la nature ; car toute chose ainsi outrée s’écarte de la donnée même du théâtre, dont le but, dès le premier jour comme aujourd’hui, a été et est encore de présenter, pour ainsi parler, un miroir à la nature ; de montrer à la vertu ses propres traits, à l’infamie sa propre image, à chaque âge et à chaque incarnation du temps sa forme et son empreinte . Tout cela donc, si vous outrez ou si vous restez en deçà, quoique cela puisse faire rire l’ignorant, ne peut que faire peine à l’homme judicieux, dont la censure, fût-il seul, doit, dans votre opinion, avoir plus de poids qu’une pleine salle d’autres spectateurs. Oh ! il y a des comédiens que j’ai vus jouer, — et je les ai entendu vanter par d’autres personnes, et vanter grandement, pour ne pas dire grossement, — qui, n’ayant ni voix de chrétiens, ni démarche de chrétiens, ni de païens, ni d’hommes, se carraient et beuglaient au point de m’avoir donné à penser que quelques-uns des manouvriers de la nature avaient fait des hommes et ne les avaient pas bien faits, tant ces gens-là imitaient abominablement l’humanité !' },
    { k: 'perso', t: 'premier comédien' },
    { k: 'ligne', t: 'J’espère que nous avons passablement réformé cela chez nous.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Ah ! réformez-le tout à fait. Et que ceux qui jouent vos clowns n’en disent pas plus qu’on n’en a écrit dans leur rôle ; car il y en a qui se mettent à rire eux-mêmes, pour mettre en train de rire un certain nombre de spectateurs imbéciles. Cependant, à ce moment-là même, il y a peut-être quelque situation essentielle de la pièce qui exige l’attention. Cela est détestable, et montre la plus pitoyable prétention de la part du sot qui use de ce moyen. Allez, préparez-vous. (Les comédiens sortent.) — (Polonius, Rosencrantz et Guildenstern entrent.) Où en sommes-nous, mon seigneur ? Le roi veut-il entendre ce chef-d’œuvre ?' },
    { k: 'perso', t: 'polonius' },
    { k: 'ligne', t: 'Oui, et la reine aussi, et cela tout de suite.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Dites aux acteurs de faire hâte. (Polonius sort.) Voulez-vous tous deux aller aussi les presser ?' },
    { k: 'perso', t: 'tous deux' },
    { k: 'ligne', t: 'Oui, mon seigneur.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Qu’est-ce ? Ah ! Horatio !' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Me voici, mon doux seigneur, à votre service.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Horatio, tu es de tout point l’homme le plus juste que jamais ma pratique du monde m’ait fait rencontrer.' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Oh ! mon cher seigneur !' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Non, ne crois pas que je flatte ; car quel avantage puis-je espérer de toi qui n’as d’autre revenu que ton bon courage, pour te nourrir et t’habiller ? Pourquoi le pauvre serait-il flatté ? Non ! Que la langue doucereuse aille lécher la pompe stupide ! que les charnières moelleuses du genou se courbent là où le profit récompense la servilité… M’entends-tu bien ? depuis que mon âme tendre a été maîtresse de son choix et a pu distinguer parmi les hommes, elle t’a pour elle-même marqué du sceau de son élection ; car tu as été, en souffrant tout, comme un homme qui ne souffre rien, un homme qui, des rebuffades de la fortune à ses faveurs, a tout pris avec des remercîments égaux ; et bénis sont ceux-là dont le sang et le jugement ont été si bien combinés, qu’ils ne sont pas des pipeaux faits pour les doigts de la fortune et prêts à chanter par le trou qui lui plaît ! Donnez-moi l’homme qui n’est point l’esclave de la passion, et je le porterai dans le fond de mon cœur, oui, dans le cœur de mon cœur, comme je fais de toi… Mais en voilà un peu trop à ce sujet. On joue ce soir une pièce devant le roi, une des scènes se rapproche fort des circonstances que je t’ai racontées sur la mort de mon père. Je te prie, quand tu verras cet acte en train, aussitôt, avec la plus intime pénétration de ton âme, observe mon oncle. Si son crime caché ne se débusque pas de lui-même, à une certaine tirade, c’est un esprit infernal que nous avons vu, et mes imaginations sont aussi noires que l’enclume de Vulcain. Surveille-le attentivement. Quant à moi, je riverai mes yeux sur son visage, et ensuite, nous réunirons nos deux jugements pour prononcer sur ce qu’il aura laissé voir.' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Bien, mon seigneur. S’il nous dérobe rien, pendant que la pièce sera jouée, et s’il échappe aux recherches, je prends ce vol-là à mon compte.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Ils viennent pour la pièce ; il faut que je flâne ; trouvez une place.' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Comment se porte notre cousin Hamlet ?' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'À merveille, sur ma foi ! vivant des reliefs du caméléon, je mange de l’air, et je m’engraisse de promesses. Vous ne pourriez pas mettre vos chapons à ce régime.' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Je n’ai rien à voir dans cette réponse, Hamlet ; je ne suis pour rien dans ces paroles.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Ni moi non plus, désormais. (À Polonius.) Mon seigneur, vous avez joué la comédie autrefois à l’Université, dites-vous ?' },
    { k: 'perso', t: 'polonius' },
    { k: 'ligne', t: 'Oui, mon seigneur, je l’ai jouée, et je passais pour bon acteur.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Et qu’avez-vous joué ?' },
    { k: 'perso', t: 'polonius' },
    { k: 'ligne', t: 'J’ai joué Jules César. Je fus tué au Capitole ; Brutus me tua.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Il joua un rôle de brute, en tuant en pareil lieu un veau d’une si capitale importance. Les comédiens sont-ils prêts ?' },
    { k: 'perso', t: 'rosencrantz' },
    { k: 'ligne', t: 'Oui, mon seigneur, ils n’attendent que votre permission.' },
    { k: 'perso', t: 'la reine' },
    { k: 'ligne', t: 'Venez ici, mon cher Hamlet, asseyez-vous près de moi.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Non, ma bonne mère, voici un aimant qui a plus de force d’attraction.' },
    { k: 'ligne', t: 'polonius' },
    { k: 'ligne', t: ', au roi. — Oh ! oh ! remarquez-vous ceci ?' },
    { k: 'ligne', t: 'hamlet' },
    { k: 'ligne', t: ', s’asseyant aux pieds d’Ophélia. — Madame, me coucherai-je entre vos genoux ?' },
    { k: 'perso', t: 'ophélia' },
    { k: 'ligne', t: 'Non, mon seigneur.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Je veux dire la tête sur vos genoux.' },
    { k: 'perso', t: 'ophélia' },
    { k: 'ligne', t: 'Oui, mon seigneur.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Pensez-vous donc que j’aie eu dans l’esprit un propos de manant ?' },
    { k: 'perso', t: 'ophélia' },
    { k: 'ligne', t: 'Je ne pense rien, mon seigneur.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Ce n’est pas une vilaine pensée que celle de s’étendre parmi des jambes de jeunes filles.' },
    { k: 'perso', t: 'ophélia' },
    { k: 'ligne', t: 'Comment, mon seigneur ?' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Rien.' },
    { k: 'perso', t: 'ophélia' },
    { k: 'ligne', t: 'Vous êtes gai, mon seigneur.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Qui, moi ?' },
    { k: 'perso', t: 'ophélia' },
    { k: 'ligne', t: 'Oui, mon seigneur.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Oh ! je ne suis que votre bouffon. Qu’est-ce que l’homme peut faire de mieux que de s’égayer ? car, voyez comme ma mère a l’air joyeux… et il n’y a pas deux heures que mon père est mort.' },
    { k: 'perso', t: 'ophélia' },
    { k: 'ligne', t: 'Mais non, mon seigneur, il y a deux mois.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Si longtemps ? eh bien, que le diable porte le noir ! Pour moi, je veux avoir un assortiment de martre zibeline . Oh, ciel ! mort depuis deux mois et pas encore oublié ? Alors il y a de l’espoir pour que la mémoire d’un grand homme survive à sa vie la moitié d’une année ; mais, par Notre-Dame, il faut alors qu’il bâtisse des églises ; autrement, il aura à souffrir du mal de non-souvenance, avec le pauvre dada de bois, dont l’épitaphe est connue :' },
    { k: 'ligne', t: '« Car oh ! car oh ! le dada de bois,' },
    { k: 'ligne', t: '« Le dada de bois est oublié ! »' },
    { k: 'perso', t: 'ophélia' },
    { k: 'ligne', t: 'Que veut dire cela, mon seigneur ?' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Ma foi ! c’est l’embûche de la méchanceté ; cela veut dire : crime.' },
    { k: 'perso', t: 'ophélia' },
    { k: 'ligne', t: 'Sans doute cette pantomime indique le sujet de la pièce.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Nous allons le savoir de ce garçon-là. Les comédiens ne peuvent garder un secret, ils nous diront tout.' },
    { k: 'perso', t: 'ophélia' },
    { k: 'ligne', t: 'Nous dira-t-il ce que signifiait cette pantomime ?' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Oui, et toute autre pantomime que vous voudrez lui mimer. N’ayez pas honte, vous, de faire le spectacle, et lui, il n’aura pas honte de vous faire le commentaire.' },
    { k: 'perso', t: 'ophélia' },
    { k: 'ligne', t: 'Vous êtes un vaurien, vous êtes un vaurien. Je veux écouter la pièce.' },
    { k: 'perso', t: 'le prologue' },
    { k: 'ligne', t: 'Pour nous et pour notre tragédie, nous agenouillant ici devant votre clémence, nous implorons de vous audience et patience .' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Est-ce là un prologue, ou la devise d’une bague ?' },
    { k: 'perso', t: 'ophélia' },
    { k: 'ligne', t: 'C’est bref, mon seigneur.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Comme l’amour d’une femme.' },
    { k: 'perso', t: 'le roi de la comédie' },
    { k: 'ligne', t: 'Trente fois le chariot de Phébus a fait le tour entier du bassin salé de Neptune et du sol arrondi de Tellus, et trente fois douze lunes, de leur splendeur empruntée, ont marqué autour du monde douze fois trente étapes du temps, depuis que l’amour a uni nos cœurs, et l’hymen nos mains, par la réciprocité des liens les plus sacrés.' },
    { k: 'ligne', t: 'hamlet' },
    { k: 'ligne', t: '(à part). — Voilà l’absinthe ! voilà l’absinthe !' },
    { k: 'ligne', t: 'hamlet' },
    { k: 'ligne', t: ', à Ophélia. — Maintenant, si elle manquait à son serment…' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Madame, comment vous plaît cette pièce ?' },
    { k: 'perso', t: 'la reine' },
    { k: 'ligne', t: 'La reine fait trop de protestations, ce me semble.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Oh ! mais elle tiendra sa parole.' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Connaissez-vous le sujet de la pièce ? N’y a-t-il rien qui puisse blesser ?' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Non, non ils ne font que rire ; ils empoisonnent pour rire ; il n’y a rien au monde de blessant.' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Comment appelez-vous la pièce ?' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'La Souricière. Et pourquoi cela, direz-vous ? Par métaphore. Cette pièce est la représentation d’un meurtre commis à Vienne. Le duc s’appelle Gonzague, et sa femme Baptista. Vous verrez tout à l’heure. C’est un chef-d’œuvre de scélératesse ; mais qu’importe ? Votre Majesté, et nous, qui avons la conscience libre, cela ne nous touche en rien. Que la haridelle écorchée rue, si le bât la blesse : notre garrot n’est pas entamé. (Lucianus entre.) Celui-là est un certain Lucianus, neveu du roi.' },
    { k: 'perso', t: 'ophélia' },
    { k: 'ligne', t: 'Vous êtes d’aussi bon secours que le Chœur, mon seigneur.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Je pourrais dire le dialogue entre vous et votre amant, si je voyais jouer les marionnettes.' },
    { k: 'perso', t: 'ophélia' },
    { k: 'ligne', t: 'Vous êtes piquant, mon seigneur, vous êtes piquant.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Il ne vous en coûterait qu’un soupir, et la pointe serait émoussée.' },
    { k: 'perso', t: 'ophélia' },
    { k: 'ligne', t: 'De mieux en mieux, mais de pis en pis.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Oui, comme vous vous méprenez quand vous prenez vos maris ! Commence donc, assassin ! Cesse tes maudites grimaces, et commence. Allons ! Le corbeau croassant hurle pour avoir sa vengeance !' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Il l’empoisonne dans le jardin pour s’emparer de ses possessions. — Son nom est Gonzague. L’histoire existe, écrite en italien, style de premier choix. Vous verrez tout à l’heure comment l’assassin acquiert l’amour de la femme de Gonzague.' },
    { k: 'perso', t: 'ophélia' },
    { k: 'ligne', t: 'Le roi se lève !' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Quoi ! effrayé par un feu follet ?' },
    { k: 'perso', t: 'la reine' },
    { k: 'ligne', t: 'Qu’avez-vous, mon seigneur ?' },
    { k: 'perso', t: 'polonius' },
    { k: 'ligne', t: 'Laissez-là la pièce !' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Donnez-moi de la lumière ! Sortons.' },
    { k: 'perso', t: 'polonius' },
    { k: 'ligne', t: 'Des lumières ! des lumières ! des lumières !' },
    { k: 'ligne', t: 'Ne croyez-vous pas, monsieur, qu’un coup de théâtre comme celui-ci, avec accompagnement d’une forêt de plumes sur la tête, et deux roses de Provins sur des souliers tailladés , pourrait, si la fortune, par la suite, me traitait de Turc à More, me faire recevoir compagnon dans une meute de comédiens ?' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'À demi-part.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'À part entière, vous dis-je !' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Vous auriez pu mettre la rime .' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Oh ! mon cher Horatio ! à présent je tiendrais mille livres sterling sur la parole du fantôme. As-tu remarqué ?' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Très-bien, mon seigneur.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Quand il a été question de l’empoisonnement…' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Je l’ai très-bien remarqué !' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Ah ! ah ! — Allons, un peu de musique ! les flageolets !' },
    { k: 'ligne', t: 'Allons ! un peu de musique.' },
    { k: 'perso', t: 'guildenstern' },
    { k: 'ligne', t: 'Non bon seigneur, accordez-moi la grâce de vous dire un mot.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Toute une histoire, monsieur.' },
    { k: 'perso', t: 'guildenstern' },
    { k: 'ligne', t: 'Le roi, monsieur…' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Ah ! oui, monsieur. Quelles nouvelles de lui ?' },
    { k: 'perso', t: 'guildenstern' },
    { k: 'ligne', t: 'Il est dans son appartement, singulièrement indisposé.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Par la boisson, monsieur ?' },
    { k: 'perso', t: 'guildenstern' },
    { k: 'ligne', t: 'Non, mon seigneur, par la colère.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Votre sagesse se serait montrée mieux en fonds, en instruisant de ceci le médecin ; car, quant à moi, me charger de lui porter des purgatifs, ce serait peut-être le plonger encore plus avant dans le cholérique.' },
    { k: 'perso', t: 'guildenstern' },
    { k: 'ligne', t: 'Mon bon seigneur, mettez quelque règle à vos discours, et ne faites pas ces bonds sauvages hors de mon sujet.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Je suis apprivoisé, monsieur ; parlez.' },
    { k: 'perso', t: 'guildenstern' },
    { k: 'ligne', t: 'La reine votre mère, dans une très-grande affliction d’esprit, m’a envoyé vers vous.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Vous êtes le bienvenu.' },
    { k: 'perso', t: 'guildenstern' },
    { k: 'ligne', t: 'Non, mon seigneur, cette courtoisie n’est pas de race franche. S’il vous plaît de me faire une saine réponse, j’exécuterai les ordres de votre mère ; sinon, votre pardon et mon retour mettront fin à mon office.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Monsieur, je ne puis…' },
    { k: 'perso', t: 'guildenstern' },
    { k: 'ligne', t: 'Quoi, mon seigneur ?' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: '… Vous faire une saine réponse ; mon esprit est malade. Mais, monsieur, ma réponse, telle que je puis la faire, est bien à votre service, ou plutôt, comme vous dites, à celui de ma mère. Ainsi, sans plus de paroles, venons au fait : ma mère, dites-vous… ?' },
    { k: 'perso', t: 'rosencrantz' },
    { k: 'ligne', t: 'Voici ce qu’elle dit : votre conduite l’a frappée de surprise et de stupéfaction.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Ô fils prodigieux, qui peut ainsi étonner sa mère ! Mais la stupéfaction de cette mère n’a-t-elle pas quelque suite qui lui coure sur les talons ? Instruisez-moi.' },
    { k: 'perso', t: 'rosencrantz' },
    { k: 'ligne', t: 'Elle désire causer avec vous dans son cabinet, avant que vous alliez vous coucher.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Nous obéirons, fût-elle dix fois notre mère. Avez-vous quelque autre affaire à traiter avec nous ?' },
    { k: 'perso', t: 'rosencrantz' },
    { k: 'ligne', t: 'Mon seigneur, il fut un temps où vous m’aimiez.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Et je vous aime encore, par la pilleuse que voici et la voleuse que voilà !' },
    { k: 'perso', t: 'rosencrantz' },
    { k: 'ligne', t: 'Mon bon seigneur, quelle est la cause de votre trouble ? C’est assurément fermer la porte à votre propre délivrance que de refuser vos chagrins à votre ami.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Monsieur, ce qui me manque, c’est de l’avancement.' },
    { k: 'perso', t: 'rosencrantz' },
    { k: 'ligne', t: 'Comment cela se peut-il, lorsque vous avez la voix du roi lui-même, en gage de votre succession à la couronne du Danemark ?' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Oui ; mais « pendant que l’herbe pousse… ; » le proverbe lui-même s’est un peu moisi. (Des comédiens et des joueurs de flageolets entrent.) Ah ! les joueurs de flageolets ! Voyons-en un. (À Guildenstern.) Me retirer avec vous ! Pourquoi tourner autour de moi, et flairer ma piste comme si vous vouliez me pousser dans un piège ?' },
    { k: 'perso', t: 'guildenstern' },
    { k: 'ligne', t: 'Ah ! mon seigneur, si mes devoirs envers le roi me rendent trop hardi, c’est aussi mon amour pour vous qui me rend importun.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Je n’entends pas bien cela. Voulez-vous jouer de cette flûte ?' },
    { k: 'perso', t: 'guildenstern' },
    { k: 'ligne', t: 'Mon seigneur, je ne puis.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Je vous prie.' },
    { k: 'perso', t: 'guildenstern' },
    { k: 'ligne', t: 'Croyez-moi ; je ne puis.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Je vous en conjure.' },
    { k: 'perso', t: 'guildenstern' },
    { k: 'ligne', t: 'Je n’en connais pas une seule touche, mon seigneur.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Cela est aussi aisé que de mentir. Gouvernez ces prises d’air avec les doigts et le pouce, animez l’instrument du souffle de votre bouche, et il se mettra à discourir en très-éloquente musique. Voyez-vous ? Voici les soupapes.' },
    { k: 'perso', t: 'guildenstern' },
    { k: 'ligne', t: 'Mais je ne saurais les faire obéir à l’expression d’aucune harmonie. Je n’ai pas le talent requis.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Eh bien ! voyez maintenant quelle indigne chose vous faites de moi ! Vous voudriez jouer de moi ; vous voudriez avoir l’air de connaître mes soupapes ; vous voudriez me tirer de vive force l’âme de mon secret ; vous voudriez me faire résonner, depuis ma note la plus basse jusqu’au haut de ma gamme. Il y a beaucoup de musique, il y a une voix excellente dans ce petit tuyau d’orgue : et pourtant vous ne pouvez le faire parler. Par la sang-bleu ! pensez-vous qu’il soit plus aisé de jouer de moi que d’une flûte ? Prenez-moi pour tel instrument que vous voudrez ; vous pouvez bien tourmenter mes touches, vous ne pouvez pas jouer de moi. (Polonius entre.) Dieu vous bénisse, monsieur !' },
    { k: 'perso', t: 'polonius' },
    { k: 'ligne', t: 'Mon seigneur, la reine voudrait vous parler, et à l’heure même.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Voyez-vous ce nuage, qui a presque la forme d’un chameau ?' },
    { k: 'perso', t: 'polonius' },
    { k: 'ligne', t: 'Par la sainte messe, il ressemble à un chameau, en vérité !' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Je crois qu’il ressemble à une belette.' },
    { k: 'perso', t: 'polonius' },
    { k: 'ligne', t: 'Il a comme un dos de belette.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Ou de baleine ?' },
    { k: 'perso', t: 'polonius' },
    { k: 'ligne', t: 'Oui, tout à fait de baleine.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Ainsi, j’irai donc trouver ma mère tout à l’heure… L’arc est à bout de corde ; ils me tirent à me rendre fou… J’irai tout à l’heure.' },
    { k: 'perso', t: 'polonius' },
    { k: 'ligne', t: 'Je le lui dirai.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Tout à l’heure est aisé à dire. Laissez-moi, mes amis. (Rosencrantz, Guildenstern, Horatio, etc., sortent.) Voici justement l’heure de la nuit, cette heure qui ensorcelle, l’heure où les cimetières bâillent et où l’enfer même souffle sur ce monde la contagion. Maintenant, je pourrais boire du sang chaud et faire des actions si amères que le jour frémirait de les regarder… Doucement ! chez ma mère, maintenant ? Ô mon cœur ! ne perds pas ta nature ; que jamais l’âme de Néron ne pénètre dans cette ferme poitrine ; soyons cruel, mais non dénaturé : je lui parlerai de poignards, mais je n’en mettrai point en usage. Ma langue et mon âme, soyez hypocrites en ceci, et de quelque façon que mes discours puissent frapper sur elle, — quant à les sceller des sceaux qui font agir, ô mon âme ! n’y consens jamais !' },
    { k: 'scene', t: 'SCÈNE III' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Il m’est déplaisant ; et, d’ailleurs, il n’y a point de sûreté pour nous à laisser errer sa folie. Préparez-vous donc ; je vais expédier sur-le-champ votre commission, et il partira pour l’Angleterre avec vous. Les intérêts de notre empire ne peuvent endurer ces hasards dangereux, et croissant d’heure en heure, qui naissent de ses accès.' },
    { k: 'perso', t: 'guildenstern' },
    { k: 'ligne', t: 'Nous allons nous préparer. Elle est très-sainte et religieuse la crainte qui s’éveille pour maintenir saufs tant et tant de corps qui vivent et se nourrissent de Votre Majesté.' },
    { k: 'perso', t: 'rosencrantz' },
    { k: 'ligne', t: 'La vie isolée et privée est sujette à ce devoir d’employer la force et l’armure entière de l’esprit pour se préserver de toute atteinte ; mais bien plus encore cette âme au salut de laquelle se rattachent et se fient les vies de beaucoup d’autres. Le décès d’une majesté n’est pas une mort unique ; mais, comme un gouffre, elle entraîne avec elle tout ce qui est près d’elle. C’est une roue énorme fixée au sommet de la plus haute montagne ; dans ses vastes rayons sont enchâssées et engagées dix mille menues pièces ; lorsqu’elle tombe, chaque petit accessoire, conséquence chétive, la suit dans sa bruyante ruine. Jamais ne vont seuls les soupirs du roi, mais toujours avec un gémissement public.' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Équipez-vous, je vous prie, pour ce pressant voyage ; car nous voulons mettre des entraves à cette crainte qui maintenant marche d’un pied trop libre.' },
    { k: 'perso', t: 'rosencrantz et guildenstern' },
    { k: 'ligne', t: 'Nous allons nous hâter.' },
    { k: 'perso', t: 'polonius' },
    { k: 'ligne', t: 'Mon seigneur, il se rend dans le cabinet de sa mère ; je me placerai derrière la tapisserie pour entendre la conversation. Je garantis qu’elle va le réprimander sans cérémonie ; mais, comme vous l’avez dit, et cela était très-sagement dit, il est à propos que quelque autre auditoire qu’une mère (puisque la nature rend les mères partiales) soit là pour constater leurs discours à l’occasion. Adieu, mon souverain, j’irai vous trouver avant que vous vous mettiez au lit, et vous dire ce que j’aurai su.' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Merci, mon cher seigneur. (Polonius sort.) Oh ! mon crime est sauvage ; son odeur impure va jusqu’au ciel. Il porte avec lui la première, la plus ancienne des malédictions ; le meurtre d’un frère !… Prier, je ne le puis, malgré le penchant qui m’y porte aussi vivement que la volonté ; ma faute plus forte triomphe de ma forte intention, et, comme un homme astreint à une double tâche, je demeure en suspens, ne sachant par où commencer, et je néglige l’une et l’autre. Eh quoi ? quand même cette main maudite serait plus épaisse du sang d’un frère que de sa propre chair, n’y a-t-il pas assez de pluie dans les cieux cléments pour la rendre aussi blanche que la neige ? À quoi sert la miséricorde, si ce n’est à tenir tête à la face du péché ? et qu’y a-t-il dans la prière, sinon cette double force de nous retenir avant que nous en venions à tomber, ou de nous faire pardonner quand nous sommes à bas ? Je lèverai donc les yeux ; ma faute est passée… Mais hélas ! quelle forme de prière peut servir ma cause ?… Pardonne-moi mon infâme meurtre. Cela ne se peut, puisque je suis encore en possession de ces résultats pour lesquels j’ai commis le meurtre… ma couronne, mon ambition propre, et ma reine. Peut-on être pardonné et garder ce qui fait l’offense ? Dans le train corrompu de ce monde, la main dorée du crime peut écarter la justice, et souvent on a vu les profits criminels employés eux-mêmes à se racheter de la loi ; mais il n’en est pas ainsi là-haut. Là, point de subterfuges. Là est exposée l’action, dans toute la vérité de sa nature, et nous sommes contraints de comparaître nous-mêmes, devant le front découvert de nos fautes et comme à portée de leurs dents, et de rendre témoignage !… Quoi donc alors ? Que me reste-t-il ? Essayer ce que peut la repentance ? Et que ne peut-elle pas ? Que peut-elle cependant, quand on ne peut se repentir ? Oh ! l’état misérable ! ô conscience aussi noire que la mort ! ô âme engluée, qui, te débattant pour te délivrer, n’es que plus engagée ! Secourez-moi, ô anges ! faites effort ! Pliez, genoux roides, et toi, cœur aux fibres d’acier, sois tendre comme les nerfs de l’enfant nouveau-né ! Alors tout pourra aller bien.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Maintenant je puis le faire, fort à propos ; maintenant il est en prières ; et maintenant, je vais le faire… et ainsi il va au ciel, et moi, suis-je ainsi vengé ? Ceci veut être examiné. Un scélérat tue mon père, et pour cela, moi, son fils unique, j’envoie ce même scélérat droit au ciel ! Eh ! mais ce serait salaire et profit, et non vengeance. Il a surpris mon père brutalement, plein de pain , quand tous ses péchés étaient largement épanouis et frais comme le mois de mai… Et comment ses comptes se balancent, qui le sait, hormis le ciel ? Mais, du point de vue où nous sommes et dans notre ordre de pensées, la charge est lourde pour lui. Serai-je donc vengé en surprenant celui-ci au moment où il purifie son âme, lorsqu’il est prêt et accommodé pour le voyage ? Non. Halte-là, mon épée, et médite une plus horrible atteinte. Quand il sera ivre, endormi, ou dans sa rage, ou dans les plaisirs incestueux de son lit ; jouant ou jurant, ou en train de quelque action qui n’ait aucun parfum de salut ; alors, abats-le, de façon que ses talons ruent vers le ciel et que son âme soit aussi damnée et aussi noire que l’enfer où elle va. — Ma mère attend. — Ce cordial, vois-tu, ne fait que prolonger tes jours incurables.' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Mes paroles s’envolent, mes pensées demeurent ici-bas. Les paroles sans les pensées ne vont jamais au ciel.' },
    { k: 'scene', t: 'SCÈNE IV' },
    { k: 'perso', t: 'polonius' },
    { k: 'ligne', t: 'Il va venir tout de suite. N’oubliez pas de le réprimander sans cérémonie. Dites-lui que ses écarts se sont donné trop large carrière pour être supportés, et que Votre Grâce a eu à se dresser comme abri entre lui et une grande chaleur de colère. Je rentre en silence, ici même ; mais, je vous en prie, menez-le rondement.' },
    { k: 'perso', t: 'la reine' },
    { k: 'ligne', t: 'Je vous le garantis, ne craignez rien de ma part. Retirez-vous, je l’entends venir.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Eh bien ! ma mère, de quoi s’agit-il ?' },
    { k: 'perso', t: 'la reine' },
    { k: 'ligne', t: 'Hamlet, tu as beaucoup offensé ton père.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Ma mère, vous avez beaucoup offensé mon père.' },
    { k: 'perso', t: 'la reine' },
    { k: 'ligne', t: 'Allons, allons, vous me répondez d’une langue oiseuse.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Allez, allez, vous m’interrogez d’une langue méchante.' },
    { k: 'perso', t: 'la reine' },
    { k: 'ligne', t: 'Comment ! Qu’est-ce donc, Hamlet ?' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'De quoi s’agit-il donc ?' },
    { k: 'perso', t: 'la reine' },
    { k: 'ligne', t: 'Avez-vous oublié qui je suis ?' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Non, par la sainte croix, non, vraiment ! Vous êtes la reine, la femme du frère de votre mari… et,… plût au ciel que cela ne fût pas !… vous êtes ma mère.' },
    { k: 'perso', t: 'la reine' },
    { k: 'ligne', t: 'Eh bien ! je vais vous adresser des gens qui sauront vous parler.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Allons, allons, asseyez-vous ; vous ne bougerez pas ; ne sortez pas que je ne vous aie présenté un miroir, où vous pourrez voir le plus intime fond de vous-même.' },
    { k: 'perso', t: 'la reine' },
    { k: 'ligne', t: 'Que veux-tu faire ? tu ne veux pas m’assassiner ? Au secours ! au secours ! Holà !' },
    { k: 'ligne', t: 'polonius' },
    { k: 'ligne', t: '(derrière la tapisserie). — Qu’y a-t-il ? Holà ! au secours !' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Qu’est-ce donc ? un rat ! (Il donne un coup d’épée à travers la tapisserie.) Mort ! un ducat qu’il est mort !' },
    { k: 'ligne', t: 'polonius' },
    { k: 'ligne', t: '(derrière la tapisserie). — Ah je suis assassiné !' },
    { k: 'perso', t: 'la reine' },
    { k: 'ligne', t: 'Malheur à moi ! Qu’as-tu fait ?' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Ma foi, je n’en sais rien. Est-ce le roi ?' },
    { k: 'perso', t: 'la reine' },
    { k: 'ligne', t: 'Ah ! quelle furieuse et sanglante action est ceci !' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Une action sanglante ?… presque aussi mauvaise, ma bonne mère, que de tuer un roi et d’épouser son frère.' },
    { k: 'perso', t: 'la reine' },
    { k: 'ligne', t: 'Que de tuer un roi ?' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Oui, madame, c’est le mot dont je me suis servi. (À Polonius.) Et toi, misérable, absurde, importun imbécile, adieu ! Je t’ai pris pour quelqu’un de meilleur que toi ; prends ton sort comme il est : tu t’aperçois qu’à faire trop l’empressé il y a quelque danger… Cessez de vous tordre ainsi les mains. Paix ! asseyez-vous, et attendez-vous à avoir le cœur tordu par moi, car c’est ce que je vais faire s’il n’est pas d’une matière impénétrable, si l’infernale habitude ne l’a pas bronzé de telle sorte qu’il soit à l’épreuve et fortifié contre tout sentiment.' },
    { k: 'perso', t: 'la reine' },
    { k: 'ligne', t: 'Qu’ai-je donc fait, pour que tu oses darder ta langue avec un bruit si rude contre moi ?' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Une action telle qu’elle souille la grâce et la rougeur de la pudeur ; qu’elle donne à la vertu le nom d’hypocrite ; qu’elle ôte la rose au front serein d’un innocent amour, et met là un ulcère ; qu’elle rend les vœux du mariage aussi faux que les serments d’un joueur ; oh ! une action telle, que, des formes et du corps du contrat, elle retire leur âme même, et fait de la douce religion une rapsodie de mots ! La face du ciel s’en est enflammée ; oui, en vérité, cette masse compacte et solide, avec un visage triste, comme à la menace du jugement dernier, est malade de penser à cet acte.' },
    { k: 'perso', t: 'la reine' },
    { k: 'ligne', t: 'Hélas ! quelle est cette action qui gronde si haut et qui tonne déjà pour s’annoncer ?' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Regardez ici, ce tableau d’abord, puis celui-ci, cette confrontation simulée de deux frères… Voyez quelle grâce résidait sur ce visage ; les bouches d’Apollon, le front de Jupiter lui-même, l’œil semblable à celui de Mars pour la menace et pour le commandement ; une stature semblable à celle du héraut Mercure, quand il vient d’abattre son vol sur une hauteur qui baise le bord du ciel ; un ensemble et une forme, en vérité, où chaque dieu semblait avoir mis son cachet, afin de donner au monde la certitude de voir un homme : c’était votre mari. Regardez maintenant ce qui suit : voici votre mari, pareil à l’épi corrompu par la nielle, qui dévora son frère florissant… Avez-vous des yeux ? avez-vous pu quitter les pâturages de cette belle montagne, pour aller vous engraisser dans ce marais ? Ah ! avez-vous des yeux ? vous ne pouvez appeler cela de l’amour : car, à votre âge, la fermentation du sang est domptée ; il est humble, il est au service de la raison. Et quelle raison voudrait passer de celui-ci à celui-là ? Assurément, vous avez la faculté de sentir ; sans quoi vous n’auriez pas celle de vous mouvoir ; mais, assurément, cette faculté de sentir est, chez vous, frappée d’apoplexie, car la folie elle-même ne se tromperait pas de la sorte, et jamais les sens n’ont été asservis à un tel transport, qu’il ne leur restât pas une certaine dose de discernement pour apercevoir une telle différence. Quel démon vous a ainsi jouée à ce jeu de colin-maillard ? Les yeux sans le toucher, le toucher sans la vue, les oreilles sans les mains ni les yeux, l’odorat sans rien autre, ou même ne fût-ce qu’une moitié infirme d’un seul de nos véritables sens, ne pourraient pas être hébétés à ce point… Ô honte ! où est ta rougeur ? Ô enfer révolté ! si tu peux mutiner ainsi la moelle des os d’une matrone, souffrons désormais que, pour la jeunesse brûlante, la vertu soit comme une cire et fonde à son propre feu ! Ne proclamez plus qu’il y a honte quand la tyrannique ardeur de l’âge donne l’assaut, puisque la glace elle-même est aussi active à brûler, et que la raison s’entremet à prostituer la volonté !' },
    { k: 'perso', t: 'la reine' },
    { k: 'ligne', t: 'Ô Hamlet ! n’en dis pas davantage. Tu tournes mes yeux vers le fond de mon âme, et j’y aperçois des places si noires et si pénétrées de noirceur, qu’elles n’en pourront jamais perdre la teinte.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Et cela pour vivre dans l’infecte moiteur d’un lit souillé, toute confite en joies dans la corruption, s’emmiellant les lèvres, et faisant l’amour sur un sale fumier !' },
    { k: 'perso', t: 'la reine' },
    { k: 'ligne', t: 'Oh ! ne m’en dis pas davantage ! Ces paroles sont comme des poignards qui entrent dans mes oreilles. Assez, mon doux Hamlet.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Un meurtrier et un scélérat ! un laquais qui n’est pas le vingtième de la dîme de ce que valait votre premier maître ! un roi de carnaval ! un coupe-bourse de l’empire et des lois, qui a pris sur une planche le précieux diadème, et l’a mis dans sa poche !' },
    { k: 'perso', t: 'la reine' },
    { k: 'ligne', t: 'Assez !' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Un roi de pièces et de morceaux !… (Le fantôme entre.) Sauvez-moi et couvrez-moi de vos ailes, célestes gardiens !… Que veut votre gracieuse apparition ?' },
    { k: 'perso', t: 'la reine' },
    { k: 'ligne', t: 'Hélas, il est fou !' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Ne venez-vous pas gourmander votre fils tardif, qui, faisant défaut à l’heure propice et à l’élan du cœur, laisse s’éloigner l’importante exécution de vos ordres révérés ? Ah ! parlez.' },
    { k: 'perso', t: 'le fantôme' },
    { k: 'ligne', t: 'N’oublie pas. Cette visite n’est faite que pour rafraîchir le souvenir presque effacé de ton dessein. Mais, regarde ! la stupeur s’est emparée de ta mère. Ah ! place-toi entre elle et son âme qui combat : c’est dans les plus faibles corps que l’imagination opère le plus fortement. Parle-lui, Hamlet.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Qu’avez-vous, madame ?' },
    { k: 'perso', t: 'la reine' },
    { k: 'ligne', t: 'Hélas ! qu’avez-vous vous-même, pour tendre ainsi vos regards dans le vide, et pour converser ainsi avec l’air incorporel ? Vos esprits vitaux se sont élancés dans vos yeux, et, de là, épient sauvagement, tandis que, pareils aux soldats endormis quand vient l’alarme, vos cheveux d’abord couchés, se soulèvent maintenant, comme si leur végétation prenait vie, et se tiennent debout. Ô mon doux fils, répands sur cette chaleur et ces flammes de ton transport la patience d’un sang plus froid. Que regardes-tu donc ?' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Lui, lui ! Regardez comme il brille d’un pâle éclat ! Une telle forme et une telle cause, réunies pour prêcher à des pierres, les rendraient sensibles… Ne me regarde pas, de peur que, par cette démarche pitoyable, tu n’altères la fermeté de mes actes : ce que j’ai à faire y perdrait peut-être sa vraie couleur ; ce seraient des larmes, peut-être, au lieu de sang.' },
    { k: 'perso', t: 'la reine' },
    { k: 'ligne', t: 'À qui dites-vous cela ?' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Ne voyez-vous rien ici ?' },
    { k: 'perso', t: 'La reine' },
    { k: 'ligne', t: 'Rien du tout : et cependant, tout ce qui est ici, je le vois.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Et n’avez-vous, non plus, rien entendu ?' },
    { k: 'perso', t: 'la reine' },
    { k: 'ligne', t: 'Non, rien que nos propres paroles.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Eh bien ! regardez là, regardez, comme il se retire, mon père, dans le costume qu’il avait durant sa vie ! Regardez, il s’en va, à ce moment même, vers le portail !' },
    { k: 'perso', t: 'la reine' },
    { k: 'ligne', t: 'C’est votre cerveau même qui se frappe de cette image ; le délire est très-adroit à ces créations sans corps.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Le délire ! mon pouls, comme le vôtre, bat tranquillement sa mesure et ne chante pas une moins saine musique. Ce n’est point la folie qui m’a fait parler : mettez-moi à l’épreuve, et je répéterai la chose mot pour mot, tandis que la folie ne ferait que s’en écarter par gambades. Mère, pour l’amour de votre salut ! ne mettez pas ce baume flatteur sur votre âme, ne croyez pas que ce soit, au lieu de votre faute, ma folie qui vous parle ; ce ne serait que cacher et masquer la place de l’ulcère, pendant que la corruption infecte, minant tout au dedans, travaille à empoisonner sans être vue. Confessez-vous au ciel, repentez-vous du passé, gardez-vous de l’avenir, et ne répandez pas l’engrais sur les herbes mauvaises, qui deviendraient plus fortes… Pardonnez-moi ces devoirs de ma vertu ; car telle est la douillette enflure de ce siècle poussif que la vertu même doit demander pardon au vice, oui, c’est elle qui doit se courber et supplier pour obtenir la permission de lui faire du bien.' },
    { k: 'perso', t: 'la reine' },
    { k: 'ligne', t: 'Ô Hamlet, tu as brisé mon cœur en deux.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Ah ! rejetez-en la pire partie, et vivez, d’autant plus pure, avec l’autre moitié. Bonne nuit, mais n’allez pas au lit de mon oncle ; faites-vous une vertu, si vous ne l’avez pas. L’habitude, ce monstre qui dévore toute raison à l’ordinaire démon, est pourtant un ange en ceci ; il nous donne aussi, pour la pratique des belles et bonnes actions un vêtement, une livrée, qui s’ajuste heureusement. Abstenez-vous ce soir, et cela prêtera une sorte de facilité à la prochaine abstinence ; la suivante sera plus facile encore, car l’usage peut presque changer l’empreinte de la nature, soumettre le démon, ou même le chasser, par une merveilleuse puissance. Encore une fois, bonne nuit, et quand vous désirerez d’être bénie, je viendrai vous demander votre bénédiction. Quant à ce même seigneur de tout à l’heure (montrant Polonius), je me repens ; mais il a plu ainsi aux cieux de me punir par lui, et lui par moi ; j’ai dû être leur fléau et leur ministre. Je me charge de lui, et je répondrai de la mort que je lui ai donnée. Ainsi, encore une fois, bonne nuit ; je dois être cruel, mais seulement pour être humain : le mal vient de commencer, et le pire reste encore à suivre.' },
    { k: 'perso', t: 'la reine' },
    { k: 'ligne', t: 'Que vais-je faire ?' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Rien, en aucune façon, de ce que je vous ai dit de faire. Non, laissez ce roi bouffi vous attirer encore au lit, vous pincer gaiement la joue, vous appeler sa petite souris ; laissez-le, pour une paire de baisers fumeux, ou pour quelques jeux de ces doigts damnés sur votre cou, vous amener à lui révéler toute cette affaire, comme quoi je ne suis pas réellement en démence, mais fou par artifice. Il serait bon que vous le lui fissiez connaître ; car quelle femme, à moins d’être une belle, chaste et sage reine, voudrait cacher à un tel crapaud, à une telle chauve-souris, à un tel matou, des secrets qui l’intéressent si chèrement ? qui voudrait en user ainsi ? Non, en dépit du bon sens et de la discrétion, allez, sur le toit de la maison, ôter la cheville qui fermait la cage ; laissez s’envoler les oiseaux ; et puis, comme le singe fameux, glissez-vous dans la cage pour en faire l’essai, et rompez-vous vous-même le col à terre .' },
    { k: 'perso', t: 'la reine' },
    { k: 'ligne', t: 'Sois assuré que, si les paroles sont faites de souffle et si le souffle est fait de vie, je n’ai pas de vie pour exhaler un souffle de ce que tu m’as dit.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Il faut que je parte pour l’Angleterre, vous le savez ?' },
    { k: 'perso', t: 'la reine' },
    { k: 'ligne', t: 'Hélas ! je l’avais oublié. Cela a été décidé ?' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Les lettres sont déjà scellées ! et mes deux camarades d’études, — à qui je me fierai comme je me fierai à des vipères armées de leurs crocs, — portent le mandat ; ils doivent me frayer le chemin, et me guider vers l’embuscade ! laissons faire, car là est l’amusement : faire sauter l’ingénieur par son propre pétard ! Ou la besogne sera bien dure, ou je creuserai à une toise au-dessous de leur mine, et je les lancerai dans la lune. Oh ! cela est bien doux, lorsque deux ruses se rencontrent juste en droite ligne ! — Cet homme va me mettre en train de faire mes paquets ; je vais traîner cette panse jusque dans la chambre voisine . Bonsoir, ma mère… Vraiment, ce conseiller est maintenant bien tranquille, bien discret et bien grave, lui qui fut, en sa vie, un drôle si niais et si babillard. Allons, monsieur, tâchons d’en finir avec vous. Bonsoir, ma mère.' },
    { k: 'acte', t: 'ACTE QUATRIÈME' },
    { k: 'scene', t: 'SCÈNE I' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Ces sanglots ont une cause ; ces profonds soulèvements de votre cœur, il faut les expliquer ; il est à propos que nous les comprenions. Où est votre fils ?' },
    { k: 'ligne', t: 'la reine' },
    { k: 'ligne', t: '(Ils s’en vont.)' },
    { k: 'ligne', t: ', à Rosencrantz et à Guildenstern. — Laissez-nous un moment.' },
    { k: 'ligne', t: 'Ah ! mon bon seigneur, qu’ai-je vu ce soir ?' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Quoi, Gertrude ! comment va Hamlet ?' },
    { k: 'perso', t: 'la reine' },
    { k: 'ligne', t: 'Fou, comme la mer et le vent, lorsqu’ils luttent ensemble à qui sera le plus puissant. Dans son accès effréné, entendant remuer quelque chose derrière la tapisserie, de sa rapière tirée il fouette l’air, il crie : « Un rat ! un rat ! » et dans ce saisissement de son cerveau, il tue le bon vieillard sans le voir.' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Ô lourd forfait ! Il nous en serait arrivé autant si nous avions été là. Sa liberté est pour tous pleine de menaces ; pour vous-même, pour nous, pour tout le monde. Hélas ! comment répondre à ce sanglant événement ? Il retombera sur nous, dont la prévoyance aurait dû tenir de court, en bride et loin de toute hantise, ce jeune homme en démence. Mais tel était notre amour que nous ne voulions pas comprendre ce qu’il était à propos de faire, et nous avons agi comme un homme affligé d’une honteuse maladie, et qui, pour éviter de la divulguer, la laisse se nourrir de la moelle même de sa vie. Où est-il allé ?' },
    { k: 'perso', t: 'la reine' },
    { k: 'ligne', t: 'Tirer à l’écart le corps qu’il a tué ; et sur ce corps sa folie même, comme un peu d’or dans un minerai de vils métaux, se montre pure. Il pleure de ce qu’il a fait.' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Ô Gertrude, venez ! Le soleil n’aura pas plutôt touché les montagnes, que nous le ferons embarquer. Quant à cette affreuse action, nous devons tous deux employer toute notre majesté et notre adresse à la couvrir et à l’excuser. — Holà ! Guildenstern (Rosencrantz et Guildenstern entrent.) Amis, allez tous deux, prenez avec vous quelque renfort ; Hamlet, dans son délire, a tué Polonius, et l’a traîné hors du cabinet de sa mère. Allez, cherchez-le ; parlez-lui comme il faut ; et portez le corps dans la chapelle : je vous prie, faites diligence. (Rosencrantz et Guildenstern sortent.) Venez, Gertrude ; nous convoquerons nos plus sages amis, et nous leur ferons connaître en même temps ce que nous comptons faire et ce qui est malheureusement déjà fait. Ainsi nous avons chance que la calomnie, — dont le murmure, parcourant la circonférence du monde, lance, aussi droit que le canon à son but, sa charge empoisonnée, — manque pourtant notre nom, et ne frappe que l’air insensible. Oh ! venez ; mon âme est pleine de discorde et d’effroi.' },
    { k: 'scene', t: 'SCÈNE II' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Déposé en lieu sûr…' },
    { k: 'ligne', t: 'rosencrantz et guildenstern' },
    { k: 'ligne', t: ', derrière la scène. — Hamlet ! seigneur Hamlet !' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Mais doucement ! Quel est ce bruit ? qui appelle Hamlet ? Oh ! ils viennent ici !' },
    { k: 'perso', t: 'rosencrantz' },
    { k: 'ligne', t: 'Qu’avez-vous fait du cadavre, monseigneur ?' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Confondu avec la poussière, dont il est parent.' },
    { k: 'perso', t: 'rosencrantz' },
    { k: 'ligne', t: 'Dites-nous où il est, pour que nous puissions le tirer de là et le porter à la chapelle.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'N’allez pas croire cela.' },
    { k: 'perso', t: 'rosencrantz' },
    { k: 'ligne', t: 'Croire quoi ?' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Que je puisse garder votre secret et non le mien. Et puis, être importuné par une éponge ! Quelle réponse doit faire à cela le fils d’un roi ?' },
    { k: 'perso', t: 'rosencrantz' },
    { k: 'ligne', t: 'Me prenez-vous pour une éponge, mon seigneur ?' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Oui, monsieur, une éponge qui pompe la physionomie du roi, ses faveurs, son autorité. Mais de tels officiers rendent en définitive de grands services au roi ; il les tient en réserve, comme ferait un singe avec des noisettes, dans le coin de sa machoire — embouchés tout d’abord, pour être avalés au dernier moment ; — quand il a besoin de ce que vous avez recueilli, il n’a qu’à vous presser un peu, éponge, et vous redevenez sèche.' },
    { k: 'perso', t: 'rosencrantz' },
    { k: 'ligne', t: 'Je ne vous comprends pas, mon seigneur.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Cela me fait grand plaisir ; un méchant propos doit mourir dans une sotte oreille.' },
    { k: 'perso', t: 'rosencrantz' },
    { k: 'ligne', t: 'Mon seigneur, il faut nous dire où est le corps, et venir avec nous chez le roi.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Le corps est avec le roi, mais le roi n’est pas avec le corps. Le roi est une chose…' },
    { k: 'perso', t: 'guildenstern' },
    { k: 'ligne', t: 'Une chose, mon seigneur ?' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: '… de rien. Conduisez-moi vers lui. Cache-toi, renard ! et tous en chasse !' },
    { k: 'scene', t: 'SCÈNE III' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Je l’ai envoyé querir, et l’on cherche le corps. Combien il est dangereux que cet homme aille en liberté ! Il ne faut pas, cependant, lui appliquer la loi rigoureuse ; il est aimé de la multitude désordonnée, qui aime, non d’après son jugement, mais d’après ses yeux ; et là où il en est ainsi, on pèse le fléau qui frappe l’offenseur, jamais on ne pèse l’offense. Pour que tout se passe doucement et sans bruit, il faut que cet éloignement soudain paraisse une décision réfléchie. Les maux qui sont devenus désespérés veulent des remèdes désespérés pour être guéris ou ne le sont pas du tout. (Rosencrantz entre.) Eh bien ! qu’est-il arrivé ?' },
    { k: 'perso', t: 'rosencrantz' },
    { k: 'ligne', t: 'Où le corps est-il déposé ? c’est ce que nous ne pouvons tirer de lui, mon seigneur.' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Mais lui, où est-il ?' },
    { k: 'perso', t: 'rosencrantz' },
    { k: 'ligne', t: 'À la porte, mon seigneur ; on le garde et l’on attend vos ordres.' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Amenez-le devant nous.' },
    { k: 'perso', t: 'rosencrantz' },
    { k: 'ligne', t: 'Holà ! Guildenstern, faites entrer mon seigneur.' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Voyons, Hamlet, où est Polonius ?' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'À souper.' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'À souper ? où donc ?' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Non pas dans un endroit où il mange, mais dans un endroit où il est mangé ; il y a un certain congrès de vermine politique qui est en affaire avec lui en ce moment même. Votre ver est l’empereur qui préside seul à toute votre diète : nous engraissons toutes les autres créatures pour nous engraisser ; et nous nous engraissons nous-mêmes pour les asticots. Votre roi bien gras et votre mendiant bien maigre ne font qu’un service différent ; deux plats, mais pour la même table : c’est là la fin de tout.' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Hélas ! hélas !' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Un homme peut pêcher avec le ver qui a mangé d’un roi, et manger le poisson qui s’est nourri de ce ver.' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Que veux-tu dire par là ?' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Rien, mais seulement vous montrer comment un roi peut faire un voyage à travers les entrailles d’un mendiant.' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Où est Polonius ?' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Dans le ciel : envoyez-y voir. Si votre messager ne le trouve pas là, allez vous-même le chercher à l’autre endroit. Mais, en vérité, si vous ne le trouvez pas d’ici à un mois, vous le flairerez en montant l’escalier de la galerie.' },
    { k: 'ligne', t: 'le roi' },
    { k: 'ligne', t: ', à quelqu’un de sa suite. — Allez le chercher là.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Oh ! il attendra bien jusqu’à votre arrivée.' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Hamlet, pour ta propre sûreté, qui nous occupe aussi tendrement que nous afflige ce que tu as fait, cette action exige que tu partes d’ici avec la promptitude de l’éclair. Ainsi prépare-toi : la barque est prête, et le vent est favorable, tes compagnons t’attendent, et toutes choses sont disposées pour ton voyage en Angleterre.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'En Angleterre ?' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Oui, Hamlet.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'C’est bon.' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Tu dis vrai ; si tu connais nos projets.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Je vois un ange qui les voit. Mais allons, en Angleterre ! Adieu, mère chérie.' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Et ton père qui t’aime, Hamlet ?' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Ma mère ! père et mère sont mari et femme ; mari et femme ne sont qu’une même chair ; et ainsi, ma mère… Allons, en Angleterre !' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Suivez-le pas à pas ; attirez-le en toute hâte à bord. Ne différez pas ; je veux qu’il soit hors d’ici ce soir. Allez, car tout ce qui touche, d’ailleurs, à cette affaire est fait et scellé ; je vous prie, hâtez-vous. (Rosencrantz et Guildenstern sortent.) Et toi, Angleterre, si tu tiens mon amitié pour quelque chose (comme ma grande puissance peut te rendre ce point sensible, puisque ta cicatrice se montre encore vive et rouge là où a passé l’épée danoise, et puisque le libre mouvement de ta crainte nous rend hommage), tu n’accueilleras pas froidement notre message souverain, qui implique nettement, par lettres instantes à cet effet, la mort immédiate de Hamlet ; entends-moi, Angleterre ! car il fait rage comme la fièvre dans mon sang, et il faut que tu me guérisses. Jusqu’à ce que je sache que c’en est fait, quoi qu’il m’arrive, mes joies ne recommenceront pas.' },
    { k: 'scene', t: 'SCÈNE IV' },
    { k: 'perso', t: 'fortinbras' },
    { k: 'ligne', t: 'Allez, capitaine, saluer de ma part le roi de Danemark ; dites-lui, qu’avec son agrément, Fortinbras réclame le passage promis pour une expédition à travers son royaume. Vous savez où est le rendez-vous. Si Sa Majesté nous veut quelque chose, nous irons en personne lui rendre nos devoirs ; faites-le-lui savoir.' },
    { k: 'perso', t: 'le capitaine' },
    { k: 'ligne', t: 'Je le ferai, mon seigneur.' },
    { k: 'perso', t: 'fortinbras' },
    { k: 'ligne', t: 'Avancez doucement.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Mon bon monsieur, à qui sont ces forces ?' },
    { k: 'perso', t: 'le capitaine' },
    { k: 'ligne', t: 'Ce sont des Norvégiens, monsieur.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Quelle est leur destination, monsieur, je vous prie ?' },
    { k: 'perso', t: 'le capitaine' },
    { k: 'ligne', t: 'Ils marchent contre une partie de la Pologne ?' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Qui les commande, monsieur ?' },
    { k: 'perso', t: 'le capitaine' },
    { k: 'ligne', t: 'Le neveu du vieux roi de Norvége, Fortinbras.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Marchent-ils contre le gros de la Pologne, monsieur ; ou s’agit-il de quelque frontière ?' },
    { k: 'perso', t: 'le capitaine' },
    { k: 'ligne', t: 'À parler vrai, monsieur, et sans amplification, nous allons conquérir un petit morceau de terre qui n’a guère d’autre valeur que son nom. S’il en fallait payer cinq ducats, je dis cinq ! je ne voudrais pas l’affermer, et il ne rapportera pas à la Norvége, non plus qu’à la Pologne, un plus gros profit, quand même on le vendrait en toute propriété.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Eh bien ! alors les Polonais ne voudront jamais le défendre.' },
    { k: 'perso', t: 'le capitaine' },
    { k: 'ligne', t: 'Si fait, il y a déjà une garnison.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Deux mille âmes et vingt mille ducats ne suffiront pas à décider la question de ce fétu. Ceci est comme un abcès, amassé par trop de richesse et de paix, qui éclate au dedans et ne montre pas au dehors la cause qui fait mourir l’homme. Je vous remercie humblement, monsieur.' },
    { k: 'perso', t: 'le capitaine' },
    { k: 'ligne', t: 'Dieu vous soit en aide, monsieur !' },
    { k: 'perso', t: 'rosencrantz' },
    { k: 'ligne', t: 'Vous plaira-t-il d’avancer, mon seigneur ?' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Je vous aurai rejoints dans un instant. Allez un peu en avant. (Rosencrantz et Guildenstern sortent.) Comme toutes les circonstances témoignent contre moi et éperonnent ma molle vengeance !… Qu’est-ce qu’un homme pour qui le bien suprême et le seul débit de son temps ne seraient que de dormir et de manger ? un animal, et rien de plus. Certes, celui qui nous a créés, avec cette vaste intelligence qui regarde en avant et en arrière, ne nous a pas donné cette capacité et cette raison divine pour moisir en nous sans emploi. Maintenant donc, que ce soit par un bestial oubli, ou par quelque lâche scrupule de vouloir réfléchir trop précisément à l’issue… et dans ces réflexions-là, à les couper en quatre, il n’y a qu’un quart de sagesse et toujours trois quarts de couardise… je ne sais pourquoi je continue à vivre pour dire : « cela est à faire ; » tandis que j’ai motif, volonté, force et moyen de le faire. J’en ai gros comme la terre, d’exemples qui m’exhortent ! Témoin cette armée, d’une telle masse et d’un tel poids, conduite par un prince délicat et frêle, dont l’âme, enflée d’une ambition divine, fait une grimace de défi à l’invisible événement, et qui expose tout ce qui, en lui, est mortel et fragile, à tout ce que peuvent oser la fortune, la mort et le péril ; et cela pour une coquille d’œuf ! À le bien prendre, être grand, c’est ne s’émouvoir pas sans une grande cause, mais grandement aussi tirer une querelle d’un fétu, lorsque l’honneur est en jeu. Comment puis-je donc rester là, moi, qui ai un père assassiné, une mère déshonorée, tant d’excitants de ma raison et de mon sang ! et laisser tout cela dormir, tandis qu’à ma honte je vois la mort imminente de vingt mille hommes, qui, pour une fantaisie et une babiole de gloire, s’en vont à leur tombeau comme à un lit, combattant pour un coin de sol, où les joueurs trop nombreux ne pourront engager la partie, et qui n’est même pas une fosse et un espace suffisants pour cacher les morts ?… Oh ! désormais que mes pensées soient sanglantes, ou estimées à néant !' },
    { k: 'scene', t: 'SCÈNE V' },
    { k: 'perso', t: 'la reine' },
    { k: 'ligne', t: 'Je ne veux pas lui parler.' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Elle est pressante, en vérité ; elle est en délire : toutes ses façons vous feront certainement pitié.' },
    { k: 'perso', t: 'la reine' },
    { k: 'ligne', t: 'Que veut-elle ?' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Elle parle beaucoup de son père ; elle dit qu’elle sait qu’on joue de mauvais tours dans le monde ; elle sanglote et se frappe la poitrine ; elle piétine avec colère pour un fétu ; elle dit des choses équivoques, qui n’ont de sens qu’à moitié ; ses paroles ne sont rien ; et pourtant, l’informe usage qu’elle en fait pousse ceux qui les entendent à les assembler ; ils ne les perdent pas de vue et recousent les mots selon leurs propres pensées ; de là, comme ses clignements d’yeux, et ses hochements de tête, et ses gestes, leur viennent encore en aide, quelqu’un pourrait croire, en vérité, qu’elle a quelque pensée, sans rien de certain, mais d’une tournure très-fâcheuse.' },
    { k: 'perso', t: 'la reine' },
    { k: 'ligne', t: 'Il serait bon de lui parler ; car elle pourrait jeter de dangereuses conjectures dans les esprits qui nourrissent un mauvais vouloir. Qu’on la fasse entrer. (Horatio sort.) Pour mon âme malade, — telle est la vraie nature du péché ! — toute bagatelle semble le prologue de quelque grand mécompte ; tant nos fautes nous remplissent de malhabile défiance ! Elles se découvrent elles-mêmes, en craignant d’être découvertes.' },
    { k: 'perso', t: 'ophélia' },
    { k: 'ligne', t: 'Où est la belle reine de Danemark ?' },
    { k: 'perso', t: 'la reine' },
    { k: 'ligne', t: 'Eh bien ! Ophélia ?' },
    { k: 'ligne', t: 'ophélia' },
    { k: 'ligne', t: ', chantant. —' },
    { k: 'ligne', t: 'Comment pourrai-je distinguer d’un autre votre véritable ami ? À son chapeau orné de coquillages, et à son bâton, et à ses sandales .' },
    { k: 'perso', t: 'la reine' },
    { k: 'ligne', t: 'Hélas ! gentille dame, que signifie cette chanson ?' },
    { k: 'perso', t: 'ophélia' },
    { k: 'ligne', t: 'Que dites-vous ? Remarquez bien, je vous prie.' },
    { k: 'ligne', t: 'Il est mort et parti, madame, il est mort et parti : à sa tête est un tertre d’herbe verte ; à ses talons est une pierre.' },
    { k: 'ligne', t: 'Ah ! ah !' },
    { k: 'perso', t: 'la reine' },
    { k: 'ligne', t: 'Oui ; mais, Ophélia…' },
    { k: 'perso', t: 'ophélia' },
    { k: 'ligne', t: 'Je vous prie, remarquez bien.' },
    { k: 'ligne', t: 'Son linceul, blanc comme la neige des montagnes…' },
    { k: 'perso', t: 'la reine' },
    { k: 'ligne', t: 'Hélas voyez ceci, mon seigneur.' },
    { k: 'perso', t: 'ophélia' },
    { k: 'ligne', t: '… est tout semé de douces fleurs, qui, tout humides de pleurs, allèrent au tombeau, humides des ondées du sincère amour.' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Comment vous trouvez-vous, ma belle demoiselle ?' },
    { k: 'perso', t: 'ophélia' },
    { k: 'ligne', t: 'Bien. Dieu vous assiste ! Ils disent que la chouette était la fille d’un boulanger . Seigneur, nous savons ce que nous sommes, mais nous ne savons pas ce que nous pouvons être. Que Dieu soit à votre table !' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Elle songe à son père.' },
    { k: 'perso', t: 'ophelia' },
    { k: 'ligne', t: 'Je vous en prie, ne disons pas un mot de cela ; mais si l’on vous demande ce que cela signifie, dites ceci :' },
    { k: 'ligne', t: 'Bonjour ! c’est le jour de Saint-Valentin ; tous, ce matin, sont levés de bonne heure, et moi, jeune fille, je suis à votre fenêtre, pour être votre Valentine. Il se leva et mit ses habits, et ouvrit la porte de la chambre : il fit entrer la jeune fille, mais jeune fille elle ne sortit plus.' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Ma charmante Ophélia !' },
    { k: 'perso', t: 'ophélia' },
    { k: 'ligne', t: 'En vérité, sans vouloir jurer, je finirai cette chanson :' },
    { k: 'ligne', t: 'Par Gis et par sainte Charité ! hélas ! fi ! quelle honte ! Ainsi font les jeunes gens quand ils peuvent le faire. Ah ! Dieu ! qu’ils sont blâmables ! Avant de me chiffonner, dit-elle, vous m’aviez promis de m’épouser…' },
    { k: 'ligne', t: 'Et il répond :' },
    { k: 'ligne', t: 'Aussi l’aurais-je fait, par l’astre que voilà, si tu n’étais pas arrivée à mon lit.' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Depuis combien de temps est-elle ainsi ?' },
    { k: 'perso', t: 'ophélia' },
    { k: 'ligne', t: 'J’espère que tout ira bien. Il faut prendre patience… ; mais je ne puis m’empêcher de pleurer, en songeant qu’ils l’ont mis dans la froide terre. Mon frère saura cela ; et, sur ce, je vous remercie de vos bons avis… Allons, ma voiture. Bonsoir, mesdames ; bonsoir, mes chères dames ; bonsoir, bonsoir.' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Suivez-la de près ; donnez-lui bonne garde, je vous en prie. (Horatio sort.) Ah ! voilà bien le poison d’une profonde douleur, jaillissant tout entier de la mort de son père. Et maintenant regardez, ô Gertrude, Gertrude ! quand les chagrins arrivent, ils ne viennent pas un à un comme des éclaireurs, mais par bataillons. D’abord son père tué, puis votre fils parti — votre fils, très-violent auteur de son propre et juste exil — le peuple, fange troublée, épaisse, exhalant de pernicieuses pensées, et murmurant au sujet de la mort du bon Polonius ; car nous n’avons pas mûrement agi en le faisant enterrer en tapinois ; puis la pauvre Ophélia enlevée à elle-même et à cette noble raison sans laquelle nous ne sommes que des simulacres humains ou de vraies brutes ; enfin, et cela est aussi important que tout le reste, son frère, revenu secrètement de France, se repaît de ses cruelles surprises, s’enveloppe de nuages, et ne manque pas de mouches bourdonnantes qui infestent ses oreilles de discours empoisonnés sur la mort de son père ; et, dans ces discours, les exigences d’un sujet trop pauvre ne leur laisseront nul scrupule de nous accuser en personne, d’oreille en oreille. Ô ma chère Gertrude, tout ceci, comme un canon à mitraille, me frappe à bien des places et me donne à la fois trop de morts !' },
    { k: 'perso', t: 'la reine' },
    { k: 'ligne', t: 'Hélas quel bruit est ceci ?' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Holà ! où sont mes Suisses ? qu’ils gardent la porte… De quoi s’agit-il ?' },
    { k: 'perso', t: 'le gentilhomme' },
    { k: 'ligne', t: 'Sauvez-vous, mon seigneur. L’Océan, franchissant ses barrières, ne dévore pas les plages avec une plus impétueuse hâte que le jeune Laërtes, à la tête de la sédition, ne renverse vos officiers ! La cohue l’appelle son seigneur ; et, comme si le monde n’en était qu’à commencer aujourd’hui, l’antiquité est mise en oubli, la coutume est méconnue, elles par qui sont ratifiés et soutenus tous les titres. Ils crient : « Choisissons nous-mêmes ! Laërtes sera roi ! » Et les bonnets, et les mains, et les langues applaudissent jusqu’aux nues à ce cri : « Laërtes sera notre roi ! Laërtes roi ! »' },
    { k: 'perso', t: 'la reine' },
    { k: 'ligne', t: 'Avec quelle joie ils s’en vont aboyant sur cette fausse piste ! Ah ! vous êtes en défaut, mauvais chiens danois !' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Les portes sont brisées.' },
    { k: 'perso', t: 'laërtes' },
    { k: 'ligne', t: 'Où est ce roi ?… Messieurs, restez tous en dehors.' },
    { k: 'perso', t: 'le peuple' },
    { k: 'ligne', t: 'Non, entrons.' },
    { k: 'perso', t: 'laërtes' },
    { k: 'ligne', t: 'Je vous en prie, laissez-moi faire.' },
    { k: 'perso', t: 'le peuple' },
    { k: 'ligne', t: 'Oui, Oui !' },
    { k: 'perso', t: 'laërtes' },
    { k: 'ligne', t: 'Je vous remercie,… gardez la porte… Ô toi, roi infâme, rends-moi mon père !' },
    { k: 'perso', t: 'la reine' },
    { k: 'ligne', t: 'Calmez-vous, brave Laërtes.' },
    { k: 'perso', t: 'laërtes' },
    { k: 'ligne', t: 'Une seule goutte de mon sang, si elle est calme, me proclame bâtard, crie à mon père : « cocu ! » et brûle, ici même, du nom de fille de joie, le front chaste et immaculé de ma loyale mère.' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Quelle est la cause, Laërtes, qui fait prendre à ta rébellion ces airs gigantesques ?… Laissez-le aller, Gertrude ; ne craignez pas pour notre personne ; il y a une magie divine qui entoure les rois d’une telle haie, que la trahison peut à peine regarder à la dérobée ce qu’elle voudrait et met en action peu de sa volonté !… Dis-moi, Laërtes, pourquoi tu es à ce point enflammé… Laissez-le aller, Gertrude… Parle, ô homme !' },
    { k: 'perso', t: 'laërtes' },
    { k: 'ligne', t: 'Où est mon père ?' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Mort.' },
    { k: 'perso', t: 'la reine' },
    { k: 'ligne', t: 'Mais non par la faute du roi.' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Laissez-le questionner à sa suffisance.' },
    { k: 'perso', t: 'laërtes' },
    { k: 'ligne', t: 'Et comment s’est-il fait qu’il soit mort ? Je ne veux pas qu’on jongle avec moi. Aux enfers la fidélité ! et les serments au plus noir des diables ! au fond de l’abîme la conscience et le salut ! Je brave la damnation. Je m’en tiens à ce point : mettre en oubli ce monde et l’autre, et advienne que pourra ! Seulement, j’aurai pleine vengeance pour mon père.' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Qui pourra vous arrêter ?' },
    { k: 'perso', t: 'laërtes' },
    { k: 'ligne', t: 'Ma volonté, non celle de l’univers entier ; et pour ce qui est de mes ressources, je les ménagerai si bien qu’avec peu elles iront loin.' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Brave Laërtes, si vous désirez connaître la vérité certaine sur la mort de votre cher père, avez-vous écrit dans votre projet de vengeance que, d’un seul coup de rafle, vous emporterez à la fois ses amis et ses ennemis, les coupables et les innocents ?' },
    { k: 'perso', t: 'laërtes' },
    { k: 'ligne', t: 'Non, ses ennemis seuls.' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Alors, voulez-vous les connaître ?' },
    { k: 'perso', t: 'laërtes' },
    { k: 'ligne', t: 'Quant à ses bons amis, voici comment je leur ouvrirai mes bras, tout larges ; et semblable au tendre pélican qui donne sa vie, je les nourrirai de mon sang.' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Eh bien ! maintenant vous parlez comme un bon fils et un loyal gentilhomme. Que je ne suis pas coupable de la mort de votre père, et que j’en ai le plus sensible chagrin, c’est ce qui pénétrera dans votre propre raison, aussi droit que le jour pénètre dans vos yeux.' },
    { k: 'ligne', t: 'le peuple' },
    { k: 'ligne', t: ', derrière le théâtre. — Laissez-la entrer.' },
    { k: 'perso', t: 'laërtes' },
    { k: 'ligne', t: 'Qu’est-ce donc ? quel est ce bruit ? (Ophélia entre, bizarrement ajustée avec des fleurs et des brins de paille.) Ô chaleur, dessèche mon cerveau ! ô larmes sept fois salées, consumez en mes yeux tout don de sentir et d’agir ! Par le ciel, ta folie sera si bien payée à son poids que ce sera notre plateau qui fera tourner le fléau de la balance ! Ô rose de mai, chère fille, bonne sœur, douce Ophélia ! Ô ciel, est-il possible que la raison d’une jeune fille soit aussi mortelle que la vie d’un vieillard ? La nature s’affine dans l’amour ; et, ainsi affinée, elle envoie, en témoignage d’elle-même, vers l’objet tant aimé, quelque chose de sa précieuse essence.' },
    { k: 'perso', t: 'ophelia' },
    { k: 'ligne', t: '(Elle chante.)' },
    { k: 'ligne', t: 'Ils l’ont porté le visage nu dans la bière, tra, la, la, la ! tra, la, la, la ! et sur son tombeau vinrent pleuvoir bien des larmes…' },
    { k: 'ligne', t: 'Bonsoir, mon tourtereau.' },
    { k: 'perso', t: 'laërtes' },
    { k: 'ligne', t: 'Tu aurais ta raison, et tu m’exciterais à la vengeance, que cela ne pourrait pas m’émouvoir autant.' },
    { k: 'perso', t: 'ophelia' },
    { k: 'ligne', t: 'Il faut que vous chantiez :' },
    { k: 'ligne', t: 'À bas ! à bas jetez-le donc à bas !' },
    { k: 'ligne', t: 'Comme la ritournelle va bien là ! C’est ce traître d’intendant, qui avait ravi la fille de son maître.' },
    { k: 'perso', t: 'laërtes' },
    { k: 'ligne', t: 'Ces non-sens sont plus que du bon sens.' },
    { k: 'ligne', t: 'ophélia' },
    { k: 'ligne', t: ', à Laërtes. — Voilà du romarin ; c’est pour le souvenir. Je vous en prie, amour, souvenez-vous. Et voici des pensées ; c’est pour vous faire penser.' },
    { k: 'perso', t: 'laërtes' },
    { k: 'ligne', t: 'Il y a un enseignement dans sa folie : les pensées et le souvenir assemblés.' },
    { k: 'ligne', t: 'ophélia' },
    { k: 'ligne', t: '(À la reine.)' },
    { k: 'ligne', t: ', au roi. — Voilà du fenouil pour vous , et des ancolies. —' },
    { k: 'ligne', t: 'Voilà de la rue pour vous , et il' },
    { k: 'ligne', t: 'y en a encore pour moi ; nous pourrons, les dimanches, la nommer herbe de grâce ; vous pouvez porter votre bouquet de rue avec une différence. Voilà aussi une marguerite ; je vous donnerais bien des violettes, mais elles se fanèrent toutes quand mon père mourut … Ils disent qu’il a fait une bonne fin ;' },
    { k: 'ligne', t: 'Car ce cher bon Robin, il fait toute ma joie…' },
    { k: 'perso', t: 'laërtes' },
    { k: 'ligne', t: 'Mélancolie et abattement, désespoir, enfer même, tout en elle tourne en charme et en grâce.' },
    { k: 'perso', t: 'ophélia' },
    { k: 'ligne', t: '(Elle chante.)' },
    { k: 'ligne', t: 'Et ne reviendra-t-il pas ? et ne reviendra-t-il pas ? Non, non, il est mort ! Va à ton lit de mort ! Il ne reviendra jamais. Sa barbe était blanche comme la neige, sa tête toute blonde comme le fin ; il est parti, il est parti, et nous gémissons en vain. Dieu fasse miséricorde à son âme !…' },
    { k: 'ligne', t: 'Et à toutes les âmes chrétiennes !… Je prie Dieu… Dieu soit avec vous !' },
    { k: 'perso', t: 'laërtes' },
    { k: 'ligne', t: 'Voyez-vous ceci, ô Dieu !' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Laërtes, je dois converser avec votre douleur, ou vous me refuseriez un droit qui m’appartient. Retirons-nous seulement. Faites choix de qui vous voudrez parmi vos plus sages amis ; ils entendront et jugeront entre vous et moi. Si, par action directe ou collatérale, ils nous trouvent compromis, nous vous livrons notre royaume, notre couronne, notre vie et tout ce que nous disons nôtre, pour vous faire satisfaction. Mais, s’il n’en est rien, résignez-vous à nous prêter votre patience, et nous travaillerons en commun avec votre âme pour lui donner les contentements qui lui sont dus.' },
    { k: 'perso', t: 'laërtes' },
    { k: 'ligne', t: 'Qu’il en soit donc ainsi. Le genre de sa mort, son obscur enterrement, point de trophée, ni d’épée, ni d’écusson sur son cercueil, point de rite nobiliaire, ni d’appareil officiel, tout cela me crie, comme une voix qui se ferait entendre de ciel en terre, que je dois en demander compte.' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Ainsi ferez-vous ; et là où est le crime, que la grande hache y tombe ! Je vous prie, venez avec moi.' },
    { k: 'scene', t: 'SCÈNE VI' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Qui sont les gens qui veulent me parler ?' },
    { k: 'perso', t: 'un serviteur' },
    { k: 'ligne', t: 'Des matelots, monsieur ; ils disent qu’ils ont des lettres pour vous.' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Fais-les entrer. (Le serviteur sort.) J’ignore de quelle partie du monde je puis recevoir un message, si ce n’est du seigneur Hamlet.' },
    { k: 'perso', t: 'premier matelot' },
    { k: 'ligne', t: 'Dieu vous bénisse, monsieur !' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Qu’il te bénisse aussi !' },
    { k: 'perso', t: 'premier matelot' },
    { k: 'ligne', t: 'Ainsi fera-t-il, monsieur, si tel est son bon plaisir. Voici une lettre pour vous, monsieur, — elle vient de l’ambassadeur qui s’était embarqué pour l’Angleterre, — si votre nom est Horatio, comme je me le suis laissé dire.' },
    { k: 'ligne', t: 'horatio' },
    { k: 'ligne', t: ', lisant. — « Horatio, quand tu auras lu ceci, donne à ces gens-là quelque moyen d’arriver jusqu’au roi ; ils ont des lettres pour lui. Nous n’avions pas vieilli de deux jours en mer, lorsqu’un pirate, très-bien équipé en guerre, nous a donné la chasse. Nous trouvant trop faibles de voiles, nous avons eu recours à un courage forcé. Les grappins jetés, j’ai monté à l’abordage. Au même instant ils se sont dégagés de notre vaisseau ; ainsi je suis demeuré seul leur prisonnier. Ils en ont usé avec moi en brigands pleins de miséricorde ; mais ils savaient bien ce qu’ils faisaient : je suis en passe de leur donner du retour. Que le roi ait les lettres que je lui envoie ; et toi, viens me rejoindre avec autant de hâte que si tu fuyais la mort. J’ai à te dire à l’oreille des paroles qui te rendront muet ; encore seront-elles bien trop légères pour le calibre' },
    { k: 'ligne', t: 'de cette affaire. Ces braves gens t’amèneront là où je suis. Rosencrantz et Guildenstern continuent leur route vers l’Angleterre ; j’ai beaucoup à te dire sur eux. Adieu.' },
    { k: 'ligne', t: '« Celui que tu sais à toi,' },
    { k: 'ligne', t: 'Venez, je vous donnerai le moyen de remettre vos lettres : faites au plus vite, afin que vous puissiez me conduire vers celui qui vous en avait chargés.' },
    { k: 'scene', t: 'SCÈNE VII' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Maintenant votre conscience doit sceller mon acquittement, et vous devez me donner place dans votre cœur comme à un ami ; car vous avez entendu, — et d’une oreille qui sait ce qu’elle entend, — comment celui qui a tué votre noble père en voulait à ma vie.' },
    { k: 'perso', t: 'laërtes' },
    { k: 'ligne', t: 'Oui, cela apparaît bien. Mais, dites-moi pourquoi vous n’avez pas fait procéder contre des actes si criminels et d’une si mortelle nature, comme votre sûreté, votre grandeur, votre sagesse, tout enfin vous y poussait puissamment.' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Oh ! pour deux raisons spéciales qui vous sembleront peut-être avoir bien peu de nerf, et qui cependant sont fortes pour moi. La reine, sa mère, ne vit presque que par ses yeux ; et, quant à moi (qu’elle soit mon salut ou mon fléau, n’importe !), elle est si intimement unie à ma vie et à mon âme, que, comme l’étoile ne peut se mouvoir hors de sa sphère, moi, je ne vais que par elle. L’autre motif qui ne me permettrait pas de pousser jusqu’à une enquête publique, c’est le grand amour que la masse du peuple lui porte. Toutes ses fautes disparaîtraient plongées dans leur affection qui, semblable à cette source où le bois tourne à la pierre, changerait ses chaînes en faveurs ; de sorte que mes flèches, faites d’un bois trop léger pour un vent si fort, seraient revenues à mon arc au lieu d’aller à mon but.' },
    { k: 'perso', t: 'laërtes' },
    { k: 'ligne', t: 'Ainsi j’ai perdu un noble père ! ainsi ma sœur a été jetée dans un état désespéré ! elle, dont le mérite (s’il est permis à la louange de retourner en arrière), droit et ferme sur le plus haut faîte, mettait tout notre siècle au défi d’égaler ses perfections ! Mais ma vengeance viendra !' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Ne rompez point pour cela vos sommeils. Il ne faut pas nous croire faits d’une assez plate et molle matière pour souffrir que le danger vienne nous secouer par la barbe, et pour regarder cela comme un passe-temps. Vous en saurez bientôt davantage. J’aimais votre père, nous nous aimons nous-mêmes, et cela vous apprendra, j’espère, à concevoir que… (Un messager entre.) Mais qu’est-ce donc ? quelles nouvelles ?' },
    { k: 'perso', t: 'le messager' },
    { k: 'ligne', t: 'Des lettres, mon seigneur, de la part de Hamlet ; celle-ci pour Votre Majesté, celle-là pour la reine.' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'De Hamlet ? qui les a apportées ?' },
    { k: 'perso', t: 'le messager' },
    { k: 'ligne', t: 'Des matelots, à ce qu’on dit, mon seigneur ; je ne les ai pas vus : elles m’ont été remises par Claudio ; il les avait reçues de celui qui les avait apportées.' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Laërtes, vous allez les entendre. Laissez-nous.' },
    { k: 'ligne', t: '« Vous saurez que j’ai été débarqué nu en votre royaume. Demain je demanderai la permission d’être admis en votre royale présence, et alors, après avoir imploré votre pardon pour tout ceci, je vous raconterai les circonstances de mon si soudain et encore plus étrange retour.' },
    { k: 'ligne', t: 'Que signifie ceci ? Est-ce que tous les autres sont aussi de retour ? ou bien est-ce quelque tromperie, et n’y a-t-il rien de vrai ?' },
    { k: 'perso', t: 'laërtes' },
    { k: 'ligne', t: 'Reconnaissez-vous la main ?' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'C’est l’écriture de Hamlet. Nu ! et, dans ce post-scriptum, il ajoute : seul. Pouvez-vous me conseiller ?' },
    { k: 'perso', t: 'laërtes' },
    { k: 'ligne', t: 'Je m’y perds, mon seigneur ; mais laissez-le venir. Tout ce que mon cœur a de malade se réchauffe quand je pense que je vivrai assez pour lui dire à ses dents : voilà ce que tu as fait !' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'S’il en est ainsi, Laërtes… et comment cela pourrait-il être ainsi ?… mais comment cela serait-il autrement ?… voulez-vous vous laisser gouverner par moi ?' },
    { k: 'perso', t: 'laërtes' },
    { k: 'ligne', t: 'Oui, mon seigneur, pourvu que vous ne vouliez pas me tyranniser jusqu’à me faire faire la paix.' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Non. La paix avec toi-même seulement. S’il est vrai que Hamlet soit déjà revenu, et, rebuté de son voyage, s’il a dessein de ne point l’entreprendre à nouveau, je l’engagerai dans une aventure, maintenant mûrie dans ma pensée, et où il ne pourra si bien faire qu’il n’y succombe ; sa mort ne soulèvera aucun souffle de blâme, mais sa mère elle-même innocentera l’affaire et l’appellera un accident.' },
    { k: 'perso', t: 'laërtes' },
    { k: 'ligne', t: 'Mon seigneur, je me laisserai gouverner, et plus volontiers encore, si vous pouvez arranger vos plans de telle manière que j’en sois moi-même l’instrument.' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Cela tombe bien. On a beaucoup parlé de vous depuis votre voyage, et cela en présence de Hamlet, à cause d’un talent où vous brillez, dit-on ; l’ensemble de vos mérites n’a pas tiré de lui autant d’envie que celui-là seul ; et celui-là, pourtant, à mes yeux, est de l’ordre le moins élevé.' },
    { k: 'perso', t: 'laërtes' },
    { k: 'ligne', t: 'Quel mérite est-ce donc, mon seigneur ?' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Un simple ruban sur la toque de la jeunesse ; utile cependant, car la jeunesse n’est pas moins bienséante, avec la livrée légère et libre dont elle se revêt, que l’âge mûr sous son deuil et ses fourrures, convenables à la santé et à la gravité… Ici se trouvait, il y a deux mois, un gentilhomme de Normandie ; j’ai vu moi-même les Français, et j’ai servi contre eux ; ils montent bien à cheval ; mais ce galant cavalier va en ce genre jusqu’à la sorcellerie ; il prenait racine en selle et obtenait de son cheval des exercices aussi merveilleux que s’il eût fait corps et double créature avec ce brave animal. Vraiment, il surpassait de si loin toutes mes idées, que j’avais beau imaginer des passes et des voltiges, je demeurais au-dessous de ce qu’il faisait.' },
    { k: 'perso', t: 'laërtes' },
    { k: 'ligne', t: 'C’était un Normand ?' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Un Normand.' },
    { k: 'perso', t: 'laërtes' },
    { k: 'ligne', t: 'Sur ma vie, c’est Lamord !' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Lui-même.' },
    { k: 'perso', t: 'laërtes' },
    { k: 'ligne', t: 'Je le connais bien ; il est, en vérité, l’ornement et la perle de toute sa nation.' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Il a rendu témoignage de vous, et vous donnait rang de passé maître, pour votre science et votre pratique de l’escrime, et tout singulièrement pour votre façon de manier la rapière. Il s’écriait que ce serait un vrai spectacle à voir, si quelqu’un pouvait vous faire votre partie : il jurait que les escrimeurs de sa nation n’avaient ni botte, ni parade, ni coup d’œil, lorsque vous leur teniez tête. Un tel éloge dans sa bouche, monsieur, empoisonna Hamlet d’une telle jalousie qu’il ne faisait plus autre chose que de souhaiter et demander votre soudain retour, pour faire assaut avec vous. D’après cela donc…' },
    { k: 'perso', t: 'laërtes' },
    { k: 'ligne', t: 'Eh bien ! d’après cela, mon seigneur ?' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Laërtes, votre père vous était-il cher ? ou n’êtes-vous pour ainsi dire que le portrait d’un chagrin, un visage qui n’a point de cœur ?' },
    { k: 'perso', t: 'laërtes' },
    { k: 'ligne', t: 'Pourquoi me demandez-vous cela ?' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Ce n’est pas que je pense que vous n’ayez pas aimé votre père. Mais ce que je sais, c’est que le temps fait naître l’amour ; et ce que je vois, dans les épreuves où l’amour passe, c’est que le temps en modifie l’éclat et l’ardeur. Il y a, au centre même de la flamme de l’amour, une sorte de mèche ou de lumignon qui finit par l’étouffer. Rien ne reste fixe en la même excellence, car l’excellence arrive à la surabondance et meurt de son propre excès. Ce que nous voulons faire, nous devrions le faire quand nous le voulons ; car ce « nous le voulons » vient à changer et souffre autant de défaillances et de délais qu’il y a autour de nous de langues, et de mains, et d’accidents ; et ce n’est plus alors qu’un « nous devrions », semblable au soupir d’un mauvais sujet, et pernicieux parce qu’il soulage. Mais droit dans le vif de la plaie ! Hamlet revient ; que sauriez-vous entreprendre pour montrer, en fait plutôt que par des paroles, que vous êtes fils de votre père ?' },
    { k: 'perso', t: 'laërtes' },
    { k: 'ligne', t: 'Je lui couperais la gorge dans l’église même.' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Aucun lieu, à vrai dire, ne devrait être un sanctuaire pour le meurtre. La vengeance ne devrait pas avoir de bornes. Mais, brave Laërtes, voulez-vous faire ceci ? Tenez-vous enfermé dans votre chambre. Hamlet revenu apprendra que vous êtes aussi de retour ; nous mettrons en avant des gens qui vanteront votre talent et donneront un nouveau lustre à la réputation que ce Français vous a faite ; nous vous amènerons enfin l’un en face de l’autre, et il y aura des paris établis sur vos têtes. Lui qui est distrait, fort généreux, innocent de tout artifice, il n’examinera pas les fleurets. De sorte que vous pourrez sans peine, ou avec un peu de ruse, choisir une épée non émoussée, et, par un coup de secrète adresse, lui payer tout pour votre père.' },
    { k: 'perso', t: 'laërtes' },
    { k: 'ligne', t: 'C’est ce que je ferai ; et, dans ce dessein, je veux oindre mon épée. J’ai acheté d’un charlatan un onguent si meurtrier, que vous avez seulement à y plonger votre couteau, et s’il vient ensuite à tirer une goutte de sang, il n’est au monde cataplasme si rare, fût-il composé de tous les simples qui ont le plus de vertu sous les rayons de la lune, qui puisse sauver de la mort un être que vous auriez seulement égratigné. Ma pointe sera touchée de cette peste, afin que, si je pique légèrement, ce soit la mort.' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Pensons encore à ceci, pesons bien quels agencements de temps et de moyens peuvent convenir à notre plan. Si ceci échouait, si une exécution manquée devait laisser voir notre dessein, il vaudrait mieux ne l’avoir point essayé. Notre projet doit donc avoir une arrière-garde, un second qui tienne encore, si celui-ci se brise à l’épreuve. Doucement… voyons un peu… nous ferons un pari solennel sur le savoir-faire de chacun de vous… j’y suis… Lorsque, par votre assaut, vous serez échauffés et altérés (poussez les bottes plus violemment pour qu’il en soit ainsi), et lorsqu’il demandera à boire, je lui aurai préparé une coupe à cet effet ; et si, par hasard, il a échappé à votre fer empoisonné, qu’il la goûte seulement, nos efforts pourront s’en tenir là ! Mais arrêtez ; quel est ce bruit ? (La reine entre.) Qu’est-ce donc, ma chère reine ?' },
    { k: 'perso', t: 'la reine' },
    { k: 'ligne', t: 'Toujours, sur les talons d’un malheur, marche un autre malheur, tant ils se suivent de près !… Votre sœur est noyée, Laërtes.' },
    { k: 'perso', t: 'laěrtes' },
    { k: 'ligne', t: 'Noyée ! Oh ! où donc ?' },
    { k: 'perso', t: 'la reine' },
    { k: 'ligne', t: 'Il y a, au bord du ruisseau, un saule qui réfléchit son feuillage blanchâtre dans le miroir du courant ; elle était là, faisant de fantasques guirlandes de renoncules, d’orties, de marguerites, et de ces longues fleurs pourpres que nos bergers licencieux nomment d’un nom plus grossier, mais que nos chastes vierges appellent des doigts de morts. Et là, comme elle grimpait pour attacher aux rameaux pendants sa couronne d’herbes sauvages, une branche ennemie se rompit ; alors ses humbles trophées, et elle-même avec eux, tombèrent dans le ruisseau qui pleurait. Ses vêtements s’enflent et s’étalent ; telle qu’une fée des eaux, ils la soutiennent un moment à la surface ; pendant ce temps elle chantait des lambeaux de vieilles ballades, comme désintéressée de sa propre détresse, ou comme une créature née et douée pour cet élément. Mais cela ne pouvait durer longtemps ; si bien qu’enfin la pauvre malheureuse ! ses vêtements, lourds de l’eau qu’ils buvaient, l’ont entraînée de ses douces chansons à une fangeuse mort.' },
    { k: 'perso', t: 'laërtes' },
    { k: 'ligne', t: 'Hélas ! elle est donc noyée !' },
    { k: 'perso', t: 'la reine' },
    { k: 'ligne', t: 'Noyée ! noyée !' },
    { k: 'perso', t: 'laërtes' },
    { k: 'ligne', t: 'Tu n’as déjà que trop d’eau, pauvre Ophélia ; aussi je retiens mes larmes. Mais non ; c’est notre train courant, la nature conserve ses coutumes, la honte a beau dire ce qui lui plaît. Que ces larmes partent, et c’en est fait de la femme en moi … Adieu, mon seigneur ! Je me sens des paroles de flamme qui éclateraient volontiers, n’était que cette folie les noie.' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Suivons-le, Gertrude. Combien j’ai eu à faire pour calmer sa rage ! maintenant je crains que ceci ne lui donne un nouvel élan. Ainsi donc, suivons-le.' },
    { k: 'acte', t: 'ACTE CINQUIÈME' },
    { k: 'scene', t: 'SCÈNE I' },
    { k: 'perso', t: 'premier paysan' },
    { k: 'ligne', t: 'Doit-elle être enterrée en terre chrétienne, celle qui volontairement est allée chercher son salut ?' },
    { k: 'perso', t: 'second paysan' },
    { k: 'ligne', t: 'Je te dis que oui ; creuse donc sa fosse tout de suite. Le coroner a tenu séance sur elle et a conclu à la sépulture chrétienne.' },
    { k: 'perso', t: 'premier paysan' },
    { k: 'ligne', t: 'Comment cela se peut-il, à moins qu’elle ne se soit noyée en un cas de légitime défense ?' },
    { k: 'perso', t: 'second paysan' },
    { k: 'ligne', t: 'Eh bien ! c’est ce qu’on a reconnu.' },
    { k: 'perso', t: 'premier paysan' },
    { k: 'ligne', t: 'Non, cela doit être un cas de personnelle offense ; cela ne peut être autrement. Car voici où gît la question : si je me noie volontairement, cela constitue un acte ; or un acte se divise en trois branches, qui sont : agir, faire et accomplir. Ergo, elle s’est noyée volontairement.' },
    { k: 'perso', t: 'second paysan' },
    { k: 'ligne', t: 'Bien ! mais écoutez-moi, bonhomme de fossoyeur.' },
    { k: 'perso', t: 'premier paysan' },
    { k: 'ligne', t: 'Permettez. Ici passe l’eau ; bien. Là se tient l’homme ; bien. Si l’homme va à l’eau et se noie, — qu’il le veuille ou non, — c’est parce qu’il y va qu’il se noie ; remarquez bien ceci. Mais si l’eau vient à lui et le noie, il ne se noie point lui-même : ergo, celui qui n’est point coupable de sa propre mort n’a point abrégé sa propre vie .' },
    { k: 'perso', t: 'second paysan' },
    { k: 'ligne', t: 'Mais est-ce la loi ?' },
    { k: 'perso', t: 'premier paysan' },
    { k: 'ligne', t: 'Oui, pardieu ! c’est la loi, la loi touchant l’enquête du coroner.' },
    { k: 'perso', t: 'second paysan' },
    { k: 'ligne', t: 'Voulez-vous savoir la vérité là-dessus ? Si ce n’avait point été une demoiselle noble, elle aurait été enterrée en dehors de la terre sainte.' },
    { k: 'perso', t: 'premier paysan' },
    { k: 'ligne', t: 'Pour çà, c’est bien parlé ; et de plus c’est une pitié que les grands personnages, en ce monde, soient en passe de se noyer et de se pendre plus que leurs frères en Jésus-Christ. Allons, ma bêche ; il n’y a point de plus anciens gentilshommes que les jardiniers, les terrassiers et les fossoyeurs : ils continuent la profession d’Adam.' },
    { k: 'perso', t: 'second paysan' },
    { k: 'ligne', t: 'Était-il gentilhomme ?' },
    { k: 'perso', t: 'premier paysan' },
    { k: 'ligne', t: 'Il est le premier qui ait jamais porté de sable et de vair.' },
    { k: 'perso', t: 'second paysan' },
    { k: 'ligne', t: 'Bah ! il n’avait aucun blason.' },
    { k: 'perso', t: 'premier paysan' },
    { k: 'ligne', t: 'Quoi ? es-tu donc un païen ? comment entends-tu l’Écriture ? L’Écriture dit : « Adam cultiva ; » et comment aurait-il cultivé sans porter du sable et du vert ? Mais je te proposerai une autre question ; si tu ne me réponds point juste, confesse-toi…' },
    { k: 'perso', t: 'second paysan' },
    { k: 'ligne', t: 'Va !' },
    { k: 'perso', t: 'premier paysan' },
    { k: 'ligne', t: 'Quel est celui qui bâtit plus solidement que le maçon, le charpentier et l’ouvrier de marine ?' },
    { k: 'perso', t: 'second paysan' },
    { k: 'ligne', t: 'Le faiseur de potences ; car sa bâtisse survit à mille de ceux qui viennent s’y loger.' },
    { k: 'perso', t: 'premier paysan' },
    { k: 'ligne', t: 'Par ma foi, j’aime ta répartie : la potence fait bien là. Mais comment fait-elle bien ? Elle fait bien pour ceux qui font mal. Et toi, tu fais mal de dire qu’une potence est bâtie plus solidement qu’une église. Ergo, la potence ferait bien pour toi. Recommence, allons.' },
    { k: 'perso', t: 'second paysan' },
    { k: 'ligne', t: 'Qui est-ce qui bâtit plus solidement que le maçon, et l’ouvrier de marine, et le charpentier ?' },
    { k: 'perso', t: 'premier paysan' },
    { k: 'ligne', t: 'Oui, dis-moi cela et dételle ensuite.' },
    { k: 'perso', t: 'second paysan' },
    { k: 'ligne', t: 'Pardieu, oui, maintenant je peux le dire.' },
    { k: 'perso', t: 'premier paysan' },
    { k: 'ligne', t: 'Allons !' },
    { k: 'perso', t: 'second paysan' },
    { k: 'ligne', t: 'Par la sainte messe ! je ne puis point le dire.' },
    { k: 'perso', t: 'premier paysan' },
    { k: 'ligne', t: 'Ne te romps point la cervelle davantage à propos de cela, car ton fainéant d’âne ne corrigera point son allure pour avoir été battu ; et quand on te posera cette question une autre fois, réponds : le fossoyeur. Les maisons qu’il fait durent jusqu’au jugement dernier. Allons, va-t’en chez Yaughan, et apporte-moi un pot de liqueur.' },
    { k: 'ligne', t: 'Dans ma jeunesse, quand j’aimais, quand j’aimais, il me semblait que c’était très-doux, pour abréger… hop !… le temps. Quant à… holà !… mes convenances… hop !… il me semblait que rien ne m’allait plus .' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Est-ce que ce gaillard-là n’a aucun sentiment de son métier ? Il chante en creusant un tombeau !' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'L’habitude a engendré en lui une faculté d’insouciance.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'C’est cela même ; la main qui fait peu de service a le tact plus délicat.' },
    { k: 'ligne', t: 'Mais l’âge, à pas furtifs, est venu me déchirer de sa griffe et m’a fait échouer en terre comme si je n’avais jamais été.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Ce crâne avait une langue autrefois et pouvait chanter. Comme ce maraud le fait rouler par terre ! Ferait-il autrement si c’était la mâchoire de Caïn, qui commit le premier meurtre ?… C’est peut-être la caboche d’un politique que cet âne-là traite maintenant du haut en bas… quelqu’un qui aurait circonvenu Dieu lui-même… n’est-ce pas bien possible ?' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'C’est bien possible, mon seigneur.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Ou d’un courtisan, qui savait dire « Bonjour, mon gracieux seigneur ; comment te portes-tu, mon excellent seigneur ? » C’est peut-être monseigneur un tel, qui vantait le cheval de monseigneur un tel, quand il avait dessein de le lui demander . N’est-ce pas bien possible ?' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Oui, mon seigneur.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'N’est-ce pas ? c’est cela même. Et maintenant le voilà marié à milady Vermine, décharné, et bien cogné à la mâchoire par la bêche d’un sacristain. Il y a là une belle révolution, si seulement nous avions le bon esprit d’y regarder ! Ces os ont-ils coûté si peu à fabriquer qu’ils doivent servir à jouer aux quilles ? Les miens me font mal quand je songe à cela.' },
    { k: 'perso', t: 'premier paysan' },
    { k: 'ligne', t: 'Une pioche et une bêche, et une bêche, et un drap pour se couvrir… holà !… et un trou d’argile à faire… cela convient à un tel hôte.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'En voici un autre ; pourquoi ne serait-ce pas le crâne d’un légiste ? Où sont ses équivoques maintenant, ses distinguo, ses points de fait, ses points de droit et tous ses tours ? Pourquoi souffre-t-il que ce maraud brutal lui cogne maintenant la tête avec une pelle crottée ? Et pourquoi ne lui intente-t-il pas son action pour coups, sévices et injures graves ? Hum ! ce monsieur-là était peut-être en son temps un grand acheteur de terres, avec ses hypothèques, ses reconnaissances, ses redevances, ses doubles garanties, ses recouvrements ! Est-ce donc là la redevance finale de toutes ses fines redevances, et le recouvrement de tous ses recouvrements, que d’avoir sa fine caboche pleine de fine boue ? Est-ce que ses garanties, les doubles comme les simples, ne lui garantiront de tous ses achats rien de plus qu’un espace long et large comme deux rôles d’écritures ? À eux seuls, les titres de transmission de ses propriétés tiendraient difficilement dans cette boîte et faut-il donc que le propriétaire lui-même n’en ait pas davantage ? Hein ?' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Pas un pouce de plus.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Le parchemin n’est-il pas fait de peau de mouton ?' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Oui, mon seigneur ; et aussi de peau de veau.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Ceux-là sont des veaux et des moutons qui cherchent là leur assurance… Je veux parler à ce camarade. Dites-moi, l’homme ! de qui est-ce la fosse ?' },
    { k: 'perso', t: 'premier paysan' },
    { k: 'ligne', t: 'C’est la mienne, monsieur.' },
    { k: 'ligne', t: 'Holà !… Et un trou d’argile à faire… cela convient à un tel hôte.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'En vérité, oui, je crois qu’elle est à toi, car tu y fais des tiennes, en voulant me mettre dedans.' },
    { k: 'perso', t: 'premier paysan' },
    { k: 'ligne', t: 'Là-dessus, monsieur, c’est bien plutôt vous qui voulez me mettre dedans ; mais vous n’y êtes point, et ça prouve bien qu’elle n’est point à vous. Quant à vous mettre dedans, pour ma part, je n’y travaille point. Et pourtant, c’est ma fosse.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Si fait, tu travailles à me mettre dedans, puisque tu y travailles, à cette fosse, et puisque tu dis qu’elle est à toi tu sais bien qu’elle est faite pour tenir le mort, et non pour saisir le vif. Voilà comment tu veux me mettre dedans.' },
    { k: 'perso', t: 'premier paysan' },
    { k: 'ligne', t: 'Ce qui est vif, monsieur, c’est de vouloir me mettre dedans. Mais ces vivacités-là pourront bien rebrousser chemin de vous à moi .' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Pour quel homme est-ce que tu la creuses ?' },
    { k: 'perso', t: 'premier paysan' },
    { k: 'ligne', t: 'Ce n’est point pour un homme, monsieur.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Pour quelle femme donc ?' },
    { k: 'perso', t: 'premier paysan' },
    { k: 'ligne', t: 'Ni pour une femme non plus.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Qui donc doit être enterré là ?' },
    { k: 'perso', t: 'premier paysan' },
    { k: 'ligne', t: 'Quelqu’un qui fut une femme, monsieur ; mais paix soit à son âme ! elle est morte.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Comme ce drôle-là est rigoureux ! Il faut lui parler selon les règles, ou les équivoques nous mettront à mal. Par le seigneur Dieu, Horatio, depuis trois ans je remarque ceci : notre siècle est devenu si pointilleux, que le paysan, du bout de son pied, serre d’assez près les talons du courtisan pour lui écorcher ses engelures… Depuis combien de temps es-tu fossoyeur ?' },
    { k: 'perso', t: 'premier paysan' },
    { k: 'ligne', t: 'De tous les jours de l’année je pris, pour commencer le métier, celui où notre feu roi Hamlet battit Fortinbras.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Combien y a-t-il de cela ?' },
    { k: 'perso', t: 'premier paysan' },
    { k: 'ligne', t: 'Ne sauriez-vous point le dire ? Il n’est si nigaud qui ne le sache. C’est le jour même où naquit le jeune Hamlet, celui qui est fou, et qu’on a envoyé en Angleterre.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Ah vraiment ? et pourquoi l’a-t-on envoyé en Angleterre ?' },
    { k: 'perso', t: 'premier paysan' },
    { k: 'ligne', t: 'Mais, parce qu’il était fou. Il retrouvera l’esprit là-bas. Ou bien, s’il ne l’y retrouve point, ce ne sera que petit dommage dans ce pays-là.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Pourquoi ?' },
    { k: 'perso', t: 'premier paysan' },
    { k: 'ligne', t: 'Cela ne se verra aucunement en lui : les hommes, là-bas, sont tous aussi fous que lui.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Comment est-il devenu fou ?' },
    { k: 'perso', t: 'premier paysan' },
    { k: 'ligne', t: 'Fort étrangement, dit-on.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Étrangement ? et comment ?' },
    { k: 'perso', t: 'premier paysan' },
    { k: 'ligne', t: 'C’est, par ma foi, en perdant l’esprit.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Et sur quel point ?' },
    { k: 'perso', t: 'premier paysan' },
    { k: 'ligne', t: 'Sur un point de ce territoire, en Danemark. Moi, j’y suis sacristain depuis trente ans, tant jeune que vieux.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Combien de temps un homme reste-t-il en terre avant de pourrir ?' },
    { k: 'perso', t: 'premier paysan' },
    { k: 'ligne', t: 'Ma foi ! s’il n’est pas pourri avant de mourir (comme nous en voyons par le temps qui court, et beaucoup ! de ces cadavres vérolés qui peuvent à peine supporter l’enterrement), il vous durera quelque huit ans… ou neuf ans… ; un tanneur vous durera neuf ans.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Pourquoi lui plus qu’un autre ?' },
    { k: 'perso', t: 'premier paysan' },
    { k: 'ligne', t: 'Ah ! voilà, monsieur ! Son cuir est si bien tanné par le fait de son métier, qu’il peut tenir contre l’eau pendant longtemps ; et c’est l’eau qui vous est un rude démolisseur de tous vos corps morts de fils de catins ! — Tenez voici un crâne qui vous est resté déjà en terre vingt-trois ans.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'De qui était-ce le crâne ?' },
    { k: 'perso', t: 'premier paysan' },
    { k: 'ligne', t: 'Ah ! le fils de catin, quel triple fou c’était ! Qui pensez-vous que ce fût ?' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'En vérité, je n’en sais rien !' },
    { k: 'perso', t: 'premier paysan' },
    { k: 'ligne', t: 'La peste soit de lui, ce gredin de fou ! il me versa une fois sur la tête un flacon de vin du Rhin. Ce même crâne-là, monsieur ! ce même crâne-là, monsieur, était le crâne d’Yorick, le bouffon du roi.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Celui-là ?' },
    { k: 'perso', t: 'premier paysan' },
    { k: 'ligne', t: 'Oui-da, cette chose-là.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Laisse-moi voir. (Il prend le crâne.) Hélas ! pauvre Yorick… Je l’ai connu, Horatio, c’était un garçon d’une verve infinie, d’une fantaisie tout à fait rare. Il m’a porté sur son dos un millier de fois ; et maintenant, comme mon imagination y répugne ! Cela me soulève le cœur. Là étaient attachées ces lèvres que j’ai baisées je ne sais combien de fois ! Où sont vos moqueries, maintenant ? vos folâtreries ? vos chansons ? vos éclats de gaieté qui avaient coutume de faire tonner les rires de toute la table ? Et rien de tout cela, maintenant, rien pour vous moquer de votre propre grimace ? quoi bouche béante, décidément ? Allez-vous-en maintenant dans la chambre de Madame, et dites à Sa Seigneurie qu’elle aura beau se peindre jusqu’à en avoir un pouce d’épaisseur, voilà la figure à laquelle il faudra qu’elle en vienne ! Faites-la rire à ce propos . — Je te prie, Horatio, dis-moi une chose.' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Qu’est-ce, mon seigneur ?' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Penses-tu qu’Alexandre fit cette figure-là sous terre ?' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Oui, certes.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Et qu’il eût cette odeur-là ? pouah !' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Oui, certes, mon seigneur.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'À quels vils emplois nous pouvons revenir, Horatio ! Pourquoi l’imagination ne pourrait-elle pas dépister la noble poussière d’Alexandre jusqu’à la trouver bouchant la bonde d’une barrique ?' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Ce serait considérer les choses avec trop de recherche que de les considérer ainsi.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Non, ma foi, je n’en rabats point un iota ; on peut le suivre jusque-là assez simplement, et il y a de la vraisemblance à mener le raisonnement comme ceci : Alexandre mourut, Alexandre fut enterré, Alexandre retourna en poussière ; la poussière est de la terre ; avec de la terre nous faisons du ciment ; et pourquoi donc, de ce ciment en quoi il a été converti, n’aurait-on point pu boucher une barrique de bière ? L’auguste César, mort, et changé en argile, pourrait boucher un trou et arrêter le vent. Oh ! dire que cette poussière qui tenait le monde en arrêt était destinée à rapiécer un mur et à repousser le souffle de l’hiver ! Mais doucement ! doucement ! retirons-nous : voici venir le roi.' },
    { k: 'ligne', t: 'La reine, les courtisans ! qui est-ce qu’ils suivent ? Et comme ces rites sont mutilés ! Cela indique que le cadavre auquel ils font cortége a, d’une main désespérée, attenté à sa propre vie. C’était une personne de quelque marque. Cachons-nous un moment et observons.' },
    { k: 'perso', t: 'laërtes' },
    { k: 'ligne', t: 'Quelle autre cérémonie ?…' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'C’est Laërtes, un fort noble jeune homme ; écoutons.' },
    { k: 'perso', t: 'laërtes' },
    { k: 'ligne', t: 'Quelle autre cérémonie ?…' },
    { k: 'perso', t: 'premier prêtre' },
    { k: 'ligne', t: 'Ses obsèques ont été poussées aussi loin que nous en avons mission. Sa mort prêtait au doute, et sans cette haute volonté qui l’emporte sur l’ordre établi, elle eût été logée dans une terre non bénite jusqu’à la trompette du dernier jugement. Au lieu de charitables prières, on eût jeté sur elle des tessons, des pierres et des cailloux ; mais on lui a accordé ses couronnes de jeune fille, ses jonchées de fleurs virginales, et l’accompagnement des cloches et des funérailles.' },
    { k: 'perso', t: 'laërtes' },
    { k: 'ligne', t: 'Ne doit-on rien faire de plus ?' },
    { k: 'perso', t: 'premier prêtre' },
    { k: 'ligne', t: 'Non, rien de plus ; ce serait profaner l’office des morts que de chanter pour elle le Requiem et ce repos réservé aux âmes qui partent en paix.' },
    { k: 'perso', t: 'laërtes' },
    { k: 'ligne', t: 'Placez-la dans la terre, et puissent de sa chair belle et sans tache mille violettes naître ici . Je te dis ceci, prêtre brutal : ma sœur sera un ange protecteur, quand tu seras, toi, tombé là-bas en hurlant !' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Quoi ? la belle Ophélia !' },
    { k: 'ligne', t: 'la reine' },
    { k: 'ligne', t: ', répandant des fleurs. — Les plus douces à la plus douce ! Adieu ! J’avais espéré que tu serais la femme de mon Hamlet ; je pensais, douce fille, à parer de ces fleurs ton lit nuptial, et non à en joncher ton tombeau.' },
    { k: 'perso', t: 'laërtes' },
    { k: 'ligne', t: 'Oh qu’une triple peine tombe trois fois dix fois sur cette tête maudite dont l’action méchante t’a privée de ta très-délicate raison ! Tenez pour un moment cette terre encore écartée, jusqu’à ce que je l’aie saisie une dernière fois dans mes bras. (Il s’élance dans la fosse.) Et maintenant entassez votre poussière sur le vivant et sur le mort, jusqu’à ce que vous ayez fait de cette plaine une montagne qui dépasse le vieux Pélion ou le front céleste de l’Olympe bleu !' },
    { k: 'ligne', t: 'hamlet' },
    { k: 'ligne', t: ', avançant. — Quel est l’homme dont la douleur comporte une pareille hauteur d’accent, et dont les plaintes vont, comme une conjuration magique, atteindre les astres errants et les arrêter, tels que des auditeurs frappés d’une mortelle surprise ? Je suis cet homme, moi, Hamlet le Danois !' },
    { k: 'ligne', t: 'laërtes' },
    { k: 'ligne', t: ', le saisissant. — Que le démon prenne ton âme !' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Tu ne pries pas bien. Allons, ôte tes doigts de ma gorge; car bien que je ne sois ni bilieux ni brusque, j’ai cependant au-dedans de moi quelque chose de dangereux et que devra redouter ta prudence. Écarte ta main.' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Séparez-les.' },
    { k: 'perso', t: 'la reine' },
    { k: 'ligne', t: 'Hamlet ! Hamlet !' },
    { k: 'perso', t: 'tous' },
    { k: 'ligne', t: 'Messieurs !' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Mon bon seigneur, calmez-vous.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Or çà, je combattrai avec lui pour cette cause, jusqu’à ce que mes paupières refusent de se mouvoir.' },
    { k: 'perso', t: 'la reine' },
    { k: 'ligne', t: 'Ô mon fils, pour quelle cause ?' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'J’aimais Ophélia. Quarante mille frères ne pourraient pas, avec toute leur somme d’amour, monter au même total que moi… Que veux-tu faire pour elle ?' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Ô Laërtes, il est fou.' },
    { k: 'perso', t: 'la reine' },
    { k: 'ligne', t: 'Pour l’amour de Dieu, laissez-le !' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Morbleu ! montre-moi ce que tu veux faire. Veux-tu pleurer ? veux-tu combattre ? veux-tu t’affamer ? veux-tu te mettre en pièces ? veux-tu t’abreuver de vinaigre ? veux-tu manger un crocodile ?… Je ferai tout cela… Ne viens-tu ici que pour gémir ? pour me braver en t’élançant dans son tombeau ? Fais-toi enterrer vivant avec elle ; j’en ferai autant. Et puisque tu bavardes à propos de montagnes, qu’on jette sur nous des millions d’arpents de terre, jusqu’à ce que notre sol aille aux sphères brûlantes heurter et roussir sa tête et fasse ressembler le mont Ossa à une verrue !… Sur mon honneur ! si tu déclames, je crierai aussi bien que toi.' },
    { k: 'perso', t: 'la reine' },
    { k: 'ligne', t: 'Ceci est de la folie toute pure ! et son accès va le travailler ainsi pendant quelque temps ; mais bientôt vous le verrez, aussi patiemment que la colombe quand ses jumeaux au duvet doré viennent d’éclore , couver un silence languissant.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Entendez-vous, monsieur ? Quelle raison avez-vous pour en user ainsi avec moi ? Je vous ai toujours aimé… mais n’importe ! Hercule lui-même aurait beau faire : le chat miaulera… et le chien aura son tour.' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Je te prie, cher Horatio, ne le quitte pas. (Horatio sort.) — À Laërtes. Que votre patience s’affermisse sur notre entretien d’hier soir. Nous allons mettre cette affaire en train. — Chère Gertrude, ordonnez quelque surveillance autour de votre fils… Il faut à cette tombe un monument vivant ; nous verrons ainsi venir l’heure du repos ; d’ici là, usons de patience dans nos entreprises.' },
    { k: 'scene', t: 'SCÈNE II' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Assez sur ce sujet, monsieur ; maintenant passons à l’autre. Vous vous souvenez bien de toutes les circonstances ?' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Si je m’en souviens, mon seigneur ?' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Monsieur, il y avait en mon cœur une sorte de combat qui ne me laissait point dormir. J’étais, à ce qui me semblait, couché plus mal à l’aise que les matelots mutins dans leurs entraves . Brusquement… et bénie soit cette brusquerie ! car notre irréflexion, sachons-le bien, nous profite parfois tandis que nos projets les plus profonds avortent, et cela devrait nous enseigner qu’il y a une divinité qui façonne nos destinées, quelle que soit notre volonté de les ébaucher…' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Cela est bien certain.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Brusquement donc, je sors de ma cabine, mon manteau de marin roulé autour de moi, et dans l’obscurité, à tâtons, je les cherche, j’arrive à souhait, empoigne leur paquet, et enfin me retire vers ma chambre, où je rentre, et là, mes craintes mettant les convenances en oubli, je prends l’audace de décacheter leur auguste commission, où je découvre, Horatio, ô royale scélératesse ! un ordre formel, lardé de toutes sortes de raisons, au nom de la prospérité du Danemark, et de l’Angleterre aussi — ha ! ha ! et avec quelle évocation d’épouvantails et de loups-garous, si je restais en vie ! — un ordre à vue, sans délai permis, non ! sans prendre même le temps d’aiguiser la hache, — l’ordre de me couper le cou.' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Est-ce possible ?' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Voici la commission ; lis-la plus à loisir. Mais veux-tu entendre ce que je fis ?' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Oui, je vous en prie.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Ainsi enlacé de toutes parts par des bandits, — je n’avais pas eu le temps de faire dans ma tête un prologue que déjà ils avaient commencé la pièce, — je m’assieds, et je compose une nouvelle commission. Je l’écris de ma plus belle main. Autrefois j’estimais, comme nos hommes d’État, qu’il y avait de la bassesse à avoir une belle écriture, et j’ai beaucoup travaillé à perdre ce talent ; mais, monsieur, il me fit alors un bon et loyal service. Veux tu savoir l’objet de ce que j’écrivis ?' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Oui, mon bon seigneur.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Une pressante mise en demeure, de par le roi, — considérant que l’Angleterre était sa tributaire fidèle ; désirant que l’amitié pût entre eux fleurir comme un palmier ; désirant que la Paix continuât à porter sa guirlande d’épis et à s’élever sur leurs frontières en signe de leurs bons sentiments, — et beaucoup de phrases semblables de quoi faire amplement la charge d’un âne, — à seule fin que, le contenu de ce pli aussitôt vu et connu, sans autre délibération longue ou brève, il fît mettre à mort tout soudainement les porteurs desdites dépêches, sans même leur donner le temps de se recommander à Dieu.' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Mais comment cela fut-il scellé ?' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Ah ! c’est à quoi le Ciel avait encore mis ordre ; j’avais dans ma bourse le cachet de mon père, qui était la copie du grand sceau danois. Je ployai l’écrit dans la forme de l’autre ; je le suscrivis ; je mis l’empreinte et le déposai sans encombre ; on ne s’est jamais douté de la substitution. Puis, le lendemain, advint notre combat naval, et ce qui s’en suivit, tu le sais déjà.' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Ainsi Guildenstern et Rosencrantz s’en vont là ?' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Eh bien ! ô homme ? N’ont-ils pas amoureusement courtisé cette ambassade ? Ah ! je suis loin de les avoir sur la conscience. Leur perte provient de leur propre désir de s’insinuer ; c’est chose dangereuse, aux gens de basse espèce, que d’intervenir dans les escrimes et entre les épées brûlantes de rage de deux adversaires puissants.' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Ah quel roi nous avons là !' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Maintenant, ne suis-je pas mis en demeure ? qu’en penses-tu ? Celui qui a tué mon roi et débauché ma mère, celui qui s’est glissé entre l’élection et mes espérances, celui qui a jeté son hameçon pour prendre ma propre vie, et avec une telle perfidie, n’est-ce pas vraiment faire acte de bonne conscience que de le payer avec la main que voici, et n’est-ce pas de quoi se faire damner que de laisser aller à plus de ravages cette gangrène de notre vie ?' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Il aura bientôt appris d’Angleterre quelle issue l’affaire a eue là-bas.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Ce sera court, l’intervalle est à moi, et la vie d’un homme ne tient pas le temps de compter jusqu’à deux. Mais je suis très-affligé, cher Horatio, de m’être oublié envers Laërtes, car dans le tableau de ma cause je vois une image de la sienne ; je rechercherai ses bonnes grâces. C’est assurément la jactance de sa plainte qui m’a poussé à ce comble de vertigineuse fureur.' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Silence ! qui vient ici ?' },
    { k: 'perso', t: 'osrick' },
    { k: 'ligne', t: 'J’offre à Votre Seigneurie mes meilleurs compliments de bienvenue sur son retour en Danemark .' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Je vous remercie humblement, monsieur… Connais-tu ce moucheron ?' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Non, mon bon seigneur.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Tu es d’autant mieux en état de grâce, car il y a du vice à le connaître. Il possède beaucoup de terres, et qui sont très-fertiles. Que le seigneur des animaux soit lui-même un animal, et celui-ci sera sûr d’avoir sa mangeoire mise à la table du roi. C’est un vrai perroquet ; mais, comme je te le dis, il peut aller loin sur les boues qui sont à lui.' },
    { k: 'perso', t: 'osrick' },
    { k: 'ligne', t: 'Mon gracieux seigneur, si Votre Seigneurie était de loisir, j’aurais quelque chose à lui transmettre de la part de Sa Majesté.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'J’y ferai accueil, monsieur, en toute diligence d’esprit… Mettez donc votre chapeau à sa vraie place ; il est fait pour la tête.' },
    { k: 'perso', t: 'osrick' },
    { k: 'ligne', t: 'Je remercie Votre Seigneurie ; il fait grand chaud.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Non, croyez-moi, il fait grand froid. Le vent est du nord.' },
    { k: 'perso', t: 'osrick' },
    { k: 'ligne', t: 'Vraiment oui, mon seigneur, il fait passablement froid.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Et pourtant, ce me semble, il fait tout à fait étouffant, tout à fait chaud ; ou, peut-être, ma complexion…' },
    { k: 'perso', t: 'osrick' },
    { k: 'ligne', t: 'Furieusement, mon seigneur ! Tout à fait étouffant,… comme si… je ne saurais dire à quel point . Mon seigneur, Sa Majesté m’a donné ordre de vous mander qu’Elle a fondé sur votre tête une grande gageure. Voici, monsieur, de quoi il s’agit…' },
    { k: 'ligne', t: 'hamlet' },
    { k: 'ligne', t: ', le pressant de mettre son chapeau. — Je vous supplie, n’oubliez pas que…' },
    { k: 'perso', t: 'osrick' },
    { k: 'ligne', t: 'Non, mon bon seigneur ; pour ma propre commodité, je vous jure… Monsieur, l’on a vu, depuis peu, arriver à la cour Laërtes, un galant homme des plus accomplis, croyez-moi ; il a cent perfections qui le tirent merveilleusement du commun ; il est d’une grande douceur de commerce et fait grande figure dans le monde. En vérité, pour parler de lui selon les sentiments qui lui sont dus, il est la Carte et l’Almanach de la Galanterie , car vous trouverez en lui l’extrait de tous les mérites qu’un galant homme aime à contempler.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Monsieur, son portrait ne souffre point indigence d’éloges à être tracé par vous. Ce n’est pas que je ne sache bien que, si l’on se piquait de faire l’anatomie et tout l’inventaire de ce gentilhomme, s’il est permis de s’exprimer ainsi, on ne laisserait pas de stupéficier l’arithmétique de la mémoire, encore que l’on ne fît que voguer derrière lui et chercher le vent çà et là, au prix de son rapide sillage . Mais sans mentir ni le pousser trop avant dans le rang favori de notre pensée, je le tiens pour une âme du premier ordre, et le concert de ses qualités a tant d’étrange et d’inouï que, pour donner dans le vrai de la chose, il n’a son pareil que dans son miroir, et tout autre qui voudrait lui ressembler n’irait qu’à doubler son ombre, rien de plus.' },
    { k: 'perso', t: 'osrick' },
    { k: 'ligne', t: 'Votre Seigneurie parle de lui à coup sûr.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Mais quelles affaires, monsieur ? Pourquoi encapucinons-nous ce galant homme dans la rudesse indue de nos paroles ?' },
    { k: 'perso', t: 'osrick' },
    { k: 'ligne', t: 'Monsieur ?' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'N’est-il pas possible de s’entendre en parlant une autre langue ? Vous le pouvez, monsieur, j’en suis sûr.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'À quoi tend la citation de ce gentilhomme ?' },
    { k: 'perso', t: 'osrick' },
    { k: 'ligne', t: 'De Laërtes ?' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Sa bourse est déjà vide : il a dépensé toutes ses paroles dorées.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Oui, monsieur, de lui.' },
    { k: 'perso', t: 'osrick' },
    { k: 'ligne', t: 'Je sais que vous n’êtes pas ignorant…' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Vous savez cela, monsieur ? Je le voudrais. Et par ma foi ! cependant, si vous le saviez, cela ne prouverait pas grand’chose en ma faveur. Eh bien ! monsieur ?' },
    { k: 'perso', t: 'osrick' },
    { k: 'ligne', t: 'Vous n’êtes pas ignorant du grand mérite que montre Laërtes…' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Je n’ose convenir de cela, de peur d’entrer en comparaison avec lui sur ce grand mérite ; car on ne sait bien d’un homme que ce qu’on sait de soi-même.' },
    { k: 'perso', t: 'osrick' },
    { k: 'ligne', t: 'Je parle seulement, monsieur, du mérite qu’il montre pour son arme ; mais d’après l’estime qu’on fait de lui, il n’a pas son égal en son genre.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Quelle est son arme ?' },
    { k: 'perso', t: 'osrick' },
    { k: 'ligne', t: 'La rapière et la dague.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Ce sont deux de ses armes ; mais à la bonne heure !' },
    { k: 'perso', t: 'osrick' },
    { k: 'ligne', t: 'Le roi, monsieur, a gagé contre lui six chevaux barbes ; et lui, il a mis pour enjeu, à ce que j’ai cru comprendre, six rapières et poignards de France, avec toute leur garniture, savoir : ceinturons, pendants, et le reste. Trois de ces équipages sont, en honneur, très-précieux pour le goût, admirablement accommodés aux poignées ; des équipages de la dernière délicatesse et du travail le plus ingénieux !' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Qu’appelez-vous équipages ?' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Je pensais bien qu’il vous faudrait quelque glose à la marge avant d’être au bout.' },
    { k: 'perso', t: 'osrick' },
    { k: 'ligne', t: 'Les équipages, monsieur, ce sont les pendants.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Le mot serait plus cousin germain de la chose, si nous étions équipés d’un canon au côté ; je voudrais bien que les pendants, d’ici là, restassent des pendants. Mais continuons : six chevaux barbes contre six épées françaises, leurs garnitures, et trois équipages ingénieusement travaillés, voilà le pari français contre le danois. Mais pourquoi a-t-on mis cet enjeu, comme vous l’appelez ?' },
    { k: 'perso', t: 'osrick' },
    { k: 'ligne', t: 'Le roi, monsieur, a parié que Laërtes, sur douze passes entre vous et lui, ne vous gagnera pas de trois bottes ; Laërtes a parié pour neuf sur douze et l’épreuve sera faite sur-le-champ, si Votre Seigneurie veut me favoriser d’une réponse.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Comment ! même si je réponds non ?' },
    { k: 'perso', t: 'osrick' },
    { k: 'ligne', t: 'Je veux dire, mon seigneur, si vous consentez à jouer en personne un rôle dans cette épreuve.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Monsieur, je me promènerai ici, dans cette salle ; s’il plaît à Sa Majesté, comme c’est pour moi l’heure de la récréation, faites qu’on apporte des fleurets, que ce gentilhomme soit de bonne volonté, que le roi tienne à son projet, et je lui gagnerai son pari, si je puis. Sinon, je n’y gagnerai que de la honte et de fâcheuses bottes.' },
    { k: 'perso', t: 'osrick' },
    { k: 'ligne', t: 'Vous ferai-je parler ainsi ?' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'En ce sens, oui, monsieur ; mais avec telles fioritures que votre talent vous dictera.' },
    { k: 'perso', t: 'osrick' },
    { k: 'ligne', t: 'Je recommande mes services à Votre Seigneurie.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Tout à vous, tout à vous. Il fait bien de se recommander lui-même ; il n’y a pas d’autre bouche qui voulût s’en charger.' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Il s’en va courant, l’étourneau, encore coiffé de sa coquille.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Lui ? il a complimenté le sein de sa nourrice, avant de se mettre à téter. Voilà comme ils sont, lui et beaucoup d’autres de la même volée, dont je vois raffoler ce siècle pétillant et mousseux. Ils ont pris seulement le ton du jour et les dehors de la courtoisie à la mode : c’est comme une collection de petites rubriques écumées çà et là, qui les mettent en vogue à tort et à travers, de par les jugements les plus évaporés et les plus éventés ; mais soufflez dessus seulement, en manière d’épreuve, et tout de suite ces bulles ont crevé.' },
    { k: 'perso', t: 'le seigneur' },
    { k: 'ligne', t: 'Mon seigneur, Sa Majesté s’est recommandée à vous par le jeune Osrick, qui lui a rapporté que vous l’attendiez dans cette salle. Il envoie savoir s’il vous plaît toujours de faire assaut avec Laërtes, ou si vous voulez prendre plus de délai.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Je suis constant dans mes résolutions ; elles suivent le bon plaisir du roi : ses convenances n’ont qu’à parler, les miennes sont prêtes à la réplique. Maintenant, ou dans un autre instant, pourvu que je sois aussi dispos qu’à présent.' },
    { k: 'perso', t: 'le seigneur' },
    { k: 'ligne', t: 'Le roi, la reine, tous vont venir.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Et ils seront les bienvenus.' },
    { k: 'perso', t: 'le seigneur' },
    { k: 'ligne', t: 'La reine désire de vous quelque compliment aimable pour Laërtes, avant de tomber en garde.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Elle me donne un bon conseil.' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Vous perdrez ce pari, mon seigneur.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Je ne crois pas. Depuis qu’il est parti pour la France, je me suis continuellement exercé ; avec l’avantage qu’il me fait, je gagnerai… Tu ne saurais croire combien tout va mal là, du côté de mon cœur. Mais, n’importe !' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Pourtant, mon bon seigneur…' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'C’est pure sottise, mais c’est une sorte de pressentiment qui troublerait peut-être une femme.' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Si votre âme éprouve quelque répugnance, obéissez-lui ; je préviendrai leur arrivée ici, et leur dirai que vous n’êtes pas bien disposé.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'N’en fais rien ; nous bravons les augures Il y a une providence spéciale pour la chute d’un passereau . Si l’heure est venue, il n’y a plus à l’attendre ; s’il n’y a plus à attendre, il n’y a rien à y faire. Si elle n’est pas encore venue, elle n’en viendra pas moins un jour ou l’autre. Le tout est d’être prêt. Puisque aucun homme ne sait ce qu’il quitte, qu’importe de quitter plus tôt !' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Venez, Hamlet, venez, et que je place cette main dans la vôtre.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Pardonnez-moi, monsieur. Je vous ai offensé ; mais pardonnez-moi comme un gentilhomme que vous êtes. Ceux qui sont ici présents savent, et vous avez nécessairement entendu dire, comment j’ai été affligé d’un cruel désordre d’esprit. Tout ce que j’ai fait, par quoi votre cœur, votre honneur, votre sévérité ont pu être mis rudement en éveil, je proclame ici que c’était de la folie. Est-ce Hamlet qui a offensé Laërtes ? Hamlet ? non, jamais. Si Hamlet est enlevé à lui-même, si, lorsqu’il n’est plus lui-même, il fait offense à Laërtes, alors ce n’est pas Hamlet qui la fait ; Hamlet la désavoue. Qui donc fait l’offense ? Sa folie ; et s’il en est ainsi, Hamlet est du parti offensé ; l’ennemi du pauvre Hamlet, c’est sa folie même. Monsieur, devant cette assistance, souffrez que mon désaveu de toute intention mauvaise m’absolve dans votre âme généreuse, comme si, lançant ma flèche par-dessus la maison, j’avais blessé mon frère.' },
    { k: 'perso', t: 'laërtes' },
    { k: 'ligne', t: 'J’ai pleine satisfaction pour mon cœur, dont les griefs en cette affaire devraient me pousser le plus fortement à la vengeance. Mais sur le terrain de l’honneur, je me tiens dans la réserve et ne veux point de réconciliation, jusqu’à ce que j’aie, de quelques arbitres d’un honneur connu, la sentence et les précédents de paix qui doivent garder mon nom de toute tache ; mais en attendant je reçois l’amitié que vous m’offrez comme une amitié vraie, et je ne lui ferai pas défaut.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'J’embrasse volontiers cette assurance, et je vais disputer loyalement cette gageure fraternelle… Donnez-nous les fleurets. Allons.' },
    { k: 'perso', t: 'laërtes' },
    { k: 'ligne', t: 'Allons… Un pour moi.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Oui, Laërtes, un fleuret, et moi, je serai votre plastron ; enchâssée en ma maladresse, votre habileté, comme une étoile dans la nuit la plus obscure, va ressortir avec tout son feu.' },
    { k: 'perso', t: 'laërtes' },
    { k: 'ligne', t: 'Vous me raillez, monsieur.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Non, j’en jure par ma main droite.' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Jeune Osrick, donnez-leur les fleurets. — Cousin Hamlet, vous connaissez la gageure ?' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Très-bien, mon seigneur. Votre Grâce a placé le plus gros enjeu du côté le plus faible.' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Je ne crains rien : je vous ai vus tous deux à l’œuvre. Mais comme il a fait des progrès, nous avons pris un avantage.' },
    { k: 'perso', t: 'laërtes' },
    { k: 'ligne', t: 'Celui-ci est trop lourd ; voyons-en un autre.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Celui-ci me va ; sont-ils tous de longueur ?' },
    { k: 'perso', t: 'osrick' },
    { k: 'ligne', t: 'Oui, mon bon seigneur.' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Mettez-moi les flacons de vin sur cette table. Si Hamlet porte la première ou la seconde botte, s’il riposte à la troisième, que toutes les batteries fassent feu : le roi boira à Hamlet, lui souhaitant de moins perdre haleine, et il jettera dans la coupe la perle de sa bague d’alliance , une perle plus riche que celles de la couronne de Danemark depuis quatre règnes. Donnez-moi les coupes, et que les timbales disent aux trompettes, les trompettes aux canonniers du dehors, les canons au ciel et le ciel à la terre : « Maintenant le roi boit à Hamlet. » Allons, commencez. — Et vous, juges, ayez l’œil attentif.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Allons, monsieur.' },
    { k: 'perso', t: 'laërtes' },
    { k: 'ligne', t: 'Allons, mon seigneur.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Une.' },
    { k: 'perso', t: 'laërtes' },
    { k: 'ligne', t: 'Non.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Qu’on en juge.' },
    { k: 'perso', t: 'osrick' },
    { k: 'ligne', t: 'Une botte, une botte très-visible.' },
    { k: 'perso', t: 'laërtes' },
    { k: 'ligne', t: 'Soit : recommençons.' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Attendez, qu’on me donne à boire. Hamlet, cette perle est à toi ; à ta santé ! Donnez-lui la coupe.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Je veux achever cette passe auparavant : mettez la coupe de côté. Allons. (Ils recommencent.) Encore une : qu’en dites-vous ?' },
    { k: 'perso', t: 'laërtes' },
    { k: 'ligne', t: 'Touché, touché, je l’avoue.' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Notre fils gagnera.' },
    { k: 'perso', t: 'la reine' },
    { k: 'ligne', t: 'Il est gros et court d’haleine . Viens, Hamlet ; prends mon mouchoir, essuie ton front. La reine boit à ton succès, Hamlet.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Chère madame…' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Gertrude, ne bois pas.' },
    { k: 'perso', t: 'la reine' },
    { k: 'ligne', t: 'Je boirai, mon seigneur. Excusez-moi, je vous prie.' },
    { k: 'ligne', t: 'le roi' },
    { k: 'ligne', t: ', à part. — C’est la coupe empoisonnée ; il est trop tard.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Je n’ose pas boire encore, madame. Tout à l’heure.' },
    { k: 'perso', t: 'la reine' },
    { k: 'ligne', t: 'Viens ; laisse-moi t’essuyer le visage.' },
    { k: 'perso', t: 'laërtes' },
    { k: 'ligne', t: 'Mon seigneur, maintenant je vais le toucher.' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Je ne crois pas.' },
    { k: 'ligne', t: 'laërtes' },
    { k: 'ligne', t: ', à part. — Et pourtant c’est presque contre ma conscience.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Allons, à la troisième, Laërtes. Vous ne faites que jouer. Je vous prie, poussez du meilleur de vos forces ; je crains que vous ne me traitiez en petit garçon.' },
    { k: 'perso', t: 'laërtes' },
    { k: 'ligne', t: 'Le croyez-vous ? Allons !' },
    { k: 'perso', t: 'osrick' },
    { k: 'ligne', t: 'Rien de part ni d’autre.' },
    { k: 'perso', t: 'laërtes' },
    { k: 'ligne', t: 'À vous, maintenant.' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Séparez-les ; ils sont enflammés.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Non ; recommençons.' },
    { k: 'perso', t: 'osrick' },
    { k: 'ligne', t: 'Voyez donc la reine ! Oh !' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Ils sont tous deux en sang. Comment vous trouvez-vous, mon seigneur ?' },
    { k: 'perso', t: 'osrick' },
    { k: 'ligne', t: 'Comment êtes-vous, Laërtes ?' },
    { k: 'perso', t: 'laërtes' },
    { k: 'ligne', t: 'Eh bien ! Osrick, comme une bécasse prise à son propre piège. Je péris justement par ma propre trahison.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Comment est la reine ?' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Elle s’est évanouie en les voyant en sang.' },
    { k: 'perso', t: 'la reine' },
    { k: 'ligne', t: 'Non, non ; la coupe, la coupe ! Ô mon cher Hamlet ! la coupe, la coupe ; je suis empoisonnée !' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Ô scélératesse ! Holà ! qu’on ferme la porte. Trahison ! Qu’on découvre la trahison !' },
    { k: 'perso', t: 'laërtes' },
    { k: 'ligne', t: 'La voici, Hamlet. Hamlet, tu es mort ; point de remède au monde qui puisse te faire du bien ; tu n’as plus en toi une demi-heure de vie ; le perfide instrument est, dans ta main, affilé et envenimé. L’infâme artifice s’est retourné contre moi ; voici, je suis ici gisant pour ne me relever jamais. Ta mère est empoisonnée. Je n’en puis plus. Le roi, le roi est coupable !' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'La pointe envenimée aussi ! Alors, venin, fais ton œuvre !' },
    { k: 'perso', t: 'osrick et les seigneurs' },
    { k: 'ligne', t: 'Trahison ! trahison !' },
    { k: 'perso', t: 'le roi' },
    { k: 'ligne', t: 'Oh ! défendez-moi encore, amis, je ne suis que blessé.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Tiens, toi, incestueux, assassin, damnable roi, achève ce breuvage ! Est-elle là dedans, ta belle alliance ? Eh bien ! va rejoindre ma mère .' },
    { k: 'perso', t: 'laërtes' },
    { k: 'ligne', t: 'Il est servi selon ses mérites ! C’est un poison préparé par lui-même… Échange le pardon avec moi, noble Hamlet ; que ma mort et celle de mon père ne tombent pas sur toi, ni la tienne sur moi !' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Que le ciel t’en absolve ! je te suis. Je suis mort, Horatio. Reine misérable, adieu… ! Vous, que je vois pâlir et trembler à ce coup, vous qui n’êtes, au milieu d’un tel spectacle, que des muets ou un public, si seulement j’avais le temps !… car c’est un huissier féroce que la mort, et strict à signifier ses arrêts… Oh je vous dirais… mais, laissons cela… Horatio je suis mort, tu vis ; redresse Hamlet et sa cause, aux yeux des mécontents.' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'N’y comptez pas ; je tiens plus de l’ancien Romain que du Danois. Il reste ici un peu de liqueur.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Si tu es un homme, donne-moi la coupe. Lâche-la, par le ciel ! je l’aurai… Ô Dieu ! Horatio, quel nom meurtri va me survivre, si les choses demeurent ainsi ignorées ! Si tu m’as jamais porté dans ton cœur, absente-toi quelque temps encore de la suprême félicité ; reste dans ce monde cruel à respirer un air douloureux, pour raconter mon histoire. (Une marche sonne au loin ; coups de canon derrière la scène.) Quel est ce bruit guerrier ?' },
    { k: 'perso', t: 'osrick' },
    { k: 'ligne', t: 'Le jeune Fortinbras, revenu de Pologne en conquérant, envoie aux ambassadeurs d’Angleterre cette salve guerrière.' },
    { k: 'perso', t: 'hamlet' },
    { k: 'ligne', t: 'Ah ! je meurs, Horatio ! le poison puissant abat tout à fait mes esprits ; je ne pourrai vivre assez pour savoir les nouvelles d’Angleterre. Mais je prédis que l’élection se fixera sur Fortinbras : il a ma voix mourante ; dis-lui cela, avec les circonstances, grandes ou petites, qui ont provoqué… le reste appartient au silence.' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Ainsi se brise un noble cœur. Dors bien, cher prince ; et que des essaims d’anges chantent pour te porter au repos ! (Une marche derrière la scène.) Mais pourquoi le tambour vient-il ici ?' },
    { k: 'perso', t: 'fortinbras' },
    { k: 'ligne', t: 'Où est ce spectacle ?' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Qu’est-ce que vous voulez voir ? Si c’est du malheur ou de la stupeur, ne cherchez pas plus loin.' },
    { k: 'perso', t: 'fortinbras' },
    { k: 'ligne', t: 'Voilà une curée qui crie : point de quartier ! Ô mort orgueilleuse, quel est donc le banquet qui se prépare dans ta caverne éternelle, pour que tu aies frappé tant de princes d’un seul coup si sanglant !' },
    { k: 'perso', t: 'premier ambassadeur' },
    { k: 'ligne', t: 'La vue en est horrible, et notre mission arrive trop tard d’Angleterre ; elle est maintenant insensible, l’oreille qui devait nous donner audience pour apprendre de nous que ses ordres sont remplis, et que Rosencrantz et Guildenstern ont péri. D’où nous viendront les remerciements qui nous sont dus ?' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'Ce ne serait pas de sa bouche, si même il avait encore le pouvoir de la vie pour vous remercier : il n’a jamais donné l’ordre de leur mort. Mais puisque vous vous rencontrez si juste à point à ce sanglant aspect, vous, venus des guerres de Pologne, vous, venus d’Angleterre, donnez ordre que ces corps soient exposés aux regards sur une haute estrade, et laissez-moi raconter, au monde qui l’ignore, comment les choses en sont venues là ; alors vous entendrez parler d’actions impudiques, sanguinaires et dénaturées, de jugements rendus par le hasard, de meurtres fortuits, de morts accomplies par la fourbe ou par une force majeure, et, quant à ce dernier acte, de projets qui, par méprise, sont retombés sur la tête de leurs auteurs. C’est là ce que je puis fidèlement raconter.' },
    { k: 'perso', t: 'fortinbras' },
    { k: 'ligne', t: 'Hâtons-nous de l’entendre, et convoquons l’élite de la noblesse à cette assemblée ; pour moi, c’est avec douleur que j’accepte ma fortune : j’ai sur ce royaume des droits dont on se souvient et que mon intérêt m’invite maintenant à réclamer.' },
    { k: 'perso', t: 'horatio' },
    { k: 'ligne', t: 'J’ai aussi mission de parler sur ce point, et de la part d’une bouche dont la voix en entraînera d’autres ; mais accomplissons sur-le-champ ce projet, pendant que les esprits sont encore agités, de peur que, par complots ou par méprises, il n’arrive de nouveaux malheurs.' },
    { k: 'perso', t: 'fortinbras' },
    { k: 'ligne', t: 'Que quatre de mes capitaines portent Hamlet, comme un soldat, vers l’estrade, car il donnait à croire que s’il était monté sur le trône, il se serait montré vraiment roi ; que, sur son passage, la musique militaire et tous les honneurs de la guerre parlent hautement de lui. Emportez ces corps ; un tel spectacle convient aux champs de bataille, mais il fait mal ici. Allez, et ordonnez aux soldats de faire feu.' },
  ],
};

export default texte;
